/* hd-lines.js — 64 门 × 6 爻 爻线内容（观己白话原创改写，中英双语）
   GATE_LINES[gate][line]={tz,te 标题中/英; mz,me 精髓中/英; pol:[{t:exalted|detriment,p:行星,z,e 中/英}]}
   tools/extract-gate-lines.mjs 抽结构 + 生成工作流原创改写；源 humdes 仅参考不入库不照搬。门 1/2/4 源无▲▼仅关键词。*/
export const GATE_LINES = {"1":{"1":{"tz":"独处蓄能","te":"The Inner Spring","mz":"创造力从独处中冒出来,先把自己照顾好,灵感自会涌现,不必硬挤。","me":"Creative energy wells up in solitude; self-care first, and inspiration follows on its own.","pol":[]},"2":{"tz":"天赋自现","te":"Natural Talent","mz":"才华是天生的,藏不住也学不来,被对的人看见时,它才真正发光。","me":"Talent is innate, neither hidden nor taught; it truly shines once the right people notice it.","pol":[]},"3":{"tz":"试错成形","te":"Forged by Trial","mz":"创意要在一次次碰壁、推倒重来里打磨,挫折不是失败,是成形的过程。","me":"Creativity is honed through setbacks and do-overs; obstacles aren't failure but the shaping itself.","pol":[]},"4":{"tz":"独行人际","te":"The Solitary in Society","mz":"创作者天生独处,却需要人脉网络;先把作品做好,缘分会带来对的人。","me":"A creator is solitary by nature yet needs a network; do the work well, and the right people arrive.","pol":[]},"5":{"tz":"感染他人","te":"Influence That Calls","mz":"成熟的表达能感染并带动一群人,但只在被真心邀请时才奏效。","me":"Mature expression moves and rallies others, but only works when genuinely invited.","pol":[]},"6":{"tz":"活成榜样","te":"Living Example","mz":"走过创作的起落,沉淀出智慧,不靠说教,只用自己的活法影响人。","me":"Having lived the creative highs and lows, wisdom settles; influence comes from how you live, not what you preach.","pol":[]}},"2":{"1":{"tz":"心里有数","te":"The Inner Compass","mz":"不用分析就知道方向的人,直觉是你的根基,顺着内在那点笃定走。","me":"You simply know the way without reasoning it out; quiet inner certainty is your starting point.","pol":[]},"2":{"tz":"待人发掘","te":"Talent Drawn Out","mz":"天生的方向感藏在身上,不必硬推;对的人一招呼,它就自然显现。","me":"A natural sense of direction lives in you; it surfaces on its own when the right person calls it forth.","pol":[]},"3":{"tz":"慢慢摸清","te":"Knowing Through Trial","mz":"想催出答案反而乱,经历几轮试错后,你才学会给那份明白留出时间。","me":"Forcing answers only muddies them; through trial and error you learn to let the knowing arrive in its own time.","pol":[]},"4":{"tz":"懂得藏拙","te":"The Quiet Container","mz":"在关系里你像个稳稳的容器,接住别人,也守得住该守的那些事。","me":"In relationships you are a steady container, receiving others and keeping what should stay private.","pol":[]},"5":{"tz":"务实导向","te":"Practical Guidance","mz":"把内在的方向落到实处去帮人,做得好被信任,被误读时也容易背锅。","me":"You turn inner direction into practical help for others; trusted when it lands, easily blamed when it is misread.","pol":[]},"6":{"tz":"顺势的人","te":"Living the Flow","mz":"活成一个范本:不去追答案,而是让智慧自己到来,旁人看着就被点醒。","me":"You become a living example of not chasing answers but letting wisdom come, and others wake up just by watching.","pol":[]}},"3":{"1":{"tz":"理顺源头","te":"Synthesis","mz":"开局总是乱的——先把所有线头看清,秩序自会从混乱里长出来。","me":"At the start things are tangled; see every factor first, and order grows out of the chaos.","pol":[{"t":"exalted","p":"Earth","z":"▲扬升:相信混乱是必经之路,沉得住气,知道清晰一定会来。","e":"Trusting that confusion is the natural first step, calmly knowing clarity will arrive."},{"t":"detriment","p":"Mercury","z":"▼落陷:只靠脑子硬想、不信直觉,反而越理越乱,徒增焦躁。","e":"Leaning on intellect over instinct, fumbling for certainty and breeding needless frustration."}]},"2":{"tz":"嫩芽认人","te":"Immaturity","mz":"像刚冒头的新芽,渴望被引导,却还没长出分辨该听谁的根基。","me":"Like a fresh sprout craving guidance, not yet grounded enough to know whom to trust.","pol":[{"t":"exalted","p":"Mars","z":"▲扬升:一股不肯停的成长劲,认准了就往上顶,终会破土而出。","e":"A relentless drive to grow that eventually breaks through and prevails."},{"t":"detriment","p":"Uranus","z":"▼落陷:一边想顺从一边想反叛,被外界牵着摇摆,内里站不稳。","e":"Torn between obeying and rebelling, swayed by others and left unsteady within."}]},"3":{"tz":"识别真假","te":"Survival","mz":"天生会分辨什么能开花结果、什么是空壳,在试错里找对的方向。","me":"A born knack for telling the fertile from the barren, finding what truly bears fruit.","pol":[{"t":"exalted","p":"Venus","z":"▲扬升:懂得挑对的人、对的事携手共创,知道哪条路有生机。","e":"Choosing the right partner and the right path, sensing where life can take root."},{"t":"detriment","p":"Pluto","z":"▼落陷:偏要跟趋势对着干,死守旧样子,拒绝任何更新。","e":"Stubbornly defying what works, clinging to the old and refusing to change."}]},"4":{"tz":"招来贵人","te":"Magnetic Charm","mz":"身上有种吸引力,不必费力,合适的帮助和滋养会自己靠过来。","me":"A natural magnetism that draws the right support and nourishment without forcing it.","pol":[]},"5":{"tz":"逆流而行","te":"Standing Alone","mz":"为理顺混乱所做的事,有时会得罪人——既要坚持,也得担下被误解。","me":"Acting to clear the chaos can alienate others; holding firm means bearing the misunderstanding.","pol":[{"t":"exalted","p":"Mars","z":"▲扬升:有底气守住自己的信念,在一片混乱中独自撑住方向。","e":"The courage to stand by your convictions and hold steady amid confusion."}]},"6":{"tz":"懂得放手","te":"Letting Go","mz":"成熟到能看清何时该停——不是放弃,是接受理顺本就是个过程。","me":"Mature enough to see when to stop struggling, accepting that ordering is a process, not a problem.","pol":[{"t":"exalted","p":"Sun","z":"▲扬升:像阳光照常升起,接住生命的节奏,知道一切会慢慢理顺。","e":"Like the sun that keeps rising, trusting life's rhythm that order unfolds in time."},{"t":"detriment","p":"Pluto","z":"▼落陷:被混乱压垮,觉得一切都没意义,陷进无力和消沉里。","e":"Crushed by the chaos, feeling everything is pointless and sinking into despair."}]}},"4":{"1":{"tz":"立论根基","te":"The Grounded Hypothesis","mz":"凡事先理出一套说法,给自己一个站得稳的逻辑地基。","me":"You build a solid logical base, settling the mind by forming a clear explanation first.","pol":[{"t":"exalted","p":"Moon","z":"▲想法随节律自然成形,有耐心等答案沉淀清楚。","e":"Ideas form in their own rhythm; patient until the answer settles clearly."},{"t":"detriment","p":"Earth","z":"▼太想立刻落地,反被现实压住,答案僵在原地。","e":"Too eager to ground it; reality weighs the idea down and it stalls."}]},"2":{"tz":"独处理思","te":"The Quiet Theorizer","mz":"答案在独处中自己冒出来,不必被人催着解释。","me":"Answers surface naturally in solitude, without needing to explain on demand.","pol":[{"t":"exalted","p":"Moon","z":"▲在安静里灵感自来,时机对了一语中的。","e":"In quiet, insight arrives on its own and lands precisely when timed right."},{"t":"detriment","p":"Mars","z":"▼急着抛出结论,没熟的想法被强推出去。","e":"Rushing to blurt the conclusion, pushing out an idea before it's ripe."}]},"3":{"tz":"试错求解","te":"Answers by Trial","mz":"靠一次次试错修正想法,错过的路也算长本事。","me":"Refines ideas through trial and error; even wrong turns teach something real.","pol":[{"t":"exalted","p":"Venus","z":"▲把试错当温柔的打磨,错了也能优雅修正。","e":"Treats mistakes as gentle polishing, correcting with grace, not shame."},{"t":"detriment","p":"Pluto","z":"▼死守一个错答案不肯放,越纠结越钻牛角尖。","e":"Clings to one flawed answer, spiraling deeper instead of letting go."}]},"4":{"tz":"答疑助人","te":"The Helpful Answer","mz":"乐于为身边人提供解法,在关系里被需要、被信任。","me":"Offers solutions to those nearby, finding worth in being needed and trusted.","pol":[{"t":"exalted","p":"Sun","z":"▲真心想帮人解惑,给出的答案照亮一群人。","e":"Genuinely wants to help; the answer given lights the way for many."},{"t":"detriment","p":"Saturn","z":"▼把给答案当义务,硬扛压力反而僵硬乏味。","e":"Treats answering as duty; the strain makes it rigid and joyless."}]},"5":{"tz":"破局新解","te":"The Unorthodox Fix","mz":"敢提别人没想过的解法,被看见时能救场,被误读时遭排斥。","me":"Dares an answer no one expected; saving the day when seen, rejected when misread.","pol":[{"t":"exalted","p":"Jupiter","z":"▲在关键时刻拿出大格局的解法,众人信服。","e":"At the crucial moment offers a big-picture fix that wins real trust."},{"t":"detriment","p":"Pluto","z":"▼用答案操控局面,信任一旦崩,口碑全毁。","e":"Uses answers to control; once trust breaks, the reputation collapses."}]},"6":{"tz":"通透之答","te":"The Settled Mind","mz":"看过太多答案后归于淡定,知道何时该说、何时留白。","me":"Having seen many answers, grows calm, knowing when to speak and when to leave space.","pol":[{"t":"exalted","p":"Mercury","z":"▲言语精准又克制,一句话点醒,不多废话。","e":"Speech is precise yet restrained; one clear line, no excess noise."},{"t":"detriment","p":"Mars","z":"▼急着证明自己懂,抢话说尽反而失了分量。","e":"Rushes to prove he knows, talking over others and losing all weight."}]}},"5":{"1":{"tz":"守住节奏","te":"Holding the Beat","mz":"认定的事就不轻易松手,哪怕风浪再大也按自己的节拍走到底。","me":"Once committed, you keep your own pace through the storm rather than abandon ship.","pol":[{"t":"exalted","p":"Mars","z":"▲逆境里也不慌,稳住自己的节奏,有种扛得住的勇气。","e":"Courage under pressure; the strength to keep your own rhythm steady."},{"t":"detriment","p":"Earth","z":"▼一受挑战就想提前放弃止损,节奏全乱,反而招来损失。","e":"Bailing out too soon when challenged; losing your rhythm and inviting loss."}]},"2":{"tz":"内心安稳","te":"Quiet Within","mz":"能挡住提前行动的诱惑,守得住一份不被催促的平静。","me":"The knack of resisting the urge to act early and resting in calm.","pol":[{"t":"exalted","p":"Venus","z":"▲把宁静当成最美的状态,从容自在,跟自己的节奏处得舒服。","e":"Composure born of valuing peace; at ease inside your own rhythm."},{"t":"detriment","p":"Pluto","z":"▼把安静熬成了停滞,想用力却被固定节奏困住,憋得慌。","e":"Stillness curdles into stagnation; the drive for power trapped by a fixed pace."}]},"3":{"tz":"瞎忙不安","te":"Restless Rush","mz":"一感到无能为力就发慌,被恐惧推着白白瞎忙、徒增压力。","me":"Helplessness breeds fear that spills into needless stress and busywork.","pol":[{"t":"exalted","p":"Neptune","z":"▲焦虑时往想象里走一走,虽然还紧张,但至少没乱动,守住了节奏。","e":"Imagination absorbs the restlessness; still tense, but no rash action."},{"t":"detriment","p":"Moon","z":"▼像月亮停不下来,静不下心,总跟自己的节奏对着干。","e":"Like the Moon, you can't sit still; forever at odds with your own pace."}]},"4":{"tz":"耐心猎手","te":"The Patient Hunter","mz":"懂得潜伏等待,把按兵不动当成活下去、抓住时机的本事。","me":"You wait in the blind, treating patience as your guarantee of survival.","pol":[{"t":"exalted","p":"Uranus","z":"▲一点灵光,把最被动的等待变成主动的成果,等得很值。","e":"Genius that turns the most passive wait into real achievement."},{"t":"detriment","p":"Sun","z":"▼太爱出风头,不肯藏起来等,结果把自己的安危都赔进去。","e":"Vanity too proud to hide; denying your rhythm at a predictable cost."}]},"5":{"tz":"等待之乐","te":"Joy in Waiting","mz":"在静静等待里尝到喜悦,看清自己在大流里的位置,近乎通透。","me":"In waiting you taste joy and glimpse your place in the flow.","pol":[{"t":"exalted","p":"Venus","z":"▲安住于平静,把它当成极致的美,从中读懂存在的本意。","e":"Calm as the highest beauty; reading the inner meaning of being."},{"t":"detriment","p":"Pluto","z":"▼觉得喜悦是骗局、等待是失败,对自己的位置彻底心灰。","e":"Joy dismissed as illusion, waiting as failure; disillusioned with your place."}]},"6":{"tz":"顺势而growth","te":"Yielding to Grow","mz":"等待从来不轻松,压力与意外不断,顺着大流弯一弯反而长出觉知。","me":"Waiting never lacks pressure; bending to the flow ripens awareness.","pol":[{"t":"exalted","p":"Neptune","z":"▲愿意向宇宙的大流低头,顶住压力守住节奏,常在意外中成长。","e":"Bending to the universal flow; growth ripens, often through the unexpected."}]}},"6":{"1":{"tz":"懂得退让","te":"The Wise Retreat","mz":"知道什么时候该退一步:硬碰硬不是勇敢,留住力气才是智慧。","me":"Knowing when to step back; saving your energy isn't cowardice, it's wisdom.","pol":[{"t":"exalted","p":"Pluto","z":"▲把后退当成节奏的一部分,不是失败;冲突来了也能稳住心。","e":"Sees retreat as a phase, not a defeat, and stays emotionally steady through conflict."},{"t":"detriment","p":"Mercury","z":"▼一退就觉得自己没用,冲突一来情绪就乱了套。","e":"Feels worthless the moment they pull back, and falls apart emotionally when conflict hits."}]},"2":{"tz":"见缝插针","te":"The Nimble Mover","mz":"处在弱势也能赢:看准时机靠近,该走就走,灵活胜过硬拼。","me":"Turning a weak spot into a win by reading the moment, engaging and withdrawing with timing.","pol":[{"t":"exalted","p":"Venus","z":"▲眼光细腻,一下就找到对方最软的地方,温柔却精准地化解。","e":"A fine eye spots the weakest point and works it with grace, not force."},{"t":"detriment","p":"Mars","z":"▼莽撞硬冲,像自杀式攻击,毫无分寸地卷进冲突里。","e":"Charges in blindly like a kamikaze, blundering into fights with no feel for timing."}]},"3":{"tz":"结盟借力","te":"Strength Through Bonds","mz":"一个人扛不住时,懂得找盟友、靠关系,把弱势变成底气。","me":"Finding allies and turning a weak position into real strength through deep bonds.","pol":[{"t":"exalted","p":"Neptune","z":"▲愿意打破旧框架去融合,感情深厚,关系因亲密而更有分量。","e":"Lets old forms dissolve into union; deep feeling enriches intimacy."},{"t":"detriment","p":"Pluto","z":"▼把结盟当成屈服,抗拒被管,最后连亲密也一并推开。","e":"Sees alliance as submission, resists being controlled, and pushes intimacy away."}]},"4":{"tz":"稳坐胜局","te":"Natural Victory","mz":"天生站在有力的位置,不必争抢,赢得自然又踏实。","me":"Standing on natural, unchallenged strength where victory comes without a fight.","pol":[{"t":"exalted","p":"Sun","z":"▲赢了之后还能宽厚有度,带着善意走向新天地。","e":"Wins with generosity and wisdom, then moves toward fresh horizons."},{"t":"detriment","p":"Pluto","z":"▼赢了还要赶尽杀绝,情绪失控,把关系一并毁掉。","e":"Conquers and purges; uncontrolled emotion turns destructive in relationships."}]},"5":{"tz":"请人评理","te":"Let It Be Judged","mz":"冲突时不死磕,愿意交给更公正的第三方来裁断。","me":"Trusting a higher authority to settle a conflict instead of slugging it out.","pol":[{"t":"exalted","p":"Venus","z":"▲懂得绕开正面冲突,用和气把事情往好的方向推。","e":"Furthers harmony by sidestepping head-on conflict."},{"t":"detriment","p":"Moon","z":"▼自以为最公正,只接受对自己有利的裁决,看不见别人的难处。","e":"Thinks itself the best judge and only accepts a verdict that favors it."}]},"6":{"tz":"主动止战","te":"The Peacemaker","mz":"明明占上风却愿意先停手,给对方留条活路,这是更高的胸怀。","me":"Strong enough to win, yet choosing to end the fight and let the other survive.","pol":[{"t":"exalted","p":"Mercury","z":"▲懂得生命可贵,有力量平息冲突,也带着对人的体恤。","e":"Holds life sacred; the power to end conflict tempered by care for others."},{"t":"detriment","p":"Venus","z":"▼也想止战,但非要先满足自己的条件,讲和却讲得让人难接受。","e":"Wants peace, but only on terms others can't accept."}]}},"7":{"1":{"tz":"强势领头","te":"The Strong Hand","mz":"天生想拿主意的人:既能照亮众人,也容易变成一言堂。","me":"A natural lead who can either guide others or rule with an iron grip.","pol":[{"t":"detriment","p":"Mercury","z":"▼坚信只有自己对,把个人主张当成唯一答案,听不进别人。","e":"Convinced only your view is right, you push your authority as the sole truth."}]},"2":{"tz":"顺众而领","te":"Leading by Consent","mz":"懂得顺着多数人的意愿带路,被选中才出头,服务大局。","me":"One who leads by serving the collective will and steps up only when chosen.","pol":[{"t":"exalted","p":"Neptune","z":"▲落实大家都认的规则,被推举后引领,能给社会带来深远改变。","e":"You apply systems everyone accepts, and once chosen, your leadership can shift society."},{"t":"detriment","p":"Mercury","z":"▼一旦被拥戴就自觉高人一等,反过来看不起当初选你的人。","e":"Once elevated, you feel superior to the very people who chose you."}]},"3":{"tz":"不服管者","te":"The Rule-Breaker","mz":"不愿被任何固定秩序框住,渴望尝试不同角色、不断求变的人。","me":"One who resists any fixed order and craves change and many roles.","pol":[{"t":"exalted","p":"Moon","z":"▲无论现状如何都想换新活法,在多种角色里找到自己的表达。","e":"An endless pull toward change, expressing yourself through many different roles."},{"t":"detriment","p":"Mercury","z":"▼走向虚无,觉得任何角色、任何秩序都没意义,全盘否定。","e":"Slipping into nihilism, you deny that any role or order holds value at all."}]},"4":{"tz":"懂得让位","te":"Knowing When to Yield","mz":"愿意接受众人评判与规则约束,该退就退、不恋权位的人。","me":"One willing to accept others' judgment and the rule of law, ready to step aside.","pol":[{"t":"exalted","p":"Sun","z":"▲为了整体利益从容退下,有这份智慧与气度,坦然受人评判。","e":"The grace to step down for the greater good and accept others' verdict."},{"t":"detriment","p":"Uranus","z":"▼死赖着不走,非要被强大反对声逼下台,拒绝承认别人的评判。","e":"Clinging to power until forced out, refusing to accept any judgment but your own."}]},"5":{"tz":"危时统帅","te":"The Crisis Leader","mz":"危机时被社会赋予绝对指挥权、需要凝聚人心的领导者。","me":"A leader whose authority becomes absolute when society faces crisis.","pol":[{"t":"exalted","p":"Venus","z":"▲天生能赢得众人忠心,把大家的力量拧成一股绳、归于和谐。","e":"A gift for drawing loyalty, weaving people's strength into harmony."},{"t":"detriment","p":"Neptune","z":"▼把自己孤立在众人之外,只顾不惜代价取胜,因此失了人心。","e":"Isolated from your people and obsessed with winning at any cost, you lose their loyalty."}]},"6":{"tz":"分权之手","te":"The Power-Sharer","mz":"懂得公平分配权力、把责任讲清楚交出去的协调者。","me":"One who shares and fairly distributes power, communicating responsibility clearly.","pol":[{"t":"exalted","p":"Mercury","z":"▲能把责任的边界讲明白,让每个人清楚自己该担起什么。","e":"You articulate the framework of responsibility so each person knows their part."},{"t":"detriment","p":"Uranus","z":"▼变成贪权的官僚,以分配责任为名揽权,最终搞乱整个组织。","e":"A power-hungry bureaucrat who grabs control under the guise of duty and destabilizes the whole."}]}},"8":{"1":{"tz":"诚实分享者","te":"The Honest Sharer","mz":"坦然承认一个人做不到，把创造交出去和大家一起成全。","me":"Owning your limits, and trusting that what you create only shines when shared.","pol":[{"t":"exalted","p":"Neptune","z":"▲懂得众人合力大于一己，把心血诚实地拿出来共享。","e":"Knowing the whole outshines the parts, and offering your gifts openly."},{"t":"detriment","p":"Mercury","z":"▼怕在群体里丢掉自己，干脆退缩，宁可不分享。","e":"Pulling back, afraid the group will swallow your individuality."}]},"2":{"tz":"无私贡献者","te":"The Selfless Giver","mz":"天生愿意默默付出，用不求回报的样子成为别人的榜样。","me":"A natural example who gives without keeping score.","pol":[{"t":"exalted","p":"Sun","z":"▲全心服务他人，活成一个不计回报的示范。","e":"Serving wholeheartedly, becoming a living example through pure giving."},{"t":"detriment","p":"Earth","z":"▼付出要先谈好价钱，没有好处就不肯当那个榜样。","e":"Helping only when there's a reward attached to it."}]},"3":{"tz":"花架子","te":"The Stylist","mz":"学到了形式却没接住内核，靠样子撑场面的人。","me":"Someone who masters the look but skips the substance.","pol":[{"t":"exalted","p":"Moon","z":"▲把表面功夫做到天衣无缝，用风格而非内容打动人。","e":"Polishing surface charm so well it's rarely caught out."},{"t":"detriment","p":"Saturn","z":"▼小看别人、高估自己，以为这套把戏永远不会被识破。","e":"Shallow bluffing that overrates itself and underrates everyone else."}]},"4":{"tz":"懂得致敬","te":"Honoring Others","mz":"天生看得见别人的功劳，尤其敬重那些以身作则的人。","me":"A gift for spotting real contribution and honoring those who lead by example.","pol":[{"t":"exalted","p":"Jupiter","z":"▲一心想融入并贡献，愿意成为他人可以效仿的榜样。","e":"Driven to belong and contribute, becoming an example for others."},{"t":"detriment","p":"Mercury","z":"▼只用道理衡量价值，看不见队里真正值得被认可的人。","e":"Judging worth by logic alone, missing who truly deserves credit."}]},"5":{"tz":"适时放手","te":"Knowing When to Let Go","mz":"懂得圆满之后该分开，羽翼丰了就放它飞，这才不伤情分。","me":"Understanding that a good union, once complete, is meant to release.","pol":[{"t":"exalted","p":"Jupiter","z":"▲像老师一样贡献，坦然接受聚散有时、尽兴而后放手。","e":"Giving like a teacher who accepts that every bond has its season."},{"t":"detriment","p":"Sun","z":"▼像放不开孩子的父母，把放手当成权威被冒犯。","e":"Clinging like a parent who reads a child's growth as a threat."}]},"6":{"tz":"默契共鸣","te":"In Tune","mz":"在和谐里生出笃定，自然知道何时该出手贡献。","me":"Certainty born from harmony, sensing exactly when to step in.","pol":[{"t":"exalted","p":"Venus","z":"▲读得懂节奏与规律，总在对的时机把创造拿出来。","e":"Reading the patterns and knowing the right moment to contribute."},{"t":"detriment","p":"Pluto","z":"▼即使时机再好也犯嘀咕，事后还忍不住后悔。","e":"Second-guessing the timing, left with regret even when all was right."}]}},"9":{"1":{"tz":"稳着解题","te":"A Steady Mind","mz":"遇到难题不急着发力,先想清楚再动手,把焦虑拆成一个个能解的小步。","me":"A grounded, level-headed way of working through problems one step at a time.","pol":[{"t":"exalted","p":"Pluto","z":"▲把注意力收拢,专注地造出新办法,从根上化解卡顿。","e":"Channeling focus to invent fresh forms and dissolve frustration."},{"t":"detriment","p":"Mars","z":"▼钥匙就在兜里却急着踹门,力气有了焦点却散了。","e":"Forcing the door when the key's in your pocket; raw energy with no focus."}]},"2":{"tz":"结伴解闷","te":"Better Together","mz":"独自憋着容易钻牛角尖,找对人一起琢磨,焦虑就被分担稀释了。","me":"Tempering frustration by joining with the right people to stay focused.","pol":[{"t":"exalted","p":"Pluto","z":"▲与人协作消解烦躁,把专注力汇成一股劲。","e":"Collaborating with others to ease frustration and pool focus."},{"t":"detriment","p":"Jupiter","z":"▼一味想做大,反而错判时机、丢了机会、陷入低落。","e":"Over-reaching for expansion that misjudges, misses chances, and saps mood."}]},"3":{"tz":"细节定败","te":"The Small Crack","mz":"压垮人的常是被忽略的那个小环节,失焦时小事会被堆成大事。","me":"The overlooked small detail that quietly decides whether things fall apart.","pol":[{"t":"exalted","p":"Earth","z":"▲临时用力顶过障碍,但一松专注,劲头就泄了。","e":"Brief force pushes past blocks, yet power drains once focus slips."},{"t":"detriment","p":"Sun","z":"▼硬撑到耗光元气,把小土丘较劲成翻不过的高山。","e":"Stubborn pushing that drains vitality and turns molehills into mountains."}]},"4":{"tz":"踏实守艺","te":"Quiet Discipline","mz":"不管压力多大,都肯在细节上耐心打磨,把对的事一步步做到位。","me":"Disciplined attention to detail that holds steady under any pressure.","pol":[{"t":"exalted","p":"Moon","z":"▲做对该做的事,顺势把潜力一点点兑现出来。","e":"Right action that steadily turns potential into reality."},{"t":"exalted","p":"Mars","z":"▲有股想跳过步骤的冲劲,行动力旺却容易漏掉细节。","e":"A drive to act fast that's tempted to skip the essential steps."}]},"5":{"tz":"信而后成","te":"Trust the Steps","mz":"相信把每个细节守好,终会走到圆满,哪怕一时看不到回报。","me":"Faith that patient, faithful attention to detail leads to fulfillment.","pol":[{"t":"exalted","p":"Jupiter","z":"▲一字一句照规矩来,让专注本身长出价值。","e":"Honoring the letter of the law so focus itself bears fruit."},{"t":"detriment","p":"Earth","z":"▼看不懂过程的逻辑就生疑,无法专注便动摇信心。","e":"Doubt born when a process seems illogical and focus won't hold."}]},"6":{"tz":"知足谢恩","te":"Small Joys Count","mz":"为小小的胜利领受小小的回报,在过程里就懂得心怀感激。","me":"The quiet joy of accepting small rewards for small victories.","pol":[{"t":"detriment","p":"Pluto","z":"▼非等全程走完才肯认值,过程中始终找不到欢喜。","e":"Counting nothing worthwhile until the whole journey ends, missing joy along the way."}]}},"10":{"1":{"tz":"安于其位","te":"Knowing Your Place","mz":"无论身处什么位置,都清楚自己是谁、该怎么做的踏实之人。","me":"Someone grounded who knows who they are and how to act, whatever the situation.","pol":[{"t":"exalted","p":"Sun","z":"▲不管站在哪个位置,都活得有分量、行得稳当。","e":"A steady sense of worth and right action in any position."},{"t":"detriment","p":"Moon","z":"▼太在意别人眼光,容易被环境带着走、动辄受伤。","e":"Too tender to outside pressure, easily swayed and hurt."}]},"2":{"tz":"独处自得","te":"Content Alone","mz":"靠独处守住自己活法的人,一个人待着反而最自在通透。","me":"A person who guards their own way of living through solitude, most at ease alone.","pol":[{"t":"exalted","p":"Mercury","z":"▲独处时脑子最活,一个人也能想得清、活得满。","e":"The mind thrives in solitude; aloneness becomes rich and clear."},{"t":"detriment","p":"Mars","z":"▼带着气躲起来,把孤立当成对抗世界的盾牌。","e":"Retreats in anger, using isolation as a shield against the world."}]},"3":{"tz":"较真的人","te":"The One Who Pushes Back","mz":"凭良心质疑既定规矩,哪怕碰壁也要试一试的人。","me":"Someone who questions set norms on principle and tries anyway, even at a cost.","pol":[{"t":"exalted","p":"Earth","z":"▲坚持到底的活法,日久被人记住,成了榜样。","e":"Steadfast conduct that endures and is finally honored by others."},{"t":"detriment","p":"Moon","z":"▼把吃苦演给人看,用受委屈来博取关注。","e":"Plays the victim for attention, chasing suffering to be seen."}]},"4":{"tz":"等对时机","te":"Waiting for the Turn","mz":"先按规矩来,暗暗蓄力,等时机一到就推动改变的人。","me":"Someone who plays by the rules, builds quietly, then drives change when the moment is right.","pol":[{"t":"exalted","p":"Uranus","z":"▲守着现状不动,等真正的拐点来时一跃升级。","e":"Holds the pattern until the right moment lifts it to a higher level."},{"t":"detriment","p":"Mercury","z":"▼把见机行事当游戏,随时改口只为占便宜。","e":"Treats opportunism as a game, shifting behavior just to gain an edge."}]},"5":{"tz":"敢破常规","te":"The Norm-Breaker","mz":"正面挑战旧规矩的人,不藏着掖着,凭原则硬碰硬。","me":"Someone who challenges old norms head-on, openly and on principle.","pol":[{"t":"exalted","p":"Jupiter","z":"▲靠想透并讲清更高的道理,正面撼动旧传统。","e":"Succeeds by grasping and voicing higher principles that shake tradition."},{"t":"detriment","p":"Mars","z":"▼硬刚到底,最终被群体当成出头鸟打压。","e":"Defies head-on until the crowd turns and punishes the outlier."}]},"6":{"tz":"以身作则","te":"Leading by Living","mz":"不靠说教、靠自己怎么活给人看,成为别人参照的人。","me":"Someone who teaches not by words but by how they live, becoming a reference for others.","pol":[{"t":"exalted","p":"Pluto","z":"▲用行动而非言语示范,把懈怠的人拉回正轨。","e":"A living example that pulls the complacent back through action, not words."},{"t":"detriment","p":"Saturn","z":"▼只会嘴上一套,要求别人却管不住自己。","e":"All talk and no walk; demands of others what they won't do themselves."}]}},"11":{"1":{"tz":"同频之人","te":"Finding Your People","mz":"你的想法需要懂的人接住,在对的圈子里灵感才被点亮。","me":"Your ideas come alive when you find the people who get them.","pol":[{"t":"exalted","p":"Moon","z":"和志同道合的人在一起,你被滋养,想法也终于有人珍惜。","e":"Among kindred spirits you feel fed, and your ideas finally land."},{"t":"detriment","p":"Mars","z":"怕没人在乎自己,担心想法被埋没、无人问津。","e":"A fear of going unseen, that no one will value what you think."}]},"2":{"tz":"居安思危","te":"Staying Sharp","mz":"太平日子里也别松懈,缺了警觉和一点冒险,安稳会发霉。","me":"Even in calm times, drop your guard and peace turns to rot.","pol":[{"t":"exalted","p":"Neptune","z":"用想象力守住已有的成果,无聊就靠创意把它越过去。","e":"Imagination guards what you've built and carries you past boredom."},{"t":"detriment","p":"Mars","z":"闲得发慌就拉帮结派、故意挑事,只为给自己找点动静。","e":"Restless boredom breeds factions and provocation just to stir things up."}]},"3":{"tz":"清醒看戏","te":"The Realist","mz":"明白安稳不会长住,想法来了又走,别太当真也别失落。","me":"Peace never stays; ideas pass through, so hold them lightly.","pol":[{"t":"exalted","p":"Pluto","z":"靠内在不断更新,保持力气与清醒,接受念头自来自去。","e":"Renew from within to stay strong and alert as ideas come and go."},{"t":"detriment","p":"Venus","z":"贪恋眼前的美好到看不清现实,以为好景永在,城烧了还在抚琴。","e":"So in love with harmony you ignore reality, fiddling while it burns."}]},"4":{"tz":"讲得明白","te":"The Teacher","mz":"能把安稳的道理讲清楚,连门外汉都听得懂、被吸引。","me":"You can put peace into words even outsiders grasp and warm to.","pol":[{"t":"exalted","p":"Moon","z":"像位智者,连五音不全的人都能教会;把疏离的人也拉回来。","e":"A sage who can teach harmony to the tone-deaf and reach the alienated."},{"t":"detriment","p":"Sun","z":"像把智慧锁起来的导师,好东西只留给少数几个人懂。","e":"A guru who keeps the best wisdom for a chosen few."}]},"5":{"tz":"无私给予","te":"The Giver","mz":"不图回报地照顾弱者,用富人情味的想法换一份和气。","me":"You give to the overlooked without agenda, ideas in service of harmony.","pol":[{"t":"exalted","p":"Moon","z":"不带目的地照拂被冷落的人,胸中装着利他与人道的念头。","e":"Nurturing the forgotten with no motive, carrying humane ideas."},{"t":"detriment","p":"Mercury","z":"把给予当挡箭牌,因为心虚才急着把想法送出去、躲开真接触。","e":"Giving as a shield, handing off ideas out of insecurity to avoid real contact."}]},"6":{"tz":"顺势而转","te":"Going With Change","mz":"心里稳,接得住变化;明白一切都会变,想法也是。","me":"Grounded enough to accept transition, knowing all things shift.","pol":[{"t":"exalted","p":"Neptune","z":"天生懂得万物无常,想法既会带来改变,也会被改变。","e":"An innate sense that all forms pass, and ideas both cause and undergo change."},{"t":"detriment","p":"Jupiter","z":"应变沦为投机,无论太平还是动荡,都踩着别人捞好处。","e":"Adaptability turned to profiteering, gaining at others' expense in peace or war."}]}},"12":{"1":{"tz":"群中独修者","te":"The Supported Hermit","mz":"你需要退后独处来保持内心的清明,但这份退避要有人懂、有人撑着才走得长久。","me":"One who steps back into stillness, sustained only when the community has their back.","pol":[{"t":"exalted","p":"Venus","z":"▲在远离诱惑的安静里,你活出一种被人接住的从容与美。","e":"Out of temptation's reach, a graceful poise that others gladly support."},{"t":"detriment","p":"Jupiter","z":"▼把退避做到极端,变成与世隔绝、连人情都拒之门外的荒诞独居。","e":"Withdrawal taken to an absurd extreme, walling off all human warmth."}]},"2":{"tz":"自净之人","te":"Keeping Clean","mz":"你会本能地远离那些消耗你、污染你的人和事,守住一片清爽的内在。","me":"Instinctively pulling away from what drains or contaminates, to stay clear within.","pol":[{"t":"exalted","p":"Saturn","z":"▲靠自律守住纯净,该断的关系果断断开,不被拖泥带水。","e":"Discipline that holds a clean state and cuts what muddies it."},{"t":"detriment","p":"Mercury","z":"▼清静久了反而无聊空虚,忍不住到处找刺激来填补。","e":"Quiet curdles into boredom, then a restless hunt for stimulation."}]},"3":{"tz":"向内自省","te":"Honest Reckoning","mz":"在与人互动的磕碰里看见自己的不足,然后诚实地面对、清理掉虚荣。","me":"Seeing one's own gaps through social friction, then facing them honestly.","pol":[{"t":"exalted","p":"Neptune","z":"▲坦然承认自己的短处,放下不必要的自我抬高,越省越通透。","e":"Owning one's shortcomings and shedding hollow vanity, growing clearer."},{"t":"exalted","p":"Mars","z":"▲自省一不留神就过头,变成对自己又狠又夸张的厌弃。","e":"Self-scrutiny tips over into harsh, exaggerated self-loathing."}]},"4":{"tz":"先知报信","te":"The Forecaster","mz":"你能预感停滞何时该结束,提前发声、号召大家一起为重新连结做准备。","me":"Sensing when the standstill should end and rallying others to prepare.","pol":[{"t":"exalted","p":"Earth","z":"▲唤醒沉睡停摆的人,把大家聚拢起来,迎接重新交流的时刻。","e":"Rousing the stalled and gathering them for renewed connection."},{"t":"detriment","p":"Mercury","z":"▼一片好意喊得再响,却像旷野独白,没人听得进去。","e":"A heartfelt call that goes out like a voice in the wilderness, unheard."}]},"5":{"tz":"务实留种","te":"Keeping the Lesson","mz":"懂得克制的人,真正的本事是停滞期结束后,不把学到的教训丢掉。","me":"Restraint pays off when, once the phase ends, the lessons aren't thrown away.","pol":[{"t":"exalted","p":"Sun","z":"▲见过黑暗才更懂光的可贵,谨慎是阅历沉淀出的智慧。","e":"Having known the dark, you value the light; caution born of experience."},{"t":"exalted","p":"Mars","z":"▲只记住最痛的那些教训,从此变得过度防备、缩手缩脚。","e":"Remembering only the most painful lessons, growing over-guarded."}]},"6":{"tz":"蜕变新生","te":"Breaking Through","mz":"对改变有信心、肯投入能量,带着大家走出停滞,长出全新的相处方式。","me":"Faith and energy poured into change, emerging from standstill into a new form.","pol":[{"t":"exalted","p":"Sun","z":"▲富有创造力地跨越旧框架,带来一种崭新的社交与连结方式。","e":"Creative transcendence that births a fresh way of relating."},{"t":"detriment","p":"Earth","z":"▼蜕变走了回头路,把自己完美地适应进停滞,认了那些局限。","e":"A backward shift that perfects adapting to the standstill, accepting its limits."}]}},"13":{"1":{"tz":"倾听共情","te":"Listening with Empathy","mz":"能与各种人平和相处、敞开倾听的人，把别人的故事接住而不评判。","me":"One who relates to everyone with calm openness, receiving their stories without judgment.","pol":[{"t":"exalted","p":"Venus","z":"▲带着温情去听，让人感到被接纳，关系自然变得和谐。","e":"Listening with genuine warmth, making others feel accepted; harmony follows."},{"t":"detriment","p":"Moon","z":"▼像政客作秀般亲切，敞开总藏着目的，热情里有算计。","e":"Warmth like a politician kissing babies; openness never quite free of motive."}]},"2":{"tz":"圈子之墙","te":"The Walled Circle","mz":"只愿向同类敞开的人，圈子温暖却有界限，容易把不同的人挡在门外。","me":"One who opens only to their own kind; the circle feels warm but quietly shuts others out.","pol":[{"t":"exalted","p":"Moon","z":"▲用包容当缓冲，即便有偏好也尽量留一道门给不同的人。","e":"Tolerance as the gentlest face of bias; leaving a door open despite preferences."},{"t":"detriment","p":"Sun","z":"▼坚信只有自己人配得上理想，圈子窄到几乎没人值得听。","e":"Certain only one's own deserve the ideal; the circle so narrow almost no one is worth hearing."}]},"3":{"tz":"试错的疑心","te":"Earned Trust","mz":"不轻易相信、要看到实证才肯敞开的人，在试错与怀疑中慢慢确认真伪。","me":"One slow to trust, opening only once shown proof; sifting truth through doubt and trial.","pol":[{"t":"exalted","p":"Earth","z":"▲不盲信，但只要拿出实打实的证据，怀疑就会化成信任。","e":"No blind faith, yet solid evidence turns suspicion into trust."},{"t":"detriment","p":"Venus","z":"▼把悲观当成本事，用讽刺戳穿一切，反倒让人看清荒诞。","e":"Pessimism honed into satire; suspicion turned to art that exposes the absurd."}]},"4":{"tz":"停战歇息","te":"Truce and Rest","mz":"敞开太久会被掏空的人，懂得在累到打不动时退一步、安静下来再回血。","me":"One drained by too much openness, who knows to step back into silence and recover.","pol":[{"t":"exalted","p":"Pluto","z":"▲先停火、给自己安静，沉淀之后会迎来一次崭新的重启。","e":"A truce and quiet first; from the stillness comes genuine renewal."},{"t":"detriment","p":"Venus","z":"▼情绪被耗尽，只能一味妥协退缩，敞开成了被消耗的破口。","e":"Emotionally spent, only appeasing and withdrawing; openness becomes a wound."}]},"5":{"tz":"安置众人","te":"Finding Each a Role","mz":"天生会听、能为每个人找到位置的人，看见他人的价值并把他放对地方。","me":"A natural listener gifted at finding a place for everyone, seeing each person's worth.","pol":[{"t":"exalted","p":"Neptune","z":"▲有魅力又有洞见，总能在人群里为每个人找到合适的位置。","e":"Charismatic and perceptive, finding a fitting role for everyone in the room."},{"t":"detriment","p":"Jupiter","z":"▼把这份天赋落到实处，当个踏实的管理者去把人安排妥当。","e":"Grounding the gift into practical administration, placing people capably."}]},"6":{"tz":"怀抱希望","te":"The Hopeful One","mz":"把每次有限的相处都当成走向更深连结的一步，始终相信关系会更好的人。","me":"One who treats every limited encounter as a step toward deeper union, always believing relationships can grow.","pol":[{"t":"exalted","p":"Mars","z":"▲有股不灭的劲头，坚信只要继续敞开，关系终会越来越好。","e":"Tireless drive and undimmed hope that openness will deepen every bond."},{"t":"detriment","p":"Mercury","z":"▼太天真，把一时的共同利益当成永恒，硬投射到所有人身上。","e":"Naive, mistaking momentary shared interest for the universal, projecting it onto all."}]}},"14":{"1":{"tz":"钱不是全部","te":"Money Isn't Everything","mz":"拥有财富后才看清:钱能放大问题,真正撑起力量的是内在的原则。","me":"Wealth amplifies as many problems as it solves; principle, not money, is what truly holds power.","pol":[{"t":"exalted","p":"Jupiter","z":"▲对钱的渴望被更高的原则托住,力量从价值观里长出来。","e":"Desire for wealth held in check by higher values; power grows from principle."},{"t":"detriment","p":"Mercury","z":"▼以为砸钱就能摆平一切,只用资源蛮干,力气终会落空。","e":"The illusion that money fixes everything; raw resources alone never become the key."}]},"2":{"tz":"懂得放手","te":"Knowing How to Delegate","mz":"把活儿交给更专业的人,力量来自不再事事亲为,而是信任与协作。","me":"Power comes from trusting expertise and delegating, not from doing it all yourself.","pol":[{"t":"exalted","p":"Jupiter","z":"▲愿意分权、托付他人,格局因此打开,事业自然扩张。","e":"Willing to delegate and share load; the reach expands and grows."},{"t":"detriment","p":"Mars","z":"▼自负地认为只有自己最在行,凡事一把抓,反被困住。","e":"Vanity of being one's own best expert; gripping everything and getting stuck."}]},"3":{"tz":"为众而用","te":"Putting It to Good Use","mz":"把才华与财富用在利他上的人;给予能让力量循环,贪占则反噬自身。","me":"Talent and wealth turned toward serving others; giving renews power, hoarding corrodes it.","pol":[{"t":"exalted","p":"Earth","z":"▲忘我地贡献社会,力量在无私的给予中越用越稳。","e":"Selfless contribution to society; power steadies through generous giving."},{"t":"exalted","p":"Neptune","z":"▲同样的能量若滑向贪婪,会一点点蚀掉道德的根。","e":"The same drive, if it tips into greed, quietly eats away one's moral roots."}]},"4":{"tz":"扎稳根基","te":"Building a Firm Base","mz":"力量来自把根基筑牢的人;先有真本事,守得住,才谈得上扩张。","me":"Power belongs to those who build a solid foundation first, securing it before reaching out.","pol":[{"t":"exalted","p":"Moon","z":"▲懂得磨练技能护住根基,稳得住才扛得起冲击。","e":"Honing skills to guard the base; steadiness lets one withstand any blow."},{"t":"detriment","p":"Mars","z":"▼轻敌冒进,本事还没练成就硬接挑战,根基反被掏空。","e":"Overconfidence meeting rivals unprepared; the very foundation gets hollowed out."}]},"5":{"tz":"莫生傲气","te":"Guarding Against Arrogance","mz":"身处高位最易染上的隐患;真力量自带尊严,傲慢只造出虚幻的优越感。","me":"Power's quiet hazard is arrogance; true dignity is innate, superiority is illusion.","pol":[{"t":"exalted","p":"Sun","z":"▲天生自带从容的尊严,不靠贬低别人就站得住。","e":"An innate, quiet dignity that holds without putting anyone down."},{"t":"detriment","p":"Venus","z":"▼看不上他人的天赋,靠俯视别人喂养出虚假的优越。","e":"Disdain for others' gifts feeding a hollow sense of being above them."}]},"6":{"tz":"心怀谦卑","te":"Carrying Humility","mz":"走到富足顶端却愈发谦卑的人;承认成就是机缘所赐,力量便有了归处。","me":"Reaching abundance yet growing humble; accepting that success was grace gives power a home.","pol":[{"t":"exalted","p":"Sun","z":"▲在精神层面看懂富足是天意,接纳与谦卑成了力量之源。","e":"Seeing abundance as a higher will; acceptance and humility become the source of power."},{"t":"detriment","p":"Earth","z":"▼此位本质皆正面;坦然承认成功来得偶然,因这份机缘而谦卑。","e":"All here is essentially positive; owning that success simply happened, humbled by the serendipity."}]}},"15":{"1":{"tz":"尽其本分","te":"Quiet Duty","mz":"不带期待地接下每一份责任,踏实做完该做的事。","me":"Taking on whatever comes, with no demands attached.","pol":[{"t":"exalted","p":"Venus","z":"▲扬升:靠和睦的关系彼此托举,再难的事也有人陪你扛。","e":"Harmonious bonds that carry you through any task."},{"t":"detriment","p":"Mars","z":"▼落陷:把话说太满、自抬身价,反倒把身边人都推远了。","e":"Overblown claims that push everyone away."}]},"2":{"tz":"顺势而为","te":"Natural Sway","mz":"接纳自己起落不定的本性,顺着节奏走,自然能影响别人。","me":"Accepting your own extremes, you move others by simply being you.","pol":[{"t":"exalted","p":"Sun","z":"▲扬升:放下做作,如实做自己,立下的标准反而长久。","e":"Unforced, true action that sets lasting standards."},{"t":"detriment","p":"Earth","z":"▼落陷:刻意经营出来的姿态,虽也有力,却少了那份天然。","e":"Contrived poses that work, but lack the natural touch."}]},"3":{"tz":"别太得意","te":"Don't Overclaim","mz":"谦逊一旦被看见就容易膨胀,试错中要守住分寸。","me":"Once your modesty is praised, the ego is tempted to ruin it.","pol":[{"t":"exalted","p":"Earth","z":"▲扬升:被认可后仍守住谦逊,把它变成稳稳带动局面的方式。","e":"Recognition reinforces modesty into a steady, working strategy."},{"t":"detriment","p":"Mercury","z":"▼落陷:一句「我早说过」,忙着挑别人的过头,自己也过头。","e":"The 'I told you so' habit of pointing out others' excess."}]},"4":{"tz":"藏在墙角","te":"By the Wall","mz":"用低调当挡箭牌,怕暴露自己不够好,宁可退到边上。","me":"Hanging back, using modesty to hide what feels not-good-enough.","pol":[{"t":"exalted","p":"Jupiter","z":"▲扬升:这份退缩是真实的,坦然承认不在状态,无需硬装。","e":"An honest discomfort when you're simply out of flow."},{"t":"detriment","p":"Saturn","z":"▼落陷:躲是躲不住的,这层薄壳终会被戳破、被看穿。","e":"A flimsy shield that ends in exposure and embarrassment."}]},"5":{"tz":"因境调和","te":"Read the Room","mz":"敏锐察觉环境在变,该调整时就调整,不死守原本的平衡。","me":"Sensing when a shifting world calls you to recalibrate.","pol":[{"t":"exalted","p":"Jupiter","z":"▲扬升:在大起大落里长见识,每一次极端都成了成长。","e":"Growing wiser by living through the extremes."},{"t":"detriment","p":"Pluto","z":"▼落陷:用力过猛、矫枉过正,一调就调过头,搅乱了节奏。","e":"Overcorrecting so hard it disturbs the whole flow."}]},"6":{"tz":"护己有度","te":"Modest, Not Weak","mz":"谦逊不等于软弱,该守的底线一寸不让。","me":"Modesty that never gets mistaken for weakness.","pol":[{"t":"exalted","p":"Pluto","z":"▲扬升:不断自查,直面那些极端处境,找出并补上最薄弱的环节。","e":"Always re-examining to root out your weakest point."},{"t":"detriment","p":"Venus","z":"▼落陷:用「和气」回避矛盾,绕开真正的病根,问题留在原地。","e":"Using harmony to dodge the real root of the problem."}]}},"16":{"1":{"tz":"白日梦者","te":"Empty Hype","mz":"热情还停在脑海里,容易把幻想当真实的人。","me":"Enthusiasm that lives in fantasy, mistaking dreams for facts.","pol":[{"t":"exalted","p":"Earth","z":"▲让想象先行酝酿,在白日梦里把天赋慢慢养成形。","e":"Imagination as incubator — talent quietly ripening through daydreams."},{"t":"detriment","p":"Mercury","z":"▼把没影的事说得跟真的一样,空头支票四处兑现。","e":"Broadcasting fantasy as fact, making promises that never land."}]},"2":{"tz":"戳破泡泡","te":"Clear-Eyed Skeptic","mz":"天生一眼看穿浮夸的人,能撇开花言巧语直击真假。","me":"A natural at seeing through hype, judging claims past the rhetoric.","pol":[{"t":"exalted","p":"Sun","z":"▲不被话术带跑,靠自己冷静衡量一件事到底成不成立。","e":"Self-reliant clarity — weighing any claim on its merits, not its packaging."},{"t":"detriment","p":"Mercury","z":"▼挑刺上了瘾,把怀疑本身当成兴奋点,逢事必泼冷水。","e":"Skepticism turned compulsion — cynicism itself becomes the thrill."}]},"3":{"tz":"自给热情","te":"Self-Fueled Spark","mz":"热情能自己点燃自己,靠节奏和时机维持不靠别人续命。","me":"Enthusiasm that fuels itself, kept alive by rhythm and timing.","pol":[{"t":"exalted","p":"Moon","z":"▲懂得踩对节拍,在合适的时机出手,不让热情泄气。","e":"A feel for timing — keeping the rhythm so momentum never deflates."},{"t":"detriment","p":"Mars","z":"▼太逞强一受挫就蔫,得靠别人捧场才重新有劲。","e":"Overconfidence that crashes, then leans on others to recharge."}]},"4":{"tz":"托举他人","te":"Genuine Backer","mz":"真心欣赏并撑起别人的人,把热情投向更大的目标。","me":"Genuinely recognizing and lifting others toward bigger goals.","pol":[{"t":"exalted","p":"Jupiter","z":"▲为更高的目标投入,也擅长看见并成全别人的才华。","e":"Devotion to higher aims, with a gift for backing others' talents."},{"t":"detriment","p":"Mars","z":"▼煽动人心却不肯认可任何人,把舞台只留给自己。","e":"The demagogue — rousing crowds yet refusing to credit anyone else."}]},"5":{"tz":"拒绝同欢","te":"Reluctant Spark","mz":"习惯置身热情之外的人,直到被真正打动才彻底转变。","me":"Holding back from shared enthusiasm until truly won over.","pol":[{"t":"exalted","p":"Pluto","z":"▲先抽身冷眼旁观,一旦被真心说服,热情来得更深更久。","e":"Standing apart on purpose — once converted, the fire burns deeper and longer."},{"t":"detriment","p":"Moon","z":"▼总觉得跟人同乐会拖累自己,凭什么我要替你高兴。","e":"Feeling shared joy holds you back — why should I be glad for you?"}]},"6":{"tz":"易被煽动","te":"Easily Swayed","mz":"容易被花哨说辞带动的人,功课是学会辨别真假热情。","me":"Susceptible to propaganda; learning to tell real fervor from hollow.","pol":[{"t":"exalted","p":"Neptune","z":"▲亲身体验后再判断,识破虚假的热情并干脆放下。","e":"Tasting, testing, then rejecting hollow hype — a knack for sizing others up."},{"t":"detriment","p":"Jupiter","z":"▼一旦失望就痛苦退场,从此对某种圈子彻底成见在心。","e":"Withdrawing in pain when let down, forever prejudiced against the fold."}]}},"17":{"1":{"tz":"开放容纳","te":"An Open Mind","mz":"能接住各种信息的人,见得多,看法也多。但别只对顺眼的东西敞开心。","me":"Someone who takes in a wide range of input and forms many views from it.","pol":[{"t":"exalted","p":"Mars","z":"▲有容量消化大量刺激,看法丰富,来者不拒。","e":"Stamina to absorb broad stimuli and hold many opinions."},{"t":"detriment","p":"Venus","z":"▼只对漂亮悦目的东西开放,看法因偏好而变窄。","e":"Opens only to what pleases the eye, narrowing one's views."}]},"2":{"tz":"择善而交","te":"Choosing Well","mz":"懂得跟价值观相投的人来往,在关系里慢慢长出自己的看法。","me":"One who forms opinions through the right relationships, chosen by shared values.","pol":[{"t":"exalted","p":"Sun","z":"▲选对了同伴,在合拍的关系里把看法养成。","e":"Aligns with the right people and grows views through them."},{"t":"detriment","p":"Moon","z":"▼挑剔过头把人都筛走,固执到只剩自己。","e":"Over-fussy filtering leaves one opinionated and alone."}]},"3":{"tz":"踏实走完","te":"The Long Road","mz":"明白最好的路未必最有趣,愿意走完全程,看法才有底气。","me":"One who knows the best road isn't the fun one, and earns solid views by walking it.","pol":[{"t":"exalted","p":"Pluto","z":"▲老实走完正道,细节里磨出经得起考验的看法。","e":"Walks the full road; opinions are grounded in real detail."},{"t":"detriment","p":"Earth","z":"▼抄近路图快,跳过细节,看法也跟着空。","e":"Takes shortcuts, skips detail, and hollows out the opinion."}]},"4":{"tz":"识人用人","te":"Reading People","mz":"善于看穿别人的动机和分量,看法建立在懂人之上。","me":"One who sees others' true motives and forms opinions from understanding them.","pol":[{"t":"exalted","p":"Pluto","z":"▲能探到人心底的动机与本钱,看法因懂人而准。","e":"Probes others' real motives and resources; opinions built on insight."},{"t":"detriment","p":"Jupiter","z":"▼来者不拒滥收人,看法只为招揽,常招祸。","e":"Over-generous acceptance of followers; opinions made to attract, often backfiring."}]},"5":{"tz":"彼此相连","te":"All Connected","mz":"看清没有人是孤岛,层层关系没有尽头,组织起来才有价值。","me":"One who sees no one stands alone and values being interconnected and organized.","pol":[{"t":"exalted","p":"Uranus","z":"▲把相互依存活成大格局,看法点出协作的价值。","e":"Lives interdependence as a larger whole; voices the worth of being organized."},{"t":"detriment","p":"Mars","z":"▼自大到'到我为止',看法拒认协作的意义。","e":"Arrogant 'buck stops here'; opinions deny the value of organization."}]},"6":{"tz":"以身示范","te":"The Living Example","mz":"走到圆熟处,跟随与带领合一,看法能真正利益他人。","me":"One who, having mastered the path, offers opinions of genuine value to others.","pol":[{"t":"exalted","p":"Moon","z":"▲温厚的滋养者,懂得相依,看法对人有益。","e":"The nurturer who grasps interdependence and shares views that help others."},{"t":"detriment","p":"Jupiter","z":"▼以为路是直线已到头,觉得再没什么可学。","e":"Mistakes the path for a finished line; opinions that there's nothing left to learn."}]}},"18":{"1":{"tz":"守旧之人","te":"Conservatism","mz":"想修补眼前的乱,却又舍不得放下旧规矩的人。","me":"Someone who wants to fix what's broken yet clings to the old ways.","pol":[{"t":"exalted","p":"Earth","z":"一点点微调旧习,在动荡来临前就悄悄把判断校准好。","e":"Quiet, gradual tweaks that head off upheaval before it ever hits."},{"t":"detriment","p":"Jupiter","z":"像固执的老家长,死守旧框架,反而亲手让一切慢慢烂掉。","e":"The stubborn patriarch whose rigidity quietly lets everything rot."}]},"2":{"tz":"认命之时","te":"Beyond Repair","mz":"看清有些坏掉的东西已无法挽回,只能学着放手的人。","me":"Someone who sees that some things are broken past saving, and learns to let go.","pol":[{"t":"exalted","p":"Pluto","z":"信旧的会消亡、新的会再生,于是坦然接受这场不可逆。","e":"Trusting in rebirth, calmly accepting what truly can't be undone."},{"t":"detriment","p":"Moon","z":"明知无力回天,却仍对着风白白嘶吼,不肯认那个结果。","e":"Raging uselessly at the wind, refusing to accept it's over."}]},"3":{"tz":"改革狂热","te":"The Zealot","mz":"停不下来非要把一切彻底翻新、清理干净的人。","me":"Someone driven to tear it all down and clean house at any cost.","pol":[{"t":"exalted","p":"Neptune","z":"懂得让旧形式自然瓦解,代价不大,改得恰到好处。","e":"Letting old forms dissolve at a price that's fair, change done right."},{"t":"detriment","p":"Jupiter","z":"死板地挑剔评判,解决一个问题又添一堆新麻烦,自己也不满足。","e":"Rigid judging that breeds as many problems as it fixes, never satisfied."}]},"4":{"tz":"力不从心","te":"Out of Depth","mz":"看见问题却没能力去修,卡在自身的不足里走不出来的人。","me":"Someone who sees the problem but lacks the means to fix it, stuck in their own limits.","pol":[{"t":"exalted","p":"Earth","z":"处境不利、修不了,就在熬过苦难中慢慢挺了下来。","e":"Unable to fix it, surviving by enduring the hardship anyway."},{"t":"detriment","p":"Mercury","z":"被该修的事逼着,却犹豫焦虑、绕不出困局,越想越慌。","e":"Pushed to correct, but trapped in indecision and spiraling anxiety."}]},"5":{"tz":"求助疗愈","te":"Therapy","mz":"有勇气承认问题、也接受自己一个人解决不了,愿意找人帮的人。","me":"Someone brave enough to admit a problem and accept they can't fix it alone.","pol":[{"t":"exalted","p":"Saturn","z":"既会去找懂的人请教,也能反过来给别人靠谱的指引。","e":"Wise enough to both seek guidance and offer it to others."},{"t":"detriment","p":"Uranus","z":"关系帮不上忙时,内在长期失稳,情绪一路滑向崩溃边缘。","e":"When no relationship can help, chronic instability tips toward breakdown."}]},"6":{"tz":"圆满典范","te":"The Perfected Form","mz":"经过反复修正,活成接近完美的样子,成为他人榜样的人。","me":"Someone who, through endless correcting, becomes a near-perfect example for others.","pol":[{"t":"exalted","p":"Mars","z":"像永葆童心的觉者,不停寻找新天地,绝不让自己停滞。","e":"An eternal child, always seeking new horizons, never letting things stall."},{"t":"detriment","p":"Moon","z":"把这份圆满落到日常,读懂大众心声,把修正的方法分享出去。","e":"Bringing it down to earth, sensing public mood and sharing the method."}]}},"19":{"1":{"tz":"彼此需要","te":"Mutual Need","mz":"渴望被接纳,却不肯弄丢自己。在靠近别人时,守住那个独一无二的我。","me":"Craving acceptance while keeping your own shape intact when others let you in.","pol":[{"t":"exalted","p":"Sun","z":"▲被群体接纳,本色却不褪色——靠近,但始终是自己。","e":"Welcomed by others yet never blurred — you fit in as yourself."},{"t":"detriment","p":"Moon","z":"▼一被接纳就停步反刍,怕被抛下,于是不敢再往前长。","e":"Once accepted, you stall in worry over rejection and stop growing."}]},"2":{"tz":"甘心付出","te":"Willing Service","mz":"因为被人触动,愿把自己的资源、心力交出去。被需要,点亮了奉献的劲。","me":"Stirred by contact, you pour your own resources into being of use.","pol":[{"t":"exalted","p":"Jupiter","z":"▲为真正值得的事倾力付出,服务里有一份开阔与信念。","e":"Devotion to what truly matters — service rooted in higher values."},{"t":"detriment","p":"Mercury","z":"▼想被需要却久久拿不定主意,绕一圈,最终还是会答应去做。","e":"Long indecision born of wanting to be wanted — but you do say yes in the end."}]},"3":{"tz":"用心守护","te":"Tending the Bond","mz":"亲近不是天上掉的,要常常留意、用心照看,关系才不会悄悄凉掉。","me":"Closeness survives only through steady attention, not by luck.","pol":[{"t":"exalted","p":"Venus","z":"▲被接纳滋养出的从容,与人相处自然、敏锐又毫不费力。","e":"Acceptance fuels an easy, tender attunement to those around you."},{"t":"detriment","p":"Moon","z":"▼太敏感、易随情绪起伏,一不留神就把关系搁置荒了。","e":"Moodiness and thin skin let carelessness creep into the bond."}]},"4":{"tz":"携手同行","te":"Team Player","mz":"用自己的方式靠近人,也吸引别人来配合。一个人冲,也带得动一群人。","me":"Approaching in your own way, you draw cooperation and move the whole group.","pol":[{"t":"exalted","p":"Mars","z":"▲一股向外的冲劲,乐于结伴,只要你跟得上,就一起把事做成。","e":"Outward drive that thrives in company and lifts the whole group along."},{"t":"detriment","p":"Venus","z":"▼亲和又愿合作,却总嫌别人贡献不够,被他人的局限磨得不满。","e":"Warm and cooperative, yet chronically dissatisfied with what others bring."}]},"5":{"tz":"顾全大局","te":"Greater Good","mz":"为了更大的目标,愿意收一收自己的锋芒和需要。退一步,是为了成全更多。","me":"Reining in your own potential so a larger goal can be reached.","pol":[{"t":"exalted","p":"Earth","z":"▲天生懂得克己,把敏感与欲望沉住,稳稳服务于更大的事。","e":"An innate self-restraint that holds your sensitivities steady for the bigger aim."},{"t":"detriment","p":"Jupiter","z":"▼一边牺牲一边带着居高临下,付出反而磨钝了对人的体察。","e":"Sacrifice slips into condescension, dulling your feel for others."}]},"6":{"tz":"避世独处","te":"The Recluse","mz":"整体上避开接触,却不是全然断绝。退到山上,愿来的人,仍能聊上几句。","me":"Generally withdrawing from contact, though never sealing the door completely.","pol":[{"t":"exalted","p":"Jupiter","z":"▲山上的智者,你若找得到,他便与你长谈——避世,是一种从容的选择。","e":"The sage on the hill: find him, and he'll talk — withdrawal as quiet wisdom."},{"t":"detriment","p":"Mars","z":"▼像闹脾气的孩子自我放逐,非要等人来哄,因怕被拒而躲起来。","e":"A sulking self-exile that ends only when someone comes to soothe it."}]}},"20":{"1":{"tz":"表面功夫","te":"Living on the Surface","mz":"习惯停在表层、用轻巧话语应对世界的人,擅长抓眼球却少往深处走。","me":"Someone who lives at the surface, catching attention with light, quick expression.","pol":[{"t":"exalted","p":"Venus","z":"▲把浅显说成一门艺术,一句金句直击人心,简洁也是天赋。","e":"Turns the surface into an art form, landing a single line that sticks."},{"t":"detriment","p":"Moon","z":"▼只把浅薄当成本色随口而出,空有姿态却没有分量。","e":"Just blurts out the shallow self, all gesture and no weight."}]},"2":{"tz":"认死理者","te":"The Narrow Believer","mz":"认准一条窄路就走到底的人,信念很纯,视野却容易被自己框住。","me":"One who commits to a single narrow path, pure in belief but boxed in by it.","pol":[{"t":"exalted","p":"Venus","z":"▲若是退一步独自清修,这份固执反而沉淀成定力,守住当下。","e":"Through quiet withdrawal, the narrowness settles into focus on the now."},{"t":"detriment","p":"Moon","z":"▼一开口就把别人也领上自己的窄路,把局限当真理传给他人。","e":"Speaks others onto the same narrow road, passing limits off as truth."}]},"3":{"tz":"照见自己","te":"Seeing Oneself","mz":"在自己的言行里反复照见自己的人,靠自我觉察一点点长出分寸。","me":"Someone who grows through watching their own actions and seeing themselves clearly.","pol":[{"t":"exalted","p":"Sun","z":"▲恰到好处的自我觉察,让人格在当下被打磨得越来越通透。","e":"Well-tuned self-awareness shapes the personality, clearer in each moment."},{"t":"detriment","p":"Earth","z":"▼自我意识过了头,处处审视自己反而把自己卡死、动弹不得。","e":"Self-consciousness taken too far jams growth and freezes every move."}]},"4":{"tz":"借力成事","te":"Acting Through Others","mz":"看得清、想得明,却要靠会动手的人来落地的人,擅长点燃却需同伴接力。","me":"One who sees and understands clearly, but needs doers to turn it into action.","pol":[{"t":"exalted","p":"Jupiter","z":"▲像一位甘心被学生超越的老师,把觉知交给他人去化成行动。","e":"The teacher whose students surpass him, his insight acted out by others."},{"t":"detriment","p":"Mercury","z":"▼只爱在脑中把理论说得头头是道,对真正去做却兴致缺缺。","e":"Loves the theory in the head but has little appetite for doing it."}]},"5":{"tz":"面对现实","te":"Facing What Is","mz":"光是冥想觉察并不能保证成事,这条爻提醒人把觉知落回现实细节。","me":"Contemplation alone guarantees nothing; this line grounds awareness in reality.","pol":[{"t":"exalted","p":"Saturn","z":"▲专注打磨每个细节,让觉知最终凝成一个近乎完美的成果。","e":"Focus on detail brings awareness into a near-perfected, finished form."},{"t":"detriment","p":"Uranus","z":"▼总对眼前现实不满,这份不满搅得自己和周围都难安定。","e":"Endless dissatisfaction with reality breeds restlessness and instability."}]},"6":{"tz":"通达之智","te":"Lived Wisdom","mz":"冥想沉淀出能用得上的智慧的人,把个人觉知化作众人可循的道理。","me":"One whose contemplation ripens into wisdom others can actually use.","pol":[{"t":"exalted","p":"Venus","z":"▲为众人立下可理解、可实践的价值与理想,让觉知惠及大家。","e":"Builds values and ideals society can grasp and apply, for everyone's good."},{"t":"detriment","p":"Mercury","z":"▼同样能把觉知化为众用,动机却只是想满足自己那点智力快感。","e":"Same gift for the public, but driven by the thrill of the mental puzzle."}]}},"21":{"1":{"tz":"最后通牒","te":"The Final Word","mz":"懂得把武力留到最后一刻的人,先警告,逼不得已才出手。","me":"One who keeps force as the last card, warning first and acting only when there's no other way.","pol":[{"t":"exalted","p":"Mars","z":"▲不动声色就让人敬畏,气场和定力足以服众,无需真的动手。","e":"Commands respect by sheer presence and resolve, never needing to lift a hand."},{"t":"detriment","p":"Moon","z":"▼天性太温和,该亮的警告变成了软软的恳求,只好低声求人尊重。","e":"So soft by nature that a needed warning slips into a plea, begging for the respect it can't command."}]},"2":{"tz":"正当反击","te":"Justified Force","mz":"面对一再的越界,出手反击天经地义,该狠的时候就要狠。","me":"When others keep crossing the line, striking back is fully justified, firm when firmness is due.","pol":[{"t":"exalted","p":"Mars","z":"▲反应又快又猛,在现实里果断拒绝被侵犯,越彻底越管用。","e":"Reacts hard and fast, decisively shutting down interference; the more thorough, the more it works."},{"t":"detriment","p":"Neptune","z":"▼明明有理,却事后悔不该那么狠,自我对强硬总觉得不安。","e":"Right to act yet haunted by regret over the harshness, uneasy with its own severity."}]},"3":{"tz":"以弱抗强","te":"Outmatched","mz":"有理却撞上更强的对手,正面硬刚只是徒劳,得换条自己的路走。","me":"In the right but facing a far stronger force, where head-on resistance is futile and one must find their own path instead.","pol":[{"t":"exalted","p":"Neptune","z":"▲把失败当成能熬过去的羞辱,别用酒精麻醉,走自己的路才不被压垮。","e":"Takes defeat as a survivable humiliation; walk your own path rather than numb the sting."},{"t":"detriment","p":"Jupiter","z":"▼为护住自尊干脆全面退场,失去了在现实里打拼的斗志。","e":"Withdraws entirely to shield the ego, losing all drive to fight in the real world."}]},"4":{"tz":"知己知彼","te":"Reading the Field","mz":"出手前先冷静掂量双方实力,看准了再决定怎么回应。","me":"Sizing up both sides calmly before responding, choosing the right move only once the picture is clear.","pol":[{"t":"exalted","p":"Jupiter","z":"▲看得清局势就赢得漂亮,凭直觉把力气用在刀刃上。","e":"Clarity brings the win, instinct steering effort exactly where it counts."},{"t":"detriment","p":"Earth","z":"▼自觉占理就低估了对手,任性凭意气出手,丢了该有的直觉。","e":"Feeling righteous, underestimates the opponent, charging on ego instead of instinct."}]},"5":{"tz":"对事不对人","te":"Cool Judgment","mz":"动用力量要凭公正,不能被情绪牵着走,该客观时绝不偏私。","me":"Using force only by fair principle, never driven by emotion, staying impartial when it matters.","pol":[{"t":"exalted","p":"Jupiter","z":"▲讲原则守规矩,自我稳得住,把力量公正地用在该用的地方。","e":"Principled and lawful, a steady ego that wields its power with even-handed fairness."},{"t":"exalted","p":"Pluto","z":"▲清除的冲劲太强,只认目标不顾后果,力量用得过于主观。","e":"A drive to eliminate so fierce it fixates on the cause alone, wielding power subjectively, blind to consequence."}]},"6":{"tz":"乱中守心","te":"Holding On in Chaos","mz":"当行动失效、局面越来越乱,有人死磕到底,也有人退守内心。","me":"When action stops working and disorder grows, some grind on against all odds while others retreat inward.","pol":[{"t":"exalted","p":"Pluto","z":"▲打消耗战,哪怕越来越乱也坚持正当的行动,等待翻盘;脱节时反添混乱。","e":"A war of attrition, pressing on legitimately amid rising chaos; but out of touch, the force only breeds disorder."},{"t":"detriment","p":"Venus","z":"▼外界一团乱,索性抽身,把力量转向在自己心里建立秩序。","e":"When the world is chaos, withdraws and turns its power toward building order within."}]}},"22":{"1":{"tz":"安于其位","te":"The Right Seat","mz":"懂得安心待在配角位置,情绪上反而自在,不硬争主角。","me":"Someone at ease in a lesser role, finding emotional comfort instead of forcing the spotlight.","pol":[{"t":"exalted","p":"Moon","z":"▲坦然接受次要位置,情绪上还能享受这份从容,不必处处出头。","e":"Gracefully accepts a backseat role and even enjoys the calm that comes with it."},{"t":"exalted","p":"Mars","z":"▲想拿低票坐头等舱,情绪冲过头,场面上容易自讨没趣、当众难堪。","e":"Pushing past your station with raw drive invites the public embarrassment of overreach."}]},"2":{"tz":"风度学堂","te":"The School of Charm","mz":"相信用风格和姿态就能盖住本性,把好看当成本事。","me":"Someone who believes polished style can mask their true nature.","pol":[{"t":"exalted","p":"Sun","z":"▲能用迷人的情绪风格打动人,先把自己也说服了,魅力天成。","e":"Wins others over with an emotional style so convincing it persuades even yourself."},{"t":"detriment","p":"Jupiter","z":"▼把形式捧得比内涵还高,光顾着好看,觉知和实质都被掏空。","e":"Crowns form over substance, feeding the style while the awareness behind it withers."}]},"3":{"tz":"天生魅力","te":"The Natural Enchanter","mz":"情绪与觉知对齐,外在风度就是内在实质的真实流露。","me":"Someone whose grace is real because outer form and inner substance line up.","pol":[{"t":"exalted","p":"Saturn","z":"▲形式成为实质的定型与落地,情绪与觉知合一,开放臻于圆熟。","e":"Form gives substance its shape, aligning feeling and awareness into perfected openness."},{"t":"detriment","p":"Mars","z":"▼魅力全凭本能,自己说不清也守不住,开放只是天生的惯性。","e":"Charm runs on instinct alone—an innate openness you can neither explain nor steer."}]},"4":{"tz":"察言观色","te":"Reading the Room","mz":"懂得为对方微调自己的姿态,让每段互动都更顺、更暖。","me":"Someone who fine-tunes their manner to make each interaction warmer and smoother.","pol":[{"t":"exalted","p":"Neptune","z":"▲一种通灵般的朴素,丢掉繁文缛节,人际反而自然敞开。","e":"A mediumistic simplicity that drops the rituals and opens people up naturally."},{"t":"detriment","p":"Mars","z":"▼太迷信那套礼节套路,反把本可深交的关系生生掐断。","e":"Leaning too hard on the mechanics of formality can choke off relationships that mattered."}]},"5":{"tz":"直来直去","te":"Cutting Through","mz":"该破格时就破格,在更高的原则面前,礼数可以先放一边。","me":"Someone willing to drop the rules when a higher principle calls for it.","pol":[{"t":"exalted","p":"Jupiter","z":"▲凭着更高原则的底气,大方越过常规,情绪觉知让你敢做自己。","e":"Higher principle gives you the standing to break the codes and act as your own person."},{"t":"detriment","p":"Mars","z":"▼直性子常制造尴尬,事虽办成,却落个粗鲁无礼的名声,招人侧目。","e":"Your bluntness gets results but leaves a trail of awkwardness and a name for rudeness."}]},"6":{"tz":"历练成熟","te":"Seasoned Maturity","mz":"经历多了,外在与内在终于对上,自然长成可被信服的人。","me":"Someone whose years of experience finally align form with substance into real authority.","pol":[{"t":"exalted","p":"Sun","z":"▲历练让你长出自然而然的领导力与威信,不必张扬就让人信服。","e":"Experience matures into evident leadership and an authority others simply trust."},{"t":"detriment","p":"Mars","z":"▼成熟却走向不合群的路数,这份开放偏要以叛逆的姿态表达。","e":"That same maturity turns nonconformist, voicing its openness in defiantly off-key ways."}]}},"23":{"1":{"tz":"传道之口","te":"Spreading the Word","mz":"想用一套新认知去取代别人旧观念的人,语言有动摇人心的力量。","me":"One who tries to replace others' old values with a new way of seeing.","pol":[{"t":"exalted","p":"Jupiter","z":"▲洞见说得透彻,能撼动陈旧的共识,把人引向更大的好。","e":"An insight so clear it can unseat established values and serve a greater good."},{"t":"detriment","p":"Mars","z":"▼急着布道,本想带来光,出口却带来阴影与负作用。","e":"Eager preaching meant to bring light that instead casts darkness."}]},"2":{"tz":"守住自己","te":"Standing One's Ground","mz":"平时包容,可当生存或表达被威胁时,懂得收起忍让保护自己。","me":"Tolerant by nature, but ready to drop tolerance when survival is at stake.","pol":[{"t":"exalted","p":"Jupiter","z":"▲存续本能最清醒,该出手护住自己的表达时绝不犹豫。","e":"The instinct to preserve at its sharpest, defending one's voice without hesitation."},{"t":"detriment","p":"Moon","z":"▼面对敌意只想躲,挡一挡就满足,不愿真正捍卫立场。","e":"Content to merely fend off hostility rather than truly hold one's ground."}]},"3":{"tz":"自成一格","te":"Quietly Different","mz":"活出独特的自己,会招来注目甚至羡慕,但不会让人感到威胁。","me":"Living one's own way—drawing notice, yet without threatening anyone.","pol":[{"t":"exalted","p":"Sun","z":"▲活力与底气自然外露,引来欣赏,却不让旁人感到压迫。","e":"Vitality that draws admiration and maybe envy, but never alarm."},{"t":"detriment","p":"Pluto","z":"▼那股神秘古怪让人起疑,被当成异类而招来戒备。","e":"A strangeness that breeds suspicion and gets one cast as the freak."}]},"4":{"tz":"各自为政","te":"Going Separate Ways","mz":"把事情拆得很散,却看不见把它们重新拼合起来的可能。","me":"Splitting things apart without seeing any way to put them back together.","pol":[{"t":"exalted","p":"Sun","z":"▲认准自己的路就走到底,哪怕这份表达对集体毫无用处。","e":"Following one's own path fully, even when it offers nothing to the collective."},{"t":"detriment","p":"Earth","z":"▼陷入怀疑与孤立,谁都不信,把自己越活越孤单。","e":"Distrust and paranoia that wall one off into isolation and fear."}]},"5":{"tz":"为我所用","te":"Taking It In","mz":"踏实地接纳另一条路上的价值,把它消化成自己的东西。","me":"Practically accepting another path's values and making them one's own.","pol":[{"t":"exalted","p":"Jupiter","z":"▲在吸收中成长,再把独到的洞见回馈给群体,彼此都更丰盛。","e":"Growing by absorbing, then gifting one's insight back to the collective."},{"t":"detriment","p":"Moon","z":"▼为求被接纳和庇护才去迎合,从弱势位置低头吸收。","e":"Assimilating from a weaker spot, just to win acceptance and protection."}]},"6":{"tz":"融会贯通","te":"Bringing It Together","mz":"活成榜样,慢慢把各种差异调和、汇聚成一个有机的整体。","me":"A role model who gradually fuses diversity into one living whole.","pol":[{"t":"exalted","p":"Mars","z":"▲融合点燃能量,让它倍增,把零散的差异拢成统一的力量。","e":"Fusion that multiplies energy and pulls diversity into one strong whole."},{"t":"detriment","p":"Jupiter","z":"▼有原则却孤芳自赏,抱着差异不肯融入,表达渐渐枯萎。","e":"A principled retreat that clings to difference and lets expression wither."}]}},"24":{"1":{"tz":"回头补课者","te":"Filling the Gap","mz":"想通一件事前,你得先把过去没弄明白的部分补回来,反复回望才有新结论。","me":"Before a fresh idea can land, you must revisit and rework the unfinished thoughts of the past.","pol":[{"t":"exalted","p":"Sun","z":"▲带着信念回头梳理旧思路,认定走通了就值得,重整后迎来清晰的新想法。","e":"Faith carries you back to re-examine old thinking; once reworked, a clear new idea forms."},{"t":"detriment","p":"Neptune","z":"▼用幻想替自己的停滞找借口,反复纠缠过去,陷在不理性的回望里出不来。","e":"Fantasy excuses the standstill, pulling you into an irrational fixation on what is gone."}]},"2":{"tz":"灵光乍现","te":"Sudden Clarity","mz":"你能在安静独处时,忽然把复杂的事想通成一个清楚的概念,这是天生的本事。","me":"In quiet aloneness, you can suddenly crystallize a tangle of thoughts into one clear concept.","pol":[{"t":"exalted","p":"Moon","z":"▲自然顺应新局面,灵感来时不勉强,自发地把想法凝成清晰概念。","e":"You adapt naturally to new forms and let insight spontaneously shape itself into a clear concept."},{"t":"detriment","p":"Mars","z":"▼把这份天赋当成个人功劳,自负地以为想通全靠自己,忘了是水到渠成。","e":"Vanity claims the gift as personal achievement, forgetting clarity arrives on its own."}]},"3":{"tz":"戒瘾的人","te":"Breaking the Loop","mz":"旧习惯有股回头的吸力,你能感到那份诱惑,但也有可能一次次真正挣脱它。","me":"Old patterns pull you backward; you feel their lure, yet you can genuinely break free.","pol":[{"t":"exalted","p":"Venus","z":"▲虽然艰难,但你终能战胜那股往回拉的力,从不理性中真正走出来。","e":"Hard as it is, you ultimately triumph over the regression and rise out of irrationality."},{"t":"detriment","p":"Jupiter","z":"▼因为眼前过得还顺,就给旧瘾找台阶,让不理性披上成功的外衣继续存在。","e":"Because things still go well, addiction gets legitimized and irrationality keeps its mask on."}]},"4":{"tz":"独处的人","te":"Alone to Renew","mz":"你需要一个人待着,只有在安静独处里,想法才会真正沉淀、整理、焕然一新。","me":"You renew yourself in solitude; only when alone do your thoughts settle and come clear.","pol":[{"t":"exalted","p":"Saturn","z":"▲独处时守住自律与专注,把思路理清,孤独反而养出更清明的头脑。","e":"Discipline and focus in solitude refine your thinking; aloneness enriches clear thought."},{"t":"detriment","p":"Neptune","z":"▼一个人待久了,容易飘进自己编的幻境里,把空想当真,越想越偏。","e":"Left alone too long, you drift into a private fantasy and mistake illusion for truth."}]},"5":{"tz":"坦白认错","te":"Owning Mistakes","mz":"你有勇气承认过去做错了,一笔勾销重新开始,这份诚实给你腾出新的可能。","me":"You have the courage to admit past mistakes, wipe the slate clean, and open new room.","pol":[{"t":"exalted","p":"Moon","z":"▲像新月一样重新起步,理性地修正过往,清空之后路就重新打开了。","e":"Like a new moon you begin fresh; rational correction clears the way to new possibilities."},{"t":"detriment","p":"Mars","z":"▼把认错偷换成辩解,拼命淡化过去的失误,用一堆理由替错误开脱。","e":"Confession turns into justification, shrinking past mistakes behind a wall of reasons."}]},"6":{"tz":"听不见机会","te":"Opportunity Knocks","mz":"机会来敲门时,你可能没听见。投入到清晰的思考里,才认得出它的样子。","me":"Opportunity knocks, but you may not hear it; engaged thinking helps you recognize it.","pol":[{"t":"exalted","p":"Jupiter","z":"▲主动投入理清思路的过程,准备好了,机会一出现就能一眼认出。","e":"By consciously engaging the thought process, you stay ready to spot opportunity at a glance."},{"t":"detriment","p":"Pluto","z":"▼天生的多疑扭曲了判断,因为不信任而一次次错过本该属于你的机会。","e":"Innate suspicion distorts your focus and lets one opportunity after another slip past."}]}},"25":{"1":{"tz":"无私之心","te":"Acting Without Motive","mz":"做事不为回报,只因爱本身就值得;一颗纯净自我在挑战里安住。","me":"Acting purely for love itself, not reward; a pure Self that stays centered amid challenge.","pol":[{"t":"exalted","p":"Neptune","z":"▲与万物相连而行动,过程本身就是奖赏,挑战中反而更定。","e":"Action attuned to all things, its own reward; challenges deepen your center."},{"t":"detriment","p":"Mercury","z":"▼把无私挂在嘴上四处张扬,一遇考验自我就慌了神。","e":"Broadcasting your selflessness; the Self panics the moment it's tested."}]},"2":{"tz":"活在当下","te":"Living in the Now","mz":"心思全放在眼前真实发生的事上,不纠缠过去也不空想未来。","me":"Mind fully on what's real right now, not lost in past or what-ifs.","pol":[{"t":"exalted","p":"Mercury","z":"▲专注于「正在发生」而非「本可以」,心思因此变得清澈通透。","e":"Focusing on what is, not what could be; the mind grows clear and sharp."},{"t":"detriment","p":"Mars","z":"▼当下仍夹带私心和投射,纯净被自己的盘算悄悄染上。","e":"Devotion still tangled with private agendas; projection clouds the now."}]},"3":{"tz":"经得起败","te":"Weathering Defeat","mz":"明白用心去做也未必成功,跌倒了仍能不丢掉本心。","me":"Knowing sincere effort guarantees nothing, yet keeping your spirit through the fall.","pol":[{"t":"exalted","p":"Mars","z":"▲挫败和打击都打不垮你,精神依旧完整,本色不改。","e":"Failure and shock can't break you; spirit stays whole, nature intact."},{"t":"detriment","p":"Pluto","z":"▼一次重创就让人失了天真,极端时甚至走向自毁。","e":"One misfortune steals your innocence; at worst it spirals toward self-destruction."}]},"4":{"tz":"污泥之莲","te":"Innocence Unbroken","mz":"无论身处怎样的处境,真正的纯净都不会被环境改写。","me":"True innocence holds no matter the circumstances around you.","pol":[{"t":"exalted","p":"Venus","z":"▲烂泥堆里也能开出玫瑰,最坏的环境也守得住最高的本心。","e":"A rose blooming in the dump; highest principles held amid the worst."}]},"5":{"tz":"先养再战","te":"Healing First","mz":"当心力被耗尽,先安静下来疗愈自己,这是头等大事。","me":"When your vitality is drained, withdraw and heal first; that comes before all.","pol":[{"t":"exalted","p":"Venus","z":"▲读懂病痛背后的讯息,退一步静养,直到真正复原。","e":"Reading the meaning behind an affliction, withdrawing to heal until whole."},{"t":"detriment","p":"Jupiter","z":"▼把康复全寄托在别人身上,稍有不适就疑神疑鬼。","e":"Hypochondria; leaning entirely on others to be healed."}]},"6":{"tz":"行为揭底","te":"Unmasked by Action","mz":"嘴上再纯,做出来的事不对劲,假天真终会被戳穿。","me":"However innocent the words, off-key actions expose the false front.","pol":[{"t":"exalted","p":"Earth","z":"▲不合时宜的举动会被点出纠正,纯净也随之失守。","e":"Inappropriate action gets called out; innocence slips away with it."},{"t":"detriment","p":"Uranus","z":"▼一连串荒腔走板的折腾,自己拆穿了那层天真的假面。","e":"Relentless misfires whose own backfiring tears off the innocent mask."}]}},"26":{"1":{"tz":"见好就收","te":"Knowing When Enough Is Enough","mz":"懂得珍惜已到手的成果,不被遥不可及的幻想牵着走。","me":"Treasures what's already in hand instead of chasing far-fetched gains.","pol":[{"t":"exalted","p":"Neptune","z":"▲让成就化作美梦,带你越过眼前的局限,而不沉迷虚妄。","e":"Lets accomplishment fuel real dreams, rising above limits without illusion."},{"t":"detriment","p":"Mars","z":"▼把过往战绩当成冒进的通行证,永远不满足、硬要赌一把。","e":"Treats past wins as a license for reckless bets, never satisfied."}]},"2":{"tz":"以史为镜","te":"Learning from the Past","mz":"沉下心从经验里取经,让走过的路点亮要去的方向。","me":"Draws on experience so the past illuminates the road ahead.","pol":[{"t":"exalted","p":"Sun","z":"▲有定力回望过往、消化教训,让自我在经验中真正成熟。","e":"Reflects deeply on history and matures through lived experience."},{"t":"detriment","p":"Pluto","z":"▼明明前车有鉴还是冲动行事,不肯把经验放在眼里。","e":"Charges ahead despite clear lessons, refusing to honor experience."}]},"3":{"tz":"号召人心","te":"Rallying Support","mz":"天生有凝聚力,准备好了就能把众人的力气拢到一处。","me":"A natural at gathering people and focusing their effort once ready.","pol":[{"t":"exalted","p":"Sun","z":"▲有那份分量把大家的劲头汇成一股,带着众人往一处使。","e":"Carries the weight to focus collective effort and draw support."},{"t":"detriment","p":"Saturn","z":"▼一心拉队伍,却低估了路上的阻力,看不清他人的难处。","e":"Rallies people but underrates the hurdles and others' resistance."}]},"4":{"tz":"取舍记忆","te":"Curating the Story","mz":"懂得删减取舍,只留下该被记住的,帮集体卸下包袱。","me":"Edits what's kept, lightening the collective by letting some go.","pol":[{"t":"exalted","p":"Pluto","z":"▲适时筛掉沉重的旧账,让群体不被自己的过去拖垮。","e":"Filters out heavy baggage so the group isn't dragged by its past."},{"t":"detriment","p":"Saturn","z":"▼只挑对自己有利的来记,怕失控而捂住真相、守着旧局。","e":"Remembers selectively to guard the status quo out of fear."}]},"5":{"tz":"随机应变","te":"Adapting to Change","mz":"摸透事情的脉络,把力气用在刀刃上,把潜力发挥到极致。","me":"Reads how things work and applies energy where it counts most.","pol":[{"t":"exalted","p":"Mars","z":"▲看懂运作的门道,精准发力榨出最大潜能,自然吸引人靠近。","e":"Grasps the mechanics, channels energy to peak, and draws others in."},{"t":"detriment","p":"Venus","z":"▼该从根上改变时却抗拒、心里别扭,死活不肯松手调整。","e":"Resists and chafes when real change is needed, refusing to adapt."}]},"6":{"tz":"言行立威","te":"Earning Authority","mz":"靠一次次做对事赢得分量,影响力是时间替你盖的章。","me":"Earns lasting influence by doing right, proven over time.","pol":[{"t":"exalted","p":"Sun","z":"▲把道理和分寸活成自己,经得起岁月检验,影响因正确而立。","e":"Embodies reason and purpose that stand the test of time."},{"t":"detriment","p":"Moon","z":"▼空有权威的名头,像个象征性的君主,有威仪却无实权。","e":"Holds authority as a symbol only—a figurehead without real power."}]}},"27":{"1":{"tz":"先顾好自己","te":"Caring for Yourself First","mz":"懂得先照顾好自己,才有余力照顾别人,这并非自私。","me":"Tending to yourself first so you have something left to give—not at others' expense.","pol":[{"t":"exalted","p":"Sun","z":"▲先把自己养好,自爱不亏欠任何人,稳稳供应他人。","e":"Filling your own cup first; healthy self-care that takes nothing from anyone."},{"t":"detriment","p":"Earth","z":"▼盯着别人有什么而生嫉妒,反而招来麻烦与匮乏。","e":"Eyeing what others have, letting envy breed misfortune and lack."}]},"2":{"tz":"先有再给","te":"Give From Fullness","mz":"想给予,先得拥有;先把自己装满,才能真正滋养人。","me":"To give, you must first have—nourish yourself full before nourishing others.","pol":[{"t":"exalted","p":"Moon","z":"▲像母亲般的滋养力,温柔而充足,养人也养己。","e":"A mother's nourishing strength—gentle, abundant, feeding self and others."},{"t":"detriment","p":"Mars","z":"▼像长不大的孩子,只会消耗别人,把人榨干。","e":"The dependent child who drains others dry instead of growing self-sufficient."}]},"3":{"tz":"贪得无厌","te":"Never Enough","mz":"明明够了还想要更多,被'占有'的执念牵着走的人。","me":"Driven to grab far more than you need, hooked on the craving to have.","pol":[{"t":"exalted","p":"Pluto","z":"▲想掌握隐秘、想拥有更多——这股渴求可化为深层力量。","e":"The hunger to uncover hidden things and have more—channeled into deep power."},{"t":"detriment","p":"Mars","z":"▼对权力与占有的贪欲,最终困住自己、上了瘾。","e":"Raw lust for power and possession that cripples and addicts you."}]},"4":{"tz":"慷慨分享","te":"Sharing the Abundance","mz":"手里有了富余,自然而然地分给别人,不计较。","me":"Naturally sharing the abundance you've gathered, freely and without grudge.","pol":[{"t":"exalted","p":"Uranus","z":"▲把好东西给配得上的人,大方而有眼光的分享。","e":"Magnanimous, discerning giving—rewarding those who truly deserve it."},{"t":"detriment","p":"Mars","z":"▼不分对象地乱给,反而散尽了自己的力量与资源。","e":"Giving indiscriminately to anyone, bleeding away your own strength."}]},"5":{"tz":"分配能手","te":"The Distributor","mz":"擅长把别人的资源调度好、发到对的地方的人。","me":"Skilled at managing others' resources and getting them where they're needed.","pol":[{"t":"exalted","p":"Jupiter","z":"▲有原则的分配高手,自己上手或懂得找对的人来做。","e":"A principled distributor—or the wisdom to find the right one to do it."},{"t":"detriment","p":"Saturn","z":"▼太多限制与顾虑,既不肯分也不肯求助,卡住了。","e":"An over-restrictive nature that blocks distribution and refuses to ask for help."}]},"6":{"tz":"留个心眼","te":"Caring With Caution","mz":"凭直觉看清自己能给多少,不让好心被人占便宜。","me":"Sensing how much you can truly give, guarding generosity from being abused.","pol":[{"t":"exalted","p":"Moon","z":"▲凭感觉与直觉量力而行,务实地照顾,不勉强。","e":"Nurturing realistically, guided by feeling and instinct about your true capacity."},{"t":"detriment","p":"Pluto","z":"▼疑心太重,处处提防,反而把关心都堵死了。","e":"Over-suspicion that walls everyone off and chokes the care you could give."}]}},"28":{"1":{"tz":"下足功夫","te":"Doing the Groundwork","mz":"想让冒险有意义,先得把准备做扎实——把热情落到每个细节上。","me":"Wanting the gamble to mean something, you first ground it in solid, detailed preparation.","pol":[{"t":"exalted","p":"Mars","z":"▲把想做成事的冲劲,稳稳投进每个细节,直觉知道劲该使在哪。","e":"Drive channeled into detail; instinct for exactly where the energy belongs."},{"t":"detriment","p":"Venus","z":"▼爱上漂亮的计划本身,却落不了地,精致全停在纸面上。","e":"In love with elegant plans that never get built; refinement with no follow-through."}]},"2":{"tz":"妥协结盟","te":"Bargain with the Dark","mz":"为了赢下这一局,有时不得不接受自己不喜欢的盟友。","me":"To win the round, you sometimes accept an ally you'd rather not.","pol":[{"t":"exalted","p":"Sun","z":"▲当局面变成苦战,直觉接受任何能取胜的联手,结果替手段正名。","e":"When it turns to a hard fight, you instinctively take any alliance that wins."},{"t":"detriment","p":"Mercury","z":"▼放下原则却没有胜算的保证,这份不安一直在心里啃。","e":"The unease of trading away principles with no guarantee the gamble pays off."}]},"3":{"tz":"莽撞下注","te":"Reckless Bets","mz":"在挣扎里,有人凭运气乱赌——分清这是勇敢还是给冲动找借口。","me":"In the struggle, some bet blind; the trick is telling courage from rationalized impulse.","pol":[{"t":"exalted","p":"Saturn","z":"▲哪怕在冒险时刻,骨子里也有份稳,直觉懂得苦战中何时收手。","e":"Even amid risk, a built-in prudence; instinct for caution when the fight is on."},{"t":"detriment","p":"Jupiter","z":"▼把鲁莽的赌注说得头头是道,理由越漂亮,失败越注定。","e":"Risk dressed up in fine reasoning—the better the excuse, the surer the fall."}]},"4":{"tz":"咬牙坚守","te":"Holding the Grip","mz":"认准了就不松手,这份韧劲能成全大局,也可能困住自己。","me":"Once committed you won't let go—a grip that can serve the whole or trap you.","pol":[{"t":"exalted","p":"Jupiter","z":"▲用见识抓住机会,这份深直觉在苦战里最亮,常能惠及他人。","e":"Knowledge seizing opportunity; deep intuition at its best in struggle, useful to others."},{"t":"detriment","p":"Mercury","z":"▼只为自己死死攥着,聪明全用在了固执的私心上。","e":"Clinging purely for self-interest; cleverness spent on stubborn, selfish holding."}]},"5":{"tz":"背信弃盟","te":"Breaking Faith","mz":"在斗局里看准时机搅动各方,这份本事既能左右全局也会辜负信任。","me":"Reading the moment to stir the factions—a gift that can sway the whole or betray trust.","pol":[{"t":"exalted","p":"Pluto","z":"▲不偏帮任何一方,却挑动各方互斗,直觉点燃别人之间的角力。","e":"Backing no side yet setting them against each other; instinct to provoke the struggle."},{"t":"detriment","p":"Sun","z":"▼直觉知道该弃旧盟投强者,虽撼动全局,却也是必要的取舍。","e":"Knowing when to drop allies for stronger forces, destabilizing all in the process."}]},"6":{"tz":"燃尽一搏","te":"Going Down Blazing","mz":"宁可拼到最后一刻,也不甘心向衰败低头——为活出意义而豁出去。","me":"You'd rather burn out fighting than surrender to decline—staking all for meaning.","pol":[{"t":"exalted","p":"Pluto","z":"▲无论代价多大都要重生,那股要赢的深层直觉,把绝境烧成新生。","e":"Renewal at any price; the deep instinct to win that turns dead ends into rebirth."},{"t":"detriment","p":"Neptune","z":"▼怕输怕到深处,在苦战里滑向自我毁灭与彻底的绝望。","e":"Fear of defeat sunk deep; in struggle it slides toward self-destruction and despair."}]}},"29":{"1":{"tz":"应召上场","te":"Answering the Call","mz":"在该投入时全力以赴,但深知苦战只是一程,不是常态。","me":"Able to dig in and endure when the moment demands it, knowing hardship is a phase, not a way of life.","pol":[{"t":"exalted","p":"Mars","z":"▲战时能拼、平时能歇;该坚持时使尽全力,过后自然松手。","e":"Throws full energy into the fight when needed, then steps back when peace returns—perseverance on demand, not by default."},{"t":"detriment","p":"Neptune","z":"▼旧伤刻得太深,难以回到平常,凡事先犹豫怕重蹈覆辙。","e":"Old wounds run so deep that returning to normal feels hard; past pain breeds hesitation before any commitment."}]},"2":{"tz":"掂量再点头","te":"Weighing the Yes","mz":"有持久的耐力,但会先看清值不值得,不轻易把自己耗进去。","me":"Real staying power, but paired with the wisdom to check whether the effort is worth it before pouring in.","pol":[{"t":"exalted","p":"Sun","z":"▲像一盏稳定的灯,真心点头后就能撑住,把事走到底。","e":"A steady inner light: once a true yes is given, the energy holds and carries things through."},{"t":"detriment","p":"Venus","z":"▼当坚持反而把局面搅乱时,会过度小心,迟迟不敢应承。","e":"When pushing on only deepens the discord, over-caution sets in and the yes never comes."}]},"3":{"tz":"懂得按兵","te":"Knowing When to Hold","mz":"明知不动有代价,仍能忍住冲动,留着力气改日再战。","me":"Aware that holding back has a cost, yet able to wait and save strength for a better day.","pol":[{"t":"exalted","p":"Mars","z":"▲手再痒也压得住,清楚有时退一步是为了走更远。","e":"However strong the urge, restrains it—knowing it's sometimes wiser to live to fight another day."},{"t":"detriment","p":"Jupiter","z":"▼凡事先想抽身,不管后果,结果什么都不敢承诺。","e":"Reflexively pulls away on principle, ignoring the fallout, until no commitment can be made at all."}]},"4":{"tz":"直来直去","te":"The Straight Line","mz":"面对难题不绕弯,用最简单最直接的方式一刀切到点上。","me":"Faced with difficulty, skips the detours and goes straight to the heart of it in the simplest way.","pol":[{"t":"exalted","p":"Saturn","z":"▲有把复杂化简的智慧,认准最短那条路就一头扎进去。","e":"The wisdom to strip a problem down and commit to the most direct route through it."},{"t":"detriment","p":"Venus","z":"▼太过直白常被嫌生硬不讨喜,一句话就得罪了人。","e":"Bluntness often reads as crude or graceless, and the directness ends up offending others."}]},"5":{"tz":"揽得太多","te":"Biting Off Too Much","mz":"容易一口答应太多,超出自己能扛的,后劲跟不上。","me":"Prone to saying yes to more than can be handled, overreaching past what the resources allow.","pol":[{"t":"exalted","p":"Sun","z":"▲那股冲劲来自天性而非野心,身体自己就想说好。","e":"The drive flows from design, not ambition—an irrepressible pull to say yes."},{"t":"detriment","p":"Earth","z":"▼答应了却把力气透支光,半途撑不住,雄心落了空。","e":"Says yes, burns through every resource, then can't hold on—ambition collapses unfinished."}]},"6":{"tz":"冲过了头","te":"Outrunning Awareness","mz":"势头跑得比清醒还快,人已陷在迷糊里却还在硬冲。","me":"Momentum races ahead of clarity, leaving one charging on while lost in the fog.","pol":[{"t":"exalted","p":"Mars","z":"▲蒙着头往前冲,靠着那股劲与决心,常莫名其妙撞上好运。","e":"Plows ahead blind, and with sheer Mars drive often stumbles into dumb luck—perseverance that makes no sense yet works."},{"t":"detriment","p":"Jupiter","z":"▼一乱就想退缩,而不是接住混乱继续走,凡事先求保险。","e":"At the first sign of confusion, withdraws instead of riding it out—choosing caution over a yes."}]}},"30":{"1":{"tz":"乱中守静","te":"Steady in Chaos","mz":"外界再翻涌,你都能让情绪有个落脚点,不被卷走。","me":"No matter how disorderly things get, your feelings find footing instead of scattering.","pol":[{"t":"exalted","p":"Sun","z":"▲扬升:认清局限反而稳得住,情绪有锚,风浪里也不慌。","e":"Exalted: you accept the limits and stay anchored, calm through every storm."},{"t":"detriment","p":"Jupiter","z":"▼落陷:表面镇定,却抓着情绪不放,稳是稳了,人也卡住了。","e":"Detriment: composed on the surface but clinging to feelings, stable yet unable to move on."}]},"2":{"tz":"不耗心力","te":"No Wasted Heat","mz":"懂得把劲用在刀刃上,不在情绪内耗里空转。","me":"You spend energy where it counts and refuse to burn it on emotional spinning.","pol":[{"t":"exalted","p":"Sun","z":"▲扬升:能量精准落地,不在感受上空烧,做事干净利落。","e":"Exalted: energy lands precisely, none wasted on feelings, action stays clean."},{"t":"detriment","p":"Mars","z":"▼落陷:情绪太冲,硬碰局限,徒耗气力还磨自己。","e":"Detriment: feelings too aggressive, ramming against limits, draining yourself for nothing."}]},"3":{"tz":"顺其自然","te":"Accepting What Is","mz":"试错够多后,学会接纳已成定局,不再硬扛。","me":"After enough trial and error, you learn to accept what is rather than fight it.","pol":[{"t":"exalted","p":"Pluto","z":"▲扬升:看懂万物循环更替,以平静之心接住眼前的一切。","e":"Exalted: you grasp the cycle of renewal and accept what is with a settled heart."},{"t":"detriment","p":"Jupiter","z":"▼落陷:懂得越多越摇摆,接纳里夹着或喜或悲的起伏。","e":"Detriment: more knowing brings more wavering, acceptance laced with swinging moods."}]},"4":{"tz":"燃尽边缘","te":"On the Edge of Burnout","mz":"节奏快到不真实,情绪绷得太满,容易一口气泄掉。","me":"A pace too unreal to sustain, feelings stretched so tight they risk collapse.","pol":[{"t":"exalted","p":"Pluto","z":"▲扬升:即便高速狂奔像要烧尽,靠自省也能稳稳收住。","e":"Exalted: even racing on the edge of burnout, self-reflection pulls you back."},{"t":"detriment","p":"Jupiter","z":"▼落陷:无节制地膨胀,情绪憋到极限,终究啪地崩开。","e":"Detriment: unchecked expansion swells the bubble until feelings burst out loud."}]},"5":{"tz":"进退之间","te":"Two Steps, One Back","mz":"每段新感受都唤回旧情绪,看似反复,其实仍在向前。","me":"Each new feeling stirs up an old one, looping yet still inching forward.","pol":[{"t":"exalted","p":"Jupiter","z":"▲扬升:明白退一步也是路,经验让你在反复中照样前进。","e":"Exalted: you know a step back still moves you on, progressing through the loops."},{"t":"detriment","p":"Pluto","z":"▼落陷:旧情绪一回来就上火,烦躁到只想砍断整个过程。","e":"Detriment: old feelings return and spark anger, frustrated enough to scrap it all."}]},"6":{"tz":"正气清场","te":"Clearing the Way","mz":"以身作则的高度,有底气清掉负面情绪、扶起弱者。","me":"From a role-model's height, you have the discipline to clear negativity and lift the weak.","pol":[{"t":"exalted","p":"Mars","z":"▲扬升:果断扫除负面情绪,又愿意俯身带领弱小同行。","e":"Exalted: you firmly purge negative feelings while choosing to lead the weak."},{"t":"detriment","p":"Moon","z":"▼落陷:天性太温和,常容忍劣质能量赖着,下不了清场的手。","e":"Detriment: too peaceful by nature, tolerating inferior forces, unable to clear them out."}]}},"31":{"1":{"tz":"天生引路","te":"Born to Lead","mz":"影响力得有人接住。你只要真诚地站出来,人们自然愿意跟随。","me":"Influence needs an audience; lead by simply showing up.","pol":[{"t":"exalted","p":"Sun","z":"▲像太阳一样不藏光,自然而然地照亮和带动周围的人。","e":"Like the sun, you shine without holding back and others rise."},{"t":"detriment","p":"Earth","z":"▼把光都收起来,只会许诺却不显化,带领变得勉强又不自然。","e":"Light withheld; all promise, no manifestation—leadership feels forced."}]},"2":{"tz":"等不及了","te":"Can't Wait","mz":"认准了原则就先做,不等所有人点头。冲在前面也可能踩空。","me":"Acts on principle before consensus arrives—bold, sometimes premature.","pol":[{"t":"exalted","p":"Jupiter","z":"▲为更高的信念挺身而出,不必等大家投票,直接领着走。","e":"Stands for higher principles without waiting for a vote to lead."},{"t":"detriment","p":"Mercury","z":"▼一紧张就抢跑,急着发声却常常落空,反而失了带领的资格。","e":"Nervy haste jumps the gun, misfires, and forfeits the lead."}]},"3":{"tz":"挑对圈子","te":"Choosing Wisely","mz":"和谁同行很重要。会挑环境的人,带领力也跟着水涨船高。","me":"Who you align with shapes how far your influence reaches.","pol":[{"t":"exalted","p":"Sun","z":"▲懂得衡量该靠近谁、远离谁,借对的人事把自己越带越高。","e":"Weighs which company to keep, and rises by allying with the right ones."},{"t":"detriment","p":"Jupiter","z":"▼热情上头来者不拒,什么追随者都收,最后可能换来难堪。","e":"Runaway zeal accepts any follower and courts humiliation."}]},"4":{"tz":"别人怎么看","te":"How It Lands","mz":"你的影响成不成,要看别人怎么接收。被看见的方式决定一切。","me":"Your influence succeeds or fails by how others perceive it.","pol":[{"t":"exalted","p":"Moon","z":"▲那份照顾和守护被大家看见认可,带领自然得到外界的掌声。","e":"A nurturing, protective influence wins public recognition to lead."},{"t":"detriment","p":"Mars","z":"▼一旦被看成自我膨胀或操控,带领的努力就被外界泼了冷水。","e":"Read as ego or manipulation, the urge to lead gets shut down."}]},"5":{"tz":"先管好自己","te":"Lead Yourself","mz":"在独处里磨出独门本事,却未必想去影响别人,先把自己活明白。","me":"Mastery grown in solitude, content to lead only oneself.","pol":[{"t":"exalted","p":"Pluto","z":"▲独处中练成的真功夫,圆满后却极难外传,先做好自己的领袖。","e":"A specialty forged alone, hard to share—first, lead yourself."},{"t":"detriment","p":"Moon","z":"▼一头扎进自己的体验里,没有向外的野心,只想顾好自己。","e":"Deep in private experience, no outward ambition beyond the self."}]},"6":{"tz":"说到做到","te":"Walk the Talk","mz":"话和行动得对得上。言行合一的人,带领才让人信服。","me":"Words and deeds must match; aligned action makes leadership real.","pol":[{"t":"exalted","p":"Sun","z":"▲说出口的话和做出的事完全一致,这份言行合一保证了成功。","e":"Words and actions are one and the same—and that guarantees success."},{"t":"detriment","p":"Moon","z":"▼嘴上一套做的另一套,这种近乎虚伪的浮夸,自然没人买账。","e":"Talk without action borders on hypocrisy—and is treated as such."}]}},"32":{"1":{"tz":"守住根基","te":"Conservation","mz":"懂得对一件事的每个环节都用心,靠长期投入把直觉养成深功夫。","me":"Building lasting instinct by honoring every step of a process.","pol":[{"t":"exalted","p":"Sun","z":"▲对过程的每个细节都保持敬意与专注,熬出真正的本能。","e":"Patient attention to every detail grows reliable instinct."},{"t":"exalted","p":"Mars","z":"▲忍不住跳过关键步骤,怕白忙一场,反而打断了延续。","e":"Rushing past essentials out of fear, breaking the thread."}]},"2":{"tz":"克制有度","te":"Restraint","mz":"天赋在于懂得收着用力,把力量用在让大家都更好的地方。","me":"A gift for restraining power so it serves the good of all.","pol":[{"t":"exalted","p":"Venus","z":"▲收着力气、为和谐而用,带来对众人有益的转变。","e":"Power held gently, transforming things for everyone's benefit."},{"t":"detriment","p":"Jupiter","z":"▼在强势位却受挫时,宁可一走了之,也不愿耐心坚持。","e":"Frustrated even from strength, retreating instead of holding on."}]},"3":{"tz":"续不下去","te":"Break in Continuity","mz":"总在反复掂量、迟迟不定,全靠脑子聪明才勉强撑住。","me":"Endless re-weighing that only sheer intelligence keeps afloat.","pol":[{"t":"exalted","p":"Mercury","z":"▲犹豫不决、反复评估,靠基本的聪明硬是把局面撑住。","e":"Indecision saved only by underlying cleverness in flux."},{"t":"detriment","p":"Jupiter","z":"▼太依赖老规矩,时代一变就彻底脱节,猝不及防地丢脸。","e":"Clinging to old norms until change brings sudden humiliation."}]},"4":{"tz":"正即是力","te":"Right Is Might","mz":"再怎么变,心里那条底线原则始终不动,这本身就是力量。","me":"Some core principles hold firm no matter how times change.","pol":[{"t":"exalted","p":"Jupiter","z":"▲风云再变,底层的对错原则仍在,本能守住正道。","e":"Even amid change, certain principles endure and guide you."},{"t":"detriment","p":"Saturn","z":"▼只要安全感没被威胁就坚守,一旦受威胁原则就松动。","e":"Holding principles only while one's security feels safe."}]},"5":{"tz":"随势而变","te":"Flexibility","mz":"懂得顺着环境调整自己,看似圆滑,其实是过关的智慧。","me":"An instinct to adapt smoothly to whatever circumstances bring.","pol":[{"t":"exalted","p":"Moon","z":"▲表面随和是好工具,藏住内光,顺势调整熬过变局。","e":"Surface ease masks inner light and adapts to conditions."},{"t":"detriment","p":"Mars","z":"▼一股冲动要表达自己,甚至激烈地拒绝随大流。","e":"An urge to reject conformity, sometimes harshly and loudly."}]},"6":{"tz":"坦然面对","te":"Tranquillity","mz":"在无常面前能静下心,从骨子里接受变化的人。","me":"Meeting impermanence calmly, accepting change at the core.","pol":[{"t":"exalted","p":"Pluto","z":"▲打心底接受变化,这份接纳或许能带来真正的平静。","e":"Deep acceptance of change that may ripen into peace."},{"t":"detriment","p":"Neptune","z":"▼把无常当成一切无意义的证据,陷入消沉甚至自毁。","e":"Reading impermanence as meaninglessness, sliding into despair."}]}},"33":{"1":{"tz":"知难即退","te":"Knowing When to Step Back","mz":"看清自己处于弱势,就果断抽身,不硬拼。退,是一种清醒。","me":"Seeing you're in a weak spot and pulling back in time, instead of forcing it.","pol":[{"t":"exalted","p":"Sun","z":"▲扬升:认清当下扛不住,主动退一步保全自己,是大智慧。","e":"Recognizing the moment is too much to win, and wisely choosing to withdraw."},{"t":"detriment","p":"Mars","z":"▼落陷:被刺激冲昏头,该退不退,把蛮勇当勇气,硬扛到底。","e":"Overstimulated and unable to retreat, mistaking reckless bravado for courage."}]},"2":{"tz":"顺势蓄力","te":"Yielding to Build Strength","mz":"面对更强的力量先低头不是认输,而是借势养力,为日后翻盘打底。","me":"Bowing to a stronger force isn't defeat—it's banking strength for a later win.","pol":[{"t":"exalted","p":"Jupiter","z":"▲扬升:把臣服当机会,借强者之势壮大自己,慢慢攒出胜局。","e":"Treating surrender as an opening, using greater forces to grow toward eventual triumph."},{"t":"detriment","p":"Neptune","z":"▼落陷:表面归顺心里不服,觉得自己原本就是错的,谁强谁有理。","e":"Publicly bowing while privately resenting it, feeling one's own stance was a delusion."}]},"3":{"tz":"退而不弃","te":"Retreat With Resolve","mz":"退守是为了守住根本,但心里那股劲没断,迟早还要回来。","me":"Pulling back to protect what matters, while keeping the will to carry on.","pol":[{"t":"exalted","p":"Jupiter","z":"▲扬升:有原则地退守,守住底线也守住决心,把独处走成出路。","e":"A principled retreat that preserves the core, with the resolve to persevere."},{"t":"detriment","p":"Mars","z":"▼落陷:为了清静一刀切断关系,说走就走,身后桥全烧光。","e":"Retreating without care, cutting off ties abruptly and burning every bridge."}]},"4":{"tz":"体面的退","te":"A Graceful Retreat","mz":"退下来时心里安稳,不慌不乱,把退守当成喘息和重整的时机。","me":"Stepping back without turmoil, treating retreat as a calm chance to regroup.","pol":[{"t":"exalted","p":"Pluto","z":"▲扬升:相信退一步能重生,把抽身当成休养与更新的好时候。","e":"Trusting in renewal, turning retreat into a healthy chance to regenerate."},{"t":"detriment","p":"Neptune","z":"▼落陷:被迫退守又看不到转机,只觉一切在崩塌,越退越散。","e":"Forced to retreat yet blind to its renewal, sliding into dissolution and decay."}]},"5":{"tz":"藏好时机","te":"Keeping the Right Timing","mz":"等对的时机出手,更要在那之前把意图藏好,不动声色。","me":"Waiting for the right moment—and keeping your intentions hidden until it comes.","pol":[{"t":"exalted","p":"Pluto","z":"▲扬升:沉得住气,把计划捂到火候正好那一刻才亮出来。","e":"Holding one's plan in secret until exactly the right moment to act."},{"t":"detriment","p":"Jupiter","z":"▼落陷:拉着别人一起定时机,过早透了底,反把局面搅乱。","e":"Letting others in on the timing too soon, spilling the secret and causing confusion."}]},"6":{"tz":"放得下手","te":"Letting It Go","mz":"退下来后能真正放下,不揪着旧账不放,安心享受独处养精神。","me":"Truly letting go in retreat—no clinging to old grievances, just restful privacy.","pol":[{"t":"exalted","p":"Sun","z":"▲扬升:专心养回元气,不被翻旧账拖累,在独处里舒坦自在。","e":"Focusing on revitalization, free of old recriminations, enjoying the quiet."},{"t":"detriment","p":"Jupiter","z":"▼落陷:退是退了,心却没放干净,残留的疑虑一直拖着恢复。","e":"Unable to fully let go, lingering doubts that keep getting in the way of recovery."}]}},"34":{"1":{"tz":"莽撞用力","te":"Force Without Aim","mz":"有力气却不分场合地往外冲,用蛮力回应憋屈,容易撞墙。","me":"Raw power used indiscriminately, often as a reaction to frustration.","pol":[{"t":"exalted","p":"Saturn","z":"▲被堵住时不憋着,把这股劲化成行动力推出去,有节制地发力。","e":"Channels frustration into purposeful, measured action rather than blind aggression."},{"t":"detriment","p":"Pluto","z":"▼一味逞强压人,迟早招来反弹,被同样的力道顶回来。","e":"Bullish shows of force invite the backlash they were always destined to provoke."}]},"2":{"tz":"乘势而上","te":"Riding the Surge","mz":"胜利在望时力量自然涌出来,关键是别被兴奋冲昏头、稳住节奏。","me":"Power swells as victory nears; the skill is keeping your head clear.","pol":[{"t":"exalted","p":"Mars","z":"▲眼看要赢仍不飘,守住全局视野,让势头稳稳积累。","e":"Sees victory coming yet keeps perspective, letting momentum build steadily."},{"t":"detriment","p":"Venus","z":"▼被胜利的味道勾着情绪走,急着收尾,反而把成长卡住。","e":"Swept up by the scent of victory, impatience caps the very growth it craves."}]},"3":{"tz":"硬气示人","te":"Show of Strength","mz":"靠展示力量来撑起自己的角色,是真有底气还是装腔,差别很大。","me":"Displaying power to define one's role—genuine backing versus posturing.","pol":[{"t":"exalted","p":"Saturn","z":"▲那份硬气是天生的、有实力托底的,不做作,自然立住角色。","e":"Strength that's innate and genuinely backed, defining the role without pretense."},{"t":"detriment","p":"Mercury","z":"▼把示强变成精算的表演,甚至放假消息,靠话术撑场面。","e":"A calculated performance of power, even spreading disinformation, to prop up the role."}]},"4":{"tz":"胜后收力","te":"Power After Victory","mz":"大胜之后可以为所欲为,真正的成熟是把力量收着用,不滥用。","me":"Absolute victory frees unlimited power; maturity lies in restraint.","pol":[{"t":"exalted","p":"Pluto","z":"▲赢了之后反而收敛锋芒,改走低调含蓄的路,自信不必张扬。","e":"In victory, restrains excess for subtler styles—confidence that needn't announce itself."},{"t":"detriment","p":"Mars","z":"▼贪图爽快,毫无顾忌地动用力量,缺乏底气却终致滥用。","e":"Ego craving gratification wields power unchecked, and that insecurity slides into abuse."}]},"5":{"tz":"彻底清场","te":"Clearing All Resistance","mz":"有把阻力一次扫平的力量,难的是用完之后能放下、转回平常。","me":"The power to eliminate all resistance—and to set it down afterward.","pol":[{"t":"exalted","p":"Mars","z":"▲该出手时彻底解决,事成之后能把这股力量转去做正经事。","e":"Destroys resistance completely, then redirects the power toward normal use."},{"t":"detriment","p":"Moon","z":"▼像月相循环,总觉得没什么是真清得掉,改不掉戒备的旧惯性。","e":"Like the moon's phases, feels nothing is ever truly gone—stuck in old defensive patterns."}]},"6":{"tz":"适可而止","te":"Knowing When Enough","mz":"懂得见好就收、量力而行,扛不动的就放下一些,这是真智慧。","me":"Common sense to know when enough is enough and not overreach.","pol":[{"t":"exalted","p":"Earth","z":"▲咬得太多嚼不烂时,有分寸地吐出一部分,力不够就不硬撑。","e":"When you've bitten off too much, the good sense to spit some out and not overextend."},{"t":"detriment","p":"Jupiter","z":"▼热情盖过判断,什么都想揽,结果把自己的力气耗空、添乱。","e":"Enthusiasm overriding judgment, taking on everything until your strength is drained."}]}},"35":{"1":{"tz":"能放下的人","te":"Letting Rejection Pass","mz":"能把拒绝和挫败当成路上的一段，而不是对自己的否定。","me":"Able to take rejection as part of the road, not a verdict on your worth.","pol":[{"t":"exalted","p":"Venus","z":"▲被拒了也不慌,把它看成创作的一环,继续往前。","e":"Treats being turned down as part of making things, and keeps going."},{"t":"detriment","p":"Neptune","z":"▼一被拒就觉得自己一文不值,把改变当成羞辱。","e":"A single no collapses your worth; change feels like humiliation."}]},"2":{"tz":"灵感会来去","te":"When the Spark Stalls","mz":"灵感不来时,懂得停一停,不硬挤、不慌乱,等它自己回来。","me":"When inspiration dries up, knowing how to wait instead of forcing it.","pol":[{"t":"exalted","p":"Venus","z":"▲明白创造力像潮水有涨有落,枯竭时安心等它回流。","e":"Knows creativity ebbs and flows, and rests easy when it's low."},{"t":"detriment","p":"Moon","z":"▼受不了空白,随便找点事做,瞎忙却推不动真进展。","e":"Can't bear the void, so busies yourself with empty motion that goes nowhere."}]},"3":{"tz":"成事在众","te":"Better Together","mz":"懂得拉上别人一起走,合力造出的进步,远大于一个人。","me":"Knows progress made together far outgrows what one person can push alone.","pol":[{"t":"exalted","p":"Jupiter","z":"▲乐于托举身边人,把进步带进别人的生活里。","e":"Lifts others up and carries real change into their lives."},{"t":"detriment","p":"Sun","z":"▼非要当主角,只盯着自己,看不见别人也在出力。","e":"Insists on being the center and overlooks everyone else's part."}]},"4":{"tz":"永不满足","te":"Hungry for More","mz":"对新鲜与进步有用不完的胃口,总想往前再迈一步。","me":"An appetite for the new and the next that never quite settles.","pol":[{"t":"exalted","p":"Moon","z":"▲冲劲像月有盈缺,满月时上头,过后自然退潮,随年岁渐缓。","e":"The drive waxes and wanes like the Moon, and softens with age."},{"t":"detriment","p":"Mars","z":"▼一味往前冲会踩到别人,迟早招来不满与反扑。","e":"Pushing ahead at all costs steps on toes and invites backlash."}]},"5":{"tz":"舍己利众","te":"Giving for the Whole","mz":"愿意放下一点自己,用沟通与协作,换来对大家都好的改变。","me":"Willing to set self aside, using exchange to bring change that serves all.","pol":[{"t":"exalted","p":"Mercury","z":"▲善于把和谐与互动讲清楚,带动整体往好处走。","e":"Communicates harmony so well it moves the whole forward."},{"t":"detriment","p":"Jupiter","z":"▼虽肯付出协作,心底却总惦记:自己是不是吃亏了。","e":"Cooperates, yet quietly mourns the personal growth given up."}]},"6":{"tz":"修正之力","te":"The Power to Correct","mz":"天生带着把偏差扳回正轨的能量,推动事情向前修正。","me":"Carries the energy to set things right and move them forward.","pol":[{"t":"exalted","p":"Saturn","z":"▲沉稳加上恒心,在对的时机出手,纠错到位又有效。","e":"Steady ambition makes corrections land at just the right time."},{"t":"detriment","p":"Mars","z":"▼用力过猛去纠正,反而激起抵抗,把问题越压越僵。","e":"Correcting by force only breeds resistance and hardens the problem."}]}},"36":{"1":{"tz":"迎难不退","te":"Standing Firm","mz":"面对阻力不退缩,有撑过危机的情绪韧劲,但也容易因死守原则而硬碰硬。","me":"Holding your ground through opposition, with the emotional stamina to weather a crisis.","pol":[{"t":"exalted","p":"Mars","z":"▲扬升:有股不服输的劲,情绪扛得住压力,危机来了也能稳住。","e":"The drive and grit to push on against resistance, with the emotional power to ride out crisis."},{"t":"detriment","p":"Jupiter","z":"▼落陷:太执着原则,该让的不让,死守旧模式只会把危机引上门。","e":"Over-rigid principles that refuse to adapt, clinging to old ways and inviting needless conflict."}]},"2":{"tz":"扶人一把","te":"Lending a Hand","mz":"在别人走下坡路时伸手相助,默默用想象力与温柔为他人撑过低谷。","me":"Quietly helping others through their decline, offering support when things fall apart.","pol":[{"t":"exalted","p":"Neptune","z":"▲扬升:用想象力想出利他的法子,危机里的一份情意能托起别人。","e":"Imagination put to work for others' good, with feelings that lift people through crisis."},{"t":"detriment","p":"Moon","z":"▼落陷:只在迫不得已时才出手,帮也是挑着帮,不当成常态。","e":"Help given only when unavoidable, selective and practical rather than freely offered."}]},"3":{"tz":"破后重生","te":"Out of the Ashes","mz":"在旧局耗尽气数的转折点,有勇气从废墟里立起新秩序,但常放不下旧情。","me":"At the turning point where decline runs out, building something new from the wreckage.","pol":[{"t":"exalted","p":"Pluto","z":"▲扬升:从灰烬里重立新局,有撑过危机、拥抱蜕变的情绪深度。","e":"The depth to endure crisis and forge a new order from what's been burned down."},{"t":"detriment","p":"Jupiter","z":"▼落陷:想把旧东西塞进新局,舍不得过去,旧势力日后可能反扑。","e":"Dragging the old into the new, unable to let go—and the past may rise against you later."}]},"4":{"tz":"未雨绸缪","te":"Knowing Ahead","mz":"靠暗中积累情报预判衰落,提前为危机备好底牌的人。","me":"Anticipating decline by quietly gathering what others don't know.","pol":[{"t":"exalted","p":"Pluto","z":"▲扬升:暗中攒下关键情报,看懂危机将至,早早备好应对的牌。","e":"Stockpiling secret, hard-won knowledge so you're ready before crisis hits."},{"t":"detriment","p":"Moon","z":"▼落陷:看清对方更强便倒戈求存,成了两头通吃的双面人。","e":"Sensing the other side is stronger, switching loyalties to survive—the double agent."}]},"5":{"tz":"隐忍求生","te":"The Survivor","mz":"无论环境多糟都能活下来的人,既制造风浪也熬得过风浪,只怕自己心慌坏事。","me":"Surviving any conditions, immune to crisis—as long as nerves don't betray you.","pol":[{"t":"exalted","p":"Pluto","z":"▲扬升:把生存本事磨到极致,什么处境都活得下去,危机伤不到你。","e":"Survival perfected against all odds—you both stir up and outlast every crisis."},{"t":"detriment","p":"Mercury","z":"▼落陷:一紧张就慌了神,话多嘴快,反倒把自己暴露、出卖。","e":"Nerves that get the better of you, blurting and slipping until you give yourself away."}]},"6":{"tz":"邪不胜正","te":"Right Prevails","mz":"深信黑暗终会自我吞噬、正义自有归途,只是看多了仍难免心生悲凉。","me":"Trusting that darkness destroys itself in the end, and right outlasts it.","pol":[{"t":"exalted","p":"Jupiter","z":"▲扬升:笃信黑暗终会自毁,从纯净的情感里生出的危机自有其正当。","e":"Faith that the powers of darkness undo themselves—crisis born of pure feeling is just."},{"t":"detriment","p":"Saturn","z":"▼落陷:看透了道理,却依旧被深深的悲伤与犬儒缠住,放不下。","e":"A deep sorrow and cynicism that knowing the truth still cannot dissolve."}]}},"37":{"1":{"tz":"持家者","te":"The One Who Holds the Home","mz":"天生被信任的人,以柔和与默契,守住一段关系或一个家的温度。","me":"Someone who naturally earns respect and keeps the bonds of a family warm.","pol":[{"t":"exalted","p":"Venus","z":"▲扬升:用和气当黏合剂,关系自然长久,美好与温情得以留存。","e":"Harmony as the glue: bonds last, and warmth is preserved with care."}]},"2":{"tz":"各守其责","te":"Each Carries Their Share","mz":"明白真正的同行,是各自先扛起自己那一份责任,而非互相挑剔。","me":"Knows that real cooperation starts with each person owning their own part.","pol":[{"t":"exalted","p":"Jupiter","z":"▲扬升:先把自己那份担起来,合作与友谊就有了稳固的地基。","e":"Carrying your own weight first lays a solid base for friendship."},{"t":"detriment","p":"Mercury","z":"▼落陷:总盯着别人该做什么,把责任往外推,关系反被消耗。","e":"Fixating on others' duties and shifting blame outward drains the bond."}]},"3":{"tz":"拿捏分寸","te":"Sensing What's Fair","mz":"群体能否长久,看的是分寸:知道什么可以、什么越界,反应不偏不倚。","me":"A group endures on fairness: knowing what's okay and responding evenly.","pol":[{"t":"exalted","p":"Jupiter","z":"▲扬升:对越界有敏感的判断力,既不放纵也不苛责,处置得当。","e":"A keen, balanced read on what fits and how to respond when lines are crossed."},{"t":"detriment","p":"Mars","z":"▼落陷:要么不停试探底线,要么对别人的试探反应过激,失了分寸。","e":"Either constantly testing limits or coming down too hard when others do."}]},"4":{"tz":"以身作则","te":"Leading by Living It","mz":"在日常小事里活出原则的人,不靠头衔,自然成了大家愿意跟随的榜样。","me":"By living their principles in daily life, they quietly become a leader others follow.","pol":[{"t":"exalted","p":"Moon","z":"▲扬升:把高尚原则落到柴米油盐里,身体力行,引领自然发生。","e":"Bringing the highest principles into everyday life, leadership follows naturally."},{"t":"detriment","p":"Saturn","z":"▼落陷:守旧到只认传统权威,看不见身边其他人也值得跟随。","e":"So traditional that only the established authority is accepted as leader."}]},"5":{"tz":"自然之爱","te":"Love That Just Flows","mz":"对家人毫不做作的牵挂,在自然的和谐里彼此付出、彼此分享。","me":"Unforced devotion to family, giving and sharing within easy harmony.","pol":[{"t":"exalted","p":"Venus","z":"▲扬升:天生的和谐,分享得恰到好处,爱在关系里自在流动。","e":"Natural harmony and well-balanced sharing let love flow with ease."},{"t":"detriment","p":"Mars","z":"▼落陷:情感上的过度依赖,一旦失衡,爱很容易翻转成恨。","e":"Emotional dependency that, when unmet, can flip love into resentment."}]},"6":{"tz":"看见意义","te":"Seeing What It's For","mz":"维系关系的能量,来自真正看懂并珍惜它的价值,而非义务。","me":"The energy to sustain bonds comes from truly valuing what they mean.","pol":[{"t":"exalted","p":"Venus","z":"▲扬升:不只看懂关系深处的意义,更由衷珍惜,愿把这份连结延伸出去。","e":"Grasping the inner meaning of bonds and cherishing them enough to extend them."},{"t":"detriment","p":"Mercury","z":"▼落陷:太渴望新鲜多样,纵使心里认可,也宁愿要泛泛之交、抽身离开。","e":"A craving for variety that prefers casual ties and quiet withdrawal."}]}},"38":{"1":{"tz":"看准了才战","te":"Knowing When to Fight","mz":"不是逢战必上,而是凭直觉判断这场仗值不值得打、该怎么打。","me":"Not every battle is yours; an inner radar tells you which fights are worth taking on, and how.","pol":[{"t":"exalted","p":"Neptune","z":"▲一种近乎本能的直觉,让你在对的时机、用对的方式出手,从不空耗。","e":"An almost psychic sense for the right moment and the right way to push back."},{"t":"exalted","p":"Mars","z":"▲天生带着抗衡的劲头,把对峙当作生活的常态去面对。","e":"A native drive to oppose, meeting resistance as a natural part of living."}]},"2":{"tz":"有礼的对抗","te":"Fighting with Manners","mz":"天生懂得在坚持立场时也守住分寸,不让对抗变成失礼。","me":"A gift for holding your ground without ever breaching the basic courtesies.","pol":[{"t":"exalted","p":"Pluto","z":"▲懂得收着说、留有余地,这份分寸感本身就是力量。","e":"Wisdom in restraint; knowing what to leave unsaid is its own strength."},{"t":"detriment","p":"Moon","z":"▼客气过了头,变成讨好与表面功夫,反而把该守的立场丢了。","e":"Politeness overdone slides into hollow flattery and defeats its own aim."}]},"3":{"tz":"并肩才走得远","te":"Strength in Allies","mz":"在硬仗里找到同路人,彼此借力,才扛得住、走得长。","me":"In a long struggle, the right allies are what let you endure and persevere.","pol":[{"t":"exalted","p":"Sun","z":"▲与志同道合者合流,互相充电,让坚持的底气源源不断。","e":"Joining with kindred forces renews your energy and sustains the fight."},{"t":"detriment","p":"Earth","z":"▼只顾自己,把同伴当电池榨干来撑自己,联盟成了消耗。","e":"A selfish alliance that drains partners just to keep yourself going."}]},"4":{"tz":"先看清再结盟","te":"Knowing Who to Trust","mz":"结伴抗争前先摸清底细,看清谁值得托付、谁能真正帮上忙。","me":"Before joining forces, you size people up to see who can truly be trusted.","pol":[{"t":"exalted","p":"Pluto","z":"▲像侦探般洞察人,认得出谁值得信任,联手才有真正的胜算。","e":"A detective's eye for who is worth trusting, so joint effort can hold."},{"t":"detriment","p":"Mars","z":"▼火气一上头就乱冲,搅乱了判断,也让人不敢信你。","e":"Adrenaline-fueled aggression clouds your judgment and erodes trust."}]},"5":{"tz":"孤身硬扛","te":"Standing Utterly Alone","mz":"走到一个谁也帮不上的关口,只能凭一己之力咬牙撑下去。","me":"A stage of total isolation, where only your own grit carries you through.","pol":[{"t":"exalted","p":"Saturn","z":"▲凭着专注与韧劲,哪怕孤军一人也能熬到底、不退场。","e":"The focus and ambition to endure, holding the line even when alone."},{"t":"detriment","p":"Pluto","z":"▼太执拗,把孤立当牢笼,看不见其实终会有人来搭把手。","e":"Stubbornness so deep it blinds you to the help that could still come."}]},"6":{"tz":"为误会而战","te":"Conflict from Misunderstanding","mz":"许多对立其实源于误解;能放下成见,僵局才有解开的一天。","me":"Much opposition is rooted in misunderstanding, and clears once it's seen for what it is.","pol":[{"t":"exalted","p":"Saturn","z":"▲时间会让误会沉淀澄清,你也有顶住对立、等到水落石出的韧劲。","e":"In time things crystallize, the misunderstanding clears, and you hold firm until it does."},{"t":"detriment","p":"Earth","z":"▼明知误会是根源,却咬定是对方在误会,死守己见不肯松口。","e":"You sense misunderstanding is the root, yet insist it's always the other side's, digging in."}]}},"39":{"1":{"tz":"暂退","te":"Strategic Withdrawal","mz":"遇阻先撤，以退为进；却难拿捏何时该重新出手。","me":"Stepping back from obstacles to provoke, while wrestling with when to step back in.","pol":[{"t":"exalted","p":"Mars","z":"遇阻不硬碰，主动退一步，留出空间再择机进逼。","e":"Wisely pulls back from a wall, using the retreat itself to push and stir."},{"t":"detriment","p":"Mercury","z":"退下后陷入犹豫，迟迟看不清何时该重返战场。","e":"Once withdrawn, gets stuck in dithering, blind to the moment to reengage."}]},"2":{"tz":"正面迎击","te":"Head-On","mz":"凭直觉直取障碍，不绕弯子，正面冲撞激起回应。","me":"Meets the obstacle straight on by instinct, provoking through direct assault.","pol":[{"t":"exalted","p":"Moon","z":"本能驱使直捣要害，干脆利落地正面突破。","e":"Instinct drives a clean, direct strike at the heart of the block."},{"t":"exalted","p":"Jupiter","z":"求稳之心诱人绕道，可有些坎注定只能硬闯。","e":"A preserving instinct tempts a detour, yet some walls must be charged."}]},"3":{"tz":"顾全大局","te":"Weighing The Cost","mz":"若失败会连累他人，便慎言冲撞；担责与卸责皆是激发。","me":"Holds back from charging when failure would endanger others around.","pol":[{"t":"exalted","p":"Jupiter","z":"先想整体福祉，甘愿自我牺牲来护住更大的局。","e":"Puts the whole first, ready to sacrifice self to shield the larger frame."},{"t":"detriment","p":"Earth","z":"误判旁人风险，逃避冲撞反酿更大祸患。","e":"Misjudges others' risk, dodging the fight and triggering worse fallout."}]},"4":{"tz":"审时度势","te":"Right Timing","mz":"出手前细察权衡，凭感觉拿准时机才发力激发。","me":"Weighs and assesses carefully, provoking only at exactly the right time.","pol":[{"t":"exalted","p":"Moon","z":"信任直觉与感受，等到分毫不差的时刻才出手。","e":"Trusts feeling and instinct to fire at precisely the ripe moment."},{"t":"detriment","p":"Sun","z":"迷信意志万能，无视处境硬推，逆势激发。","e":"Believes willpower alone conquers all, pushing blind to circumstance."}]},"5":{"tz":"另辟蹊径","te":"Sidestepping","mz":"不硬攻而绕过障碍，以想象力让难关变得无关紧要。","me":"Doesn't overcome the obstacle but bypasses it, making it irrelevant.","pol":[{"t":"exalted","p":"Neptune","z":"靠想象另开新局，让原有障碍彻底失去意义。","e":"Imagines fresh patterns that render the old obstacle meaningless."},{"t":"detriment","p":"Mars","z":"纯凭一根筋的固执硬撑，靠死磕也偶能成事。","e":"Plain bullheaded persistence that, though crude, sometimes still wins."}]},"6":{"tz":"解难能手","te":"The Troubleshooter","mz":"天生善解难题，以为他人排忧解难来激发推动。","me":"A natural gift for solving problems, provoking by tackling others' troubles.","pol":[{"t":"exalted","p":"Moon","z":"务实又懂人心，引导滋养他人，替人化解困局。","e":"Practical and caring, guides and nurtures while untangling others' knots."},{"t":"detriment","p":"Mars","z":"自我膨胀，把解难天赋拿去博取名利、彰显己强。","e":"Ego hijacks the gift, using it for self-glory and ambition over others."}]}},"40":{"1":{"tz":"歇息回血","te":"Recuperation","mz":"辛劳后懂得停下,独处也能怡然自得。","me":"Resting to refuel, at ease enjoying your own company.","pol":[{"t":"exalted","p":"Sun","z":"放松享受劳动果实,自我充盈,独处自在。","e":"You unwind and savor what you've earned, content on your own."},{"t":"detriment","p":"Moon","z":"难以静止,独处稍久便焦躁难安。","e":"Restless and unable to be still, you chafe at solitude that lingers."}]},"2":{"tz":"决然斩断","te":"Resoluteness","mz":"果断放下拖累自己的旧习,看清他人影响。","me":"Firmly shedding what held you back, clear-eyed about others' pull.","pol":[{"t":"exalted","p":"Sun","z":"有力切断旧束缚,独处中看清谁会扰乱前路。","e":"You cut old chains for good, sensing who could derail you."},{"t":"detriment","p":"Moon","z":"心软去呵护拖累自己的力量,孤独蒙蔽判断。","e":"Too soft, you nurse the very ties that drag you, loneliness clouding sight."}]},"3":{"tz":"藏锋低调","te":"Humility","mz":"刻意收敛,不张扬解脱,避开恶意纠缠。","me":"Staying low-key to keep clear of hostile attention.","pol":[{"t":"exalted","p":"Pluto","z":"享受解脱却不炫耀,宁可独处也避开恶势力。","e":"You enjoy freedom quietly, dodging hostile forces even if it means going it alone."},{"t":"exalted","p":"Mars","z":"高调索取关注,且真能把目光吸引过来。","e":"Boldly demanding the spotlight, you actually command it."}]},"4":{"tz":"运筹有方","te":"Organization","mz":"精明组织、有所取舍,巩固自己的解脱。","me":"Organizing wisely and selectively to hold your freedom secure.","pol":[{"t":"exalted","p":"Uranus","z":"凭直觉甄选、统筹,守住解脱与自主。","e":"With intuitive judgment you select and arrange, guarding your independence."},{"t":"detriment","p":"Mars","z":"只图人多不问质量,狂热终将动摇解脱。","e":"Chasing numbers over quality, blind zeal quietly undermines your freedom."}]},"5":{"tz":"毫不妥协","te":"Rigidity","mz":"要真正解放,必须彻底拒绝一切负面力量。","me":"True liberation means rejecting every negative force outright.","pol":[{"t":"exalted","p":"Uranus","z":"革新者只求全胜,坚决断绝有害关系。","e":"The revolutionary wants total victory, severing harmful ties without flinching."},{"t":"detriment","p":"Earth","z":"幻想日后再清,容忍偏差,孤独中留下隐患。","e":"Tolerating some rot to purge later, loneliness keeps you clinging to bad ties."}]},"6":{"tz":"斩除首恶","te":"Decapitation","mz":"解放前,必须清除盘踞高位的腐败势力。","me":"Before liberation, the corrupt in power must be removed.","pol":[{"t":"exalted","p":"Sun","z":"公正而宽厚,只罢黜真正该罢黜之人。","e":"Fair yet magnanimous, you oust only those who truly deserve it."},{"t":"detriment","p":"Earth","z":"如恐怖统治,滥施惩罚,权力扭曲成残暴。","e":"Like the Terror, punishment runs wild as power warps into cruelty."}]}},"41":{"1":{"tz":"量力而行","te":"Reasonable Delegation","mz":"在有限中分清轻重，把责任交给对的人。","me":"Knowing your limits, you hand each task to the right shoulders.","pol":[{"t":"exalted","p":"Neptune","z":"以巧思把微薄资源用到极致，情绪克制、有所取舍。","e":"Imagination wrings the most from little; feelings released with cool restraint."},{"t":"detriment","p":"Mercury","z":"高估自己揽下过多，情绪一触即发、徒增内耗。","e":"Overrating capacity invites strain; the hothead spills feelings too soon."}]},"2":{"tz":"谨慎自守","te":"Prudent Compassion","mz":"愿助人却不拿自身安稳冒险，务实的善意。","me":"Helping others without gambling your own footing.","pol":[{"t":"exalted","p":"Saturn","z":"守稳本分，先护好自己再援手，情绪只为自己留力。","e":"A steady nature aids others but never risks its own security."},{"t":"detriment","p":"Mars","z":"为博认可不计后果，耗尽资源只换一时风光。","e":"Craving recognition, it burns precious reserves for fleeting applause."}]},"3":{"tz":"集中精力","te":"Focused Efficiency","mz":"资源紧缺时，专注己务的自私是合理的。","me":"When means are thin, a single-minded focus is justified.","pol":[{"t":"exalted","p":"Saturn","z":"怀抱目标，自律独行，把热情灌注于个人企图。","e":"Material ambition with the discipline to walk the road alone."},{"t":"detriment","p":"Moon","z":"本能想拉人同行，却让两人把有限资源消耗加倍。","e":"Instinctive helping, well-meant, drains scarce supplies twice as fast."}]},"4":{"tz":"顺势调整","te":"Adapting to Limits","mz":"接受局限并主动调整，方能存续乃至壮大。","me":"Adapt to the constraint and you survive, then thrive.","pol":[{"t":"exalted","p":"Earth","z":"适者生存，懂得变通终能开花，深植求生本能。","e":"Adaptation rooted in a deep survival instinct eventually flourishes."},{"t":"detriment","p":"Venus","z":"把力气耗在维系无益关系，舍不得放手而误了调整。","e":"Spending energy to keep weak ties costs more than the change it shuns."}]},"5":{"tz":"获得认可","te":"Earning Endorsement","mz":"潜力虽受局限，仍被外界看见并授权。","me":"Others recognize your potential even within tight bounds.","pol":[{"t":"exalted","p":"Mars","z":"局限之下仍将能量精准导向，情绪用在刀刃上。","e":"Energy and feeling, well-channeled, prove their worth despite limits."},{"t":"detriment","p":"Venus","z":"对限制始终不满，纵有支持也被负面情绪拖住成长。","e":"Chronic discontent with limits stalls growth even when help arrives."}]},"6":{"tz":"善果外溢","te":"Beneficial Contagion","mz":"潜能登顶不仅终结匮乏，更福泽他人。","me":"Maxing your potential ends scarcity and spills over to others.","pol":[{"t":"exalted","p":"Saturn","z":"把形态潜能发挥到极致，如父辈之成就荫蔽后人。","e":"Form fulfilled to its peak; a father's success blesses his children."},{"t":"exalted","p":"Pluto","z":"超越后却怕失去特权而藏起成果，情绪深埋不露。","e":"Transcendence hoarded in secret, feelings repressed for fear of loss."}]}},"42":{"1":{"tz":"余力外拓","te":"Branching Out","mz":"资源有余时向外扩张，把精力延伸到日常之外的新领域。","me":"With surplus on hand, you stretch your reach into new ground.","pol":[{"t":"exalted","p":"Sun","z":"底气足时稳健扩张，让成长向更广处自然铺开。","e":"Solid surplus fuels healthy, grounded expansion outward."},{"t":"detriment","p":"Venus","z":"扩张失了节制，盈余被四散挥霍走向腐化。","e":"Unchecked spread scatters the surplus into decadence."}]},"2":{"tz":"顺势而长","te":"Riding the Trend","mz":"敏锐识别正在兴起的趋势，借势加入而获得成长。","me":"You spot rising currents and grow by moving with them.","pol":[{"t":"exalted","p":"Sun","z":"看准势头果断投入，借趋势之力快速壮大。","e":"Read the wave, commit, and let momentum amplify you."},{"t":"detriment","p":"Venus","z":"面对变化退缩自守，成长在抗拒中停滞。","e":"Recoiling from change, growth stalls in self-denial."}]},"3":{"tz":"试错成长","te":"Learning by Error","mz":"增长途中犯错难免，把错误化为养分才是真本事。","me":"Mistakes come with growth; turn them into fuel.","pol":[{"t":"exalted","p":"Mars","z":"有胆量直面失误，把错误转化成前进的动力。","e":"Bold enough to flip errors into forward thrust."},{"t":"detriment","p":"Moon","z":"因错而郁结，陷入反复纠结与过度谨慎。","e":"Errors breed brooding and needless overcaution."}]},"4":{"tz":"居中调和","te":"The Middle Man","mz":"成熟担当中间人，以斡旋促成各方共同成长。","me":"A mature mediator who grows the whole through brokering.","pol":[{"t":"exalted","p":"Moon","z":"天生的调停者，以成熟手腕牵线促成增长。","e":"The born mediator, ripe enough to grow through go-between work."},{"t":"detriment","p":"Venus","z":"一味求和谐，回避务实，反让斡旋失真、增长受限。","e":"Clinging to harmony over pragmatism warps the mediation."}]},"5":{"tz":"自我成全","te":"Self-Actualization","mz":"把实现自我当作本然之路，影响力自然随成长而来。","me":"Fulfilling your purpose naturally draws influence to you.","pol":[{"t":"exalted","p":"Sun","z":"走在本然的实现之路上，成长带来踏实的自我感。","e":"Living your purpose grows a grounded, healthy sense of self."},{"t":"detriment","p":"Venus","z":"只向内求圆满，把成长封进与世隔绝的孤境。","e":"Inner-only fulfillment seals growth into reclusiveness."}]},"6":{"tz":"滋养众生","te":"Nurturing","mz":"本能地滋养他人，乐于把成长的过程与人分享。","me":"You instinctively nourish others, sharing the path of growth.","pol":[{"t":"exalted","p":"Moon","z":"出于天性照拂他人，把成长的果实与众人共享。","e":"An instinctive carer who shares the whole growth journey."},{"t":"detriment","p":"Saturn","z":"困于占有式的物欲，自我孤立又催生攻击性。","e":"Hoarding materialism isolates the self and breeds aggression."}]}},"43":{"1":{"tz":"静待时机","te":"Patience","mz":"新知未到沉淀火候，别急着摘果，先让阻力消退、洞见扎根。","me":"A fresh insight needs depth before form; let resistance fade rather than rush the harvest.","pol":[{"t":"exalted","p":"Pluto","z":"懂得新形态须待阻力散尽方能立，沉得住气把洞见酿成实质。","e":"Knows new forms hold only once resistance clears, and has the depth to root the insight."},{"t":"detriment","p":"Venus","z":"急于品尝成果的甜，反而留下苦涩；爱洞见却没耐心扎根。","e":"Grabs the sweetness too soon and tastes only sourness; loves the idea, skips the depth."}]},"2":{"tz":"专注成习","te":"Dedication","mz":"靠独特的思维习惯持续酝酿突破，但临门一脚别因兴奋乱了章法。","me":"Unique mental habits breed breakthrough, but don't abandon your process when the goal appears.","pol":[{"t":"exalted","p":"Pluto","z":"守住自己独有的思考方式与心态，让突破在专注中自然成形。","e":"Holds to its own thought patterns and stance, letting breakthrough ripen through focus."},{"t":"detriment","p":"Moon","z":"一见机会就抛开惯常步骤，行动失了分寸，急于表达反而冒进。","e":"Drops its routine the moment a chance appears, growing reckless in the rush to act."}]},"3":{"tz":"不择手段","te":"Expediency","mz":"突破受阻时不惜借任何力、扛任何骂去达成；但太怕被骂就会自废。","me":"When breakthrough is at stake, use any means and bear any blame—just don't let blame stop you.","pol":[{"t":"exalted","p":"Pluto","z":"认定方向便顶住非议，借势而行，强劲的再生力撑到突破达成。","e":"Certain of its knowing, it endures condemnation and uses any force to reach breakthrough."},{"t":"detriment","p":"Moon","z":"太在意他人指责，正当的变通也不敢用，洞见在非议前缴械。","e":"Too stung by criticism to act expediently, it surrenders its insight under condemnation."}]},"4":{"tz":"一根筋","te":"The One-Track Mind","mz":"认死理死磕脑力，独到洞见需精准概念化才成；缺深度的自负则空谈。","me":"Stubbornly trusts its mind; unique insight only works when sharply conceptualized, not bluffed.","pol":[{"t":"exalted","p":"Mercury","z":"对独特洞见的执守需要清晰的脑力来落实，专注思考方能成形。","e":"Clings to unique insight and uses keen focus to give it precise conceptual form."},{"t":"detriment","p":"Jupiter","z":"凭一知半解便自信正确、拒听劝告，没深度还硬要表达，是虚妄。","e":"Sure it's right on thin knowledge, it shuns advice and vainly expresses without depth."}]},"5":{"tz":"循序渐进","te":"Progression","mz":"懂得在关系中一步步务实推进，找准时机分享洞见而不损成功。","me":"Adapts to relationships step by step, sharing insight at the right moment without risking success.","pol":[{"t":"exalted","p":"Moon","z":"用务实步骤适应阻碍突破的关系，知道何时把洞见有效说出。","e":"Adjusts to obstructive ties through practical steps, knowing when insight can land well."},{"t":"detriment","p":"Venus","z":"一味维系和谐反倒巩固了束缚，太靠他人接纳，和气成了枷锁。","e":"Chasing harmony props up restraint; over-relying on others' acceptance, harmony becomes a leash."}]},"6":{"tz":"突破立新","te":"Breakthrough","mz":"突破时归于中心，内外自然立起新秩序，独到之知兼具个人与集体价值。","me":"Centered in breakthrough, a new order arises within and without; knowing serves self and all.","pol":[{"t":"exalted","p":"Sun","z":"落实而归位，突破之际内外自成新秩序，洞见于己于众皆有价值。","e":"Actualized and centered, it founds a new order within and without, of value to self and all."},{"t":"detriment","p":"Mars","z":"突破成了小我的自我开脱，把旧毛病带进新局，只把知看得最重。","e":"Ego uses breakthrough to excuse its flaws, dragging them into the new order, prizing knowing above all."}]}},"44":{"1":{"tz":"立规则","te":"Setting the Terms","mz":"在互动中建立框架，凭直觉识别模式，定下能约束的规矩。","me":"From interaction comes the framework, and an instinct sharp enough to set conditions that actually hold.","pol":[{"t":"exalted","p":"Pluto","z":"敏锐读懂群体脉络，立下清晰规范并有力执行，化模式洞察为掌控力。","e":"Reads the group's patterns and lays down firm conditions it can enforce, turning insight into mastery."},{"t":"detriment","p":"Venus","z":"因贪图和谐而不愿立界限，被弱势力量牵着走，直觉失灵。","e":"So hungry for harmony it skips the limits, letting weak forces drift in until the instinct goes quiet."}]},"2":{"tz":"善管理","te":"Bringing Things Together","mz":"把杂乱元素纳入协作结构，让直觉化为真正的管理才能。","me":"Weaving scattered elements into a working structure, where instinct matures into real management.","pol":[{"t":"exalted","p":"Jupiter","z":"搭建包容的协作架构，把弱项整合进上升的整体，物尽其用。","e":"Builds an inclusive structure that folds weak parts into the rising whole, so nothing is wasted."},{"t":"detriment","p":"Mars","z":"只盯目标硬冲，忽视细节，数量上达标却失了品质。","e":"Charges at the goal and ignores the weak links, hitting the number while losing the quality."}]},"3":{"tz":"防干扰","te":"Reading the Threat","mz":"凭直觉觉察外来干扰，看清能否驾驭他人的自我。","me":"Sensing interference before it lands, and knowing whether you can handle another's ego.","pol":[{"t":"exalted","p":"Mars","z":"提前嗅到威胁，做好防备，从容应对他人的自我。","e":"Smells the threat early, braces for it, and meets the other's ego without flinching."},{"t":"detriment","p":"Neptune","z":"陷入投射与幻想，错判形势，应对干扰频频出错。","e":"Lost in projection, it misreads the situation and fumbles the response again and again."}]},"4":{"tz":"不虚伪","te":"Refusing the Charade","mz":"拒绝虚假往来，凭本能记忆保持冷静的清醒。","me":"No room for hypocrisy, just a cool clarity rooted in instinctive memory.","pol":[{"t":"exalted","p":"Pluto","z":"以最冷静利落的疏离划清界限，由本能记忆指引取舍。","e":"A cool, clean detachment that draws the line, guided by what instinct remembers."}]},"5":{"tz":"巧借力","te":"Turning Weakness to Fuel","mz":"凭直觉识破模式，把弱势力量化作推动进程的能量。","me":"Spotting the patterns by instinct, then turning weaker forces into fuel for what moves forward.","pol":[{"t":"exalted","p":"Uranus","z":"把与弱者的互动转为进步动能，借力同时让对方无从坐大。","e":"Channels weak elements into progress, drawing on them while keeping them too small to threaten."},{"t":"detriment","p":"Mars","z":"借力变成压榨，沦为欺凌，与所利用者一同堕落。","e":"When leverage turns to abuse, it sinks to the level of those it exploits."}]},"6":{"tz":"超然立","te":"Standing Above It","mz":"觉察模式护住自身安康，在新生中超脱旁人非议。","me":"Aware of the patterns that keep you whole, rising past the judgment of those left behind.","pol":[{"t":"exalted","p":"Pluto","z":"立起新格局而免疫于旧者的指责，洞察模式守护自身安康。","e":"Renewed into a new form, immune to the scorn of the rejected, with pattern-awareness guarding well-being."},{"t":"detriment","p":"Earth","z":"以洞察喂养傲慢，对不如己者轻蔑，损人安康抬高自我。","e":"Feeds insight into arrogance, looking down on lesser souls and inflating itself at their cost."}]}},"45":{"1":{"tz":"招揽","te":"Canvassing","mz":"用教育唤起认同，把游离者引入共同体。","me":"Drawing in the uncommitted by teaching, not pressuring.","pol":[{"t":"exalted","p":"Jupiter","z":"以启迪取信，让未定者自愿聚拢，方向落在教化。","e":"Wins people over by educating the undecided, growing the group with grace."},{"t":"detriment","p":"Mars","z":"热心过度变成强行布道，反把人推远。","e":"Zeal tips into preaching, alienating the very support it seeks."}]},"2":{"tz":"共识","te":"Consensus","mz":"找到公认的共同利益，聚合才稳固。","me":"Gathering holds firm once shared interest is named.","pol":[{"t":"exalted","p":"Uranus","z":"巧创方法测出共同地带，让众人各得其益。","e":"Invents ways to surface common ground for everyone's benefit."},{"t":"detriment","p":"Mars","z":"天生反骨拒绝随大流，不肯用他人之法。","e":"Born to rebel, it refuses the methods others rely on."}]},"3":{"tz":"排斥","te":"Exclusion","mz":"被拒于门外时，化解旧形以求接纳。","me":"When shut out, dissolve the old form to get back in.","pol":[{"t":"exalted","p":"Neptune","z":"被排斥也肯放下身段，化掉陈规以求归入。","e":"Even swallows humiliation to dissolve stale barriers and rejoin."},{"t":"detriment","p":"Mars","z":"遭排斥便激烈反扑，把挫败化作攻击。","e":"Met with rejection, it lashes out and turns hurt into aggression."}]},"4":{"tz":"方向","te":"Direction","mz":"把聚合的力量导向更高原则。","me":"Steering the gathered toward a higher purpose.","pol":[{"t":"exalted","p":"Jupiter","z":"聚众之力为崇高原则所用，于现实中落地。","e":"Channels the group's momentum to serve higher principles in the world."},{"t":"detriment","p":"Mars","z":"暗中扭转群体走向，只为私利谋算。","e":"Bends the group's course toward personal gain, losing all principle."}]},"5":{"tz":"领导","te":"Leadership","mz":"凡聚合，必有可敬的中心与焦点。","me":"Every gathering needs a respected center to hold it.","pol":[{"t":"exalted","p":"Uranus","z":"凭直觉与创新提升群体，敬重中心而存续。","e":"Lifts the group with intuitive innovation, honoring the center that endures."},{"t":"detriment","p":"Jupiter","z":"尚未赢得敬重，却已索要应得的尊崇。","e":"Claims the respect of leadership before it has actually been earned."}]},"6":{"tz":"重纳","te":"Reconsideration","mz":"外人若肯承认昔日之误，便得接纳。","me":"An outsider who admits past error earns its way in.","pol":[{"t":"exalted","p":"Uranus","z":"懂得外人的怪异逻辑，创变为其留一席之地。","e":"Understands the outsider's odd logic and invents room for it to belong."},{"t":"detriment","p":"Jupiter","z":"不容外人本色，硬要其归顺常规方收。","e":"Won't make space, demanding the outsider conform before it's let in."}]}},"46":{"1":{"tz":"被看见","te":"Discovered in obscurity","mz":"默默深耕，终有一天被世界看见。","me":"Quiet dedication eventually gets noticed, however unexpectedly.","pol":[{"t":"exalted","p":"Neptune","z":"为热爱而创作，纯粹投入本身迟早赢得认可。","e":"Creating purely for love; sincere devotion earns recognition in time."},{"t":"detriment","p":"Jupiter","z":"慧眼识人，却只为蹭别人的成功为己牟利。","e":"Spotting hidden talent only to ride its success for personal gain."}]},"2":{"tz":"天才任性","te":"The demanding talent","mz":"才华足够耀眼，便容得下难搞的脾气。","me":"Talent so deep it succeeds despite a prickly nature.","pol":[{"t":"exalted","p":"Sun","z":"脾气虽难相处，凭真本事照样脱颖而出。","e":"Hard to please, yet genuine gifts carry it through to success."},{"t":"detriment","p":"Mars","z":"平庸却自大，未成事先要别人当成功者捧。","e":"Mediocrity demanding the rewards of success it hasn't yet earned."}]},"3":{"tz":"投射陷阱","te":"Projecting ahead","mz":"守住成功的节奏，别把幻想当现实。","me":"Stay with what works rather than chasing imagined futures.","pol":[{"t":"exalted","p":"Moon","z":"脚踏实地守住带来好运的习惯，不被妄想带偏。","e":"Practically keeping the habits that brought luck, not chasing more."},{"t":"detriment","p":"Mars","z":"把还没到的未来当现成，自满而丢了势头。","e":"Treating an imagined win as real, losing momentum and support."}]},"4":{"tz":"出头时刻","te":"Sudden impact","mz":"一旦被看见，便从无名快速跃上台面。","me":"Once seen, you rise from obscurity to influence fast.","pol":[{"t":"exalted","p":"Earth","z":"持续努力终在对的时间地点遇见认可。","e":"Steady determination meets recognition at the right time and place."},{"t":"exalted","p":"Pluto","z":"得势后反咬恩人，无视一路扶持自己的人。","e":"On reaching success, biting the hand that helped you climb."}]},"5":{"tz":"把握节奏","te":"Pacing the rhythm","mz":"顺着已被验证的节拍走，不轻易偏航。","me":"Keep the proven rhythm; don't veer off what works.","pol":[{"t":"exalted","p":"Moon","z":"本能地守住稳定节奏，避免与成功模式背离。","e":"Instinctively holding the steady pace that keeps success on track."},{"t":"detriment","p":"Neptune","z":"无端推翻早已奏效的节奏，自毁好局。","e":"Irrationally rejecting the very rhythm that has been working."}]},"6":{"tz":"守住诚信","te":"Keeping integrity","mz":"看清承诺的束缚，敢于对超载说不。","me":"Weigh commitments wisely and dare to say no.","pol":[{"t":"exalted","p":"Saturn","z":"权衡承诺的代价，必要时拒绝以护住自己。","e":"Wisely weighing commitments and declining what would bind you."},{"t":"detriment","p":"Neptune","z":"盲目应承超出能力，最终只能毁约失信。","e":"Overpromising beyond your means until promises must be broken."}]}},"47":{"1":{"tz":"清点内耗","te":"Taking Stock","mz":"困住你的常是脑中的念头,先把消耗自己的负面想法一条条揪出来。","me":"When pressed, you sort through your own mind and weed out the thoughts that drain you.","pol":[{"t":"exalted","p":"Saturn","z":"▲难关里沉得住气,专心铲除拖住自己的负面念头,看清出路在内不在外。","e":"Under pressure, calmly pinpoints and clears the negative thinking that holds you down."},{"t":"detriment","p":"Neptune","z":"▼把困境全怪给外界,深信全世界都在跟自己作对,结果越陷越深。","e":"Blames the squeeze entirely on the outside world, feeling everyone is against you."}]},"2":{"tz":"动起来","te":"Drive to Rise","mz":"陷在压力里也不肯躺平,用一股向上的劲头给自己挣回安稳。","me":"Even when boxed in, an upward drive pushes you to work your way back to safety.","pol":[{"t":"exalted","p":"Saturn","z":"▲有股不服输的劲,主动突围争取安稳;明白忙起来心反而踏实。","e":"A steady ambition to break free and find security; staying busy keeps the mind well."},{"t":"detriment","p":"Mercury","z":"▼受困时拿不定主意:该奋力翻盘,还是顺势躲一阵,分不清哪样才对自己好。","e":"Stuck and undecided whether to push for recovery or wait out the moment, unsure what's healthy."}]},"3":{"tz":"自我为难","te":"Pressing Yourself","mz":"压力多半来自跟自己过不去,等想通了才发现那份否定本就没根据。","me":"The pressure comes from turning on yourself, until you realize it was never warranted.","pol":[{"t":"exalted","p":"Jupiter","z":"▲心里通透、行得自然,迟早会看穿那份自我否定毫无根据,认下自己其实挺好。","e":"Clear and at ease, you eventually see the self-doubt has no ground, and accept that you're okay."},{"t":"detriment","p":"Mars","z":"▼自我打压被火气越烧越旺,可能一发不可收,难得很难肯定自身的价值。","e":"Self-attack so charged it may turn destructive, making your own worth hard to feel."}]},"4":{"tz":"被外界压住","te":"Held Down","mz":"压力来自外面而非自身,真正的考验是顶着压力守住自己是谁。","me":"The weight comes from outside, and the test is keeping hold of who you are under it.","pol":[{"t":"exalted","p":"Saturn","z":"▲外压再大也守得住底气,留住自己的本钱,甚至护得了身边的人。","e":"However heavy the pressure, holds its core intact, even safeguarding others."},{"t":"detriment","p":"Moon","z":"▼像被夺走光的月亮,陷在黑里连自己都顾不上,自我被外界彻底淹没。","e":"Like a moon robbed of light, lost in dark, the self swallowed by outside conditioning."}]},"5":{"tz":"温柔的圣者","te":"The Grace-Giver","mz":"受压时仍能真心善待压你的人,也扶住一同受苦的人;一种带着恩慈的通透。","me":"Under pressure you stay genuinely kind to oppressor and oppressed alike, a grace-filled clarity.","pol":[{"t":"exalted","p":"Venus","z":"▲受压也不虚伪,既能与施压者和睦相处,又能扶持同样受苦的人;坦然接住命运的重量,恩慈自来。","e":"Without pretense, stays in harmony with oppressors while aiding the oppressed; accepts the weight and grace follows."}]},"6":{"tz":"硬撑度日","te":"Sheer Endurance","mz":"处境艰难看不到翻盘的希望,只能凭一股意志撑着活下来。","me":"A hard spot with no way to truly win, where sheer will is all that carries you through.","pol":[{"t":"detriment","p":"Sun","z":"▼单靠意志勉强适应、活下去,却始终翻不了身;日子成了没有领悟的苦熬。","e":"Will alone scrapes by and survives, but never overcomes; life as an ordeal stripped of insight."}]}},"48":{"1":{"tz":"扎根求实","te":"Rooted in the Practical","mz":"在意自己有没有真本事的人,本能分得清什么值得花力气、什么是瞎忙。","me":"Someone who measures their own depth — instinctively sensing what's worth real effort and what is just noise.","pol":[{"t":"exalted","p":"Moon","z":"▲一眼看出哪件事踏实、值得投入,把力气用在刀刃上。","e":"An instinct for what's practical and genuinely worth your attention."},{"t":"detriment","p":"Mars","z":"▼为了刷存在感,把精力耗在鸡毛蒜皮的小事上。","e":"Burning energy on trivial things just to feel busy or seen."}]},"2":{"tz":"守住底线","te":"Holding the High Line","mz":"心里清楚什么是好东西,不愿为了合群而向低水准妥协的人。","me":"Someone who knows quality when they see it and won't water it down to fit in.","pol":[{"t":"exalted","p":"Pluto","z":"▲立新规时守住最好的部分,不为迁就平庸而打折。","e":"Building something new without sacrificing its best parts to accommodate the mediocre."},{"t":"detriment","p":"Venus","z":"▼太想和谐,结果被劣质的人和事拉着一起堕落。","e":"Craving harmony so much you slide into decay alongside lesser values."}]},"3":{"tz":"暗夜独行","te":"The Dark Phase","mz":"才华一时无人看见、自己也使不上劲的人,深度需要慢慢熬出来。","me":"Someone whose gift goes unseen for a while — depth is a slow, lonely process.","pol":[{"t":"exalted","p":"Moon","z":"▲像无月之夜,光暂时藏起;熬过这段反而长出真功夫。","e":"Like a moonless night — the light is hidden now, but enduring it forges real strength."},{"t":"detriment","p":"Mercury","z":"▼明明有真才实学,却因长期不被看见而陷入深深焦虑。","e":"A deep intelligence left in the wilderness, gnawed at by anxiety."}]},"4":{"tz":"蓄势重整","te":"Regroup and Rebuild","mz":"外部环境受限时,懂得停下来重新布局、为长远蓄力的人。","me":"Someone who uses a forced pause to restructure for the long game rather than push uselessly.","pol":[{"t":"exalted","p":"Sun","z":"▲被叫停时不硬扛,趁机重新规划,等条件回来再发力。","e":"Using a restriction wisely — pausing to reassess and rebuild for when momentum returns."},{"t":"detriment","p":"Earth","z":"▼不肯提前重整,事到临头还是得被迫从头收拾。","e":"Refusing to restructure ahead of time, then forced to do it anyway when activity resumes."}]},"5":{"tz":"落地行动","te":"Put It Into Action","mz":"把深度变成实际行动的人,关键时刻肯出手、不空想。","me":"Someone who turns depth into action — willing to actually move when it counts.","pol":[{"t":"exalted","p":"Mars","z":"▲该出手就出手,把积累的本事痛快用出来。","e":"A natural drive to act — putting your competence to real use."},{"t":"detriment","p":"Moon","z":"▼太求稳,纠结于细节和计划,迟迟不敢动手。","e":"Clinging to safety and over-planning until the moment to act slips away."}]},"6":{"tz":"取之不竭","te":"An Inexhaustible Source","mz":"像一口好井,越给越满;自身的深度本就是给别人的礼物。","me":"Someone whose depth is a gift to others — the more they give, the more they're replenished.","pol":[{"t":"exalted","p":"Venus","z":"▲如井般给予,越分享越充盈,才华真正惠及他人。","e":"A well that gives and is refilled by giving — a depth that truly serves others."},{"t":"detriment","p":"Moon","z":"▼虽乐于付出,但深度不够,礼物流于表面、打动不了人。","e":"Generous but shallow — the gift lacks the depth that would truly move people."}]}},"49":{"1":{"tz":"顺势而立","te":"The Law of Need","mz":"只有大家都觉得非变不可,变革才站得住脚。先让需求被看见。","me":"Change only holds up when everyone feels it's truly necessary.","pol":[{"t":"exalted","p":"Jupiter","z":"▲懂得先扩大共识再行动,让原则因被广泛接受而真正立得住。","e":"Builds wide support first, so the principle becomes truly viable."},{"t":"detriment","p":"Sun","z":"▼硬把需求制造出来,靠制造混乱来证明该乱,过度怕被拒就走极端。","e":"Manufactures crisis to justify upheaval; fear of rejection breeds zealotry."}]},"2":{"tz":"穷尽再说","te":"When All Else Fails","mz":"天生愿意把每条温和的路都走一遍,真没办法了才动手翻盘。","me":"Exhausts every peaceful path first, then changes course only as a last resort.","pol":[{"t":"exalted","p":"Earth","z":"▲耐心试遍所有可能,确认别无他法后才周密筹划再行动。","e":"Tries every option, plans carefully, and acts only when nothing else works."},{"t":"detriment","p":"Pluto","z":"▼按捺不住翻盘的冲动,懒得谈判磋商,贸然出手却孤立无援。","e":"Too impatient to negotiate; a hasty coup that nobody backs."}]},"3":{"tz":"破旧立新","te":"Letting the Old Go","mz":"敏锐地察觉哪些旧规矩、旧关系已经不行了,该放手就放手。","me":"Senses which outworn forms and ties have failed, and lets them go.","pol":[{"t":"exalted","p":"Neptune","z":"▲束缚一旦解除,就能清掉过时的框架,凭直觉舍弃失效的原则。","e":"Once free, dismantles outdated forms; intuitively drops what no longer works."},{"t":"detriment","p":"Pluto","z":"▼清算旧秩序时下手太狠,粗暴的否定会给新局面留下永久伤疤。","e":"Tears down the old so brutally it scars whatever comes next."}]},"4":{"tz":"立约护人","te":"The Platform","mz":"对外提出实在的主张与承诺,让取代旧秩序的新方案值得托付。","me":"Offers a real agenda and promises that make the new order worth trusting.","pol":[]},"5":{"tz":"安顿众人","te":"Organizing Care","mz":"动荡时刻把大家的实际生计安排妥当,人心稳了才有人跟随。","me":"In upheaval, tends to people's real needs so support holds.","pol":[{"t":"exalted","p":"Moon","z":"▲体察众人的现实需要,把生活照料周全,赢得长久的理解与支持。","e":"Senses people's practical needs and provides for them, earning lasting support."},{"t":"detriment","p":"Mars","z":"▼只顾着排座次、抓权力,为了管住人不惜牺牲更高的原则。","e":"Fixates on power and authority, sacrificing higher principles to control others."}]},"6":{"tz":"感召人心","te":"Winning Hearts","mz":"用真心打动观望的人,让原本骑墙的也愿意投入进来。","me":"Wins over the undecided, turning fence-sitters into the committed.","pol":[{"t":"exalted","p":"Neptune","z":"▲天生有感染力,能让观望者动心投入,温柔地转化身边的人。","e":"A natural pull that moves fence-sitters to commit and quietly transforms others."},{"t":"detriment","p":"Saturn","z":"▼固执到把人和原则一概拒之门外,过度敏感让拒绝成了习惯。","e":"Stubborn shutting-out; oversensitivity makes rejecting people and principles a habit."}]}},"50":{"1":{"tz":"出身不拘","te":"The Outsider Who Rises","mz":"出身平凡反而轻装上阵,把根基打磨成一生的价值。","me":"Humble roots are no cage—polished, they become the foundation of who you are.","pol":[{"t":"exalted","p":"Mars","z":"▲扬升:从最朴素的底子起步,一边精进一边把价值带向更远。","e":"Builds on basic strengths, refining values into a force that serves your path."},{"t":"detriment","p":"Venus","z":"▼落陷:嫌弃自己的出身,把精致变成执念,反被起点绑住。","e":"Ashamed of origins, you obsess over polish and let the past hold you back."}]},"2":{"tz":"守得住的","te":"Standing Firm","mz":"压力越大越站得稳,在反对声里守住自己认定的价值。","me":"The harder the push, the steadier you stand—holding your values against the crowd.","pol":[{"t":"exalted","p":"Sun","z":"▲扬升:把逆境当成可越过的关,目标清晰,越战越有劲。","e":"Finds purpose in overcoming adversity, growing stronger as it holds its ground."},{"t":"detriment","p":"Venus","z":"▼落陷:受不了冲突,一遇反对就缩回去,价值跟着退让。","e":"Shrinks from conflict, withdrawing until your values quietly give way."}]},"3":{"tz":"懂得借力","te":"Leaning on Others","mz":"单打独斗走不远时,自然靠向能护你、养你的人。","me":"When you can't go it alone, you instinctively align with those who nurture and protect.","pol":[{"t":"exalted","p":"Moon","z":"▲扬升:明白守住原则需要盟友,主动靠近滋养你的力量。","e":"Knows that keeping your principles takes allies, and seeks supportive ground."},{"t":"detriment","p":"Mercury","z":"▼落陷:才华被忽视就憋屈,被迫讨好才能生存,心有不甘。","e":"Resents being overlooked, forced to court favor just to get by."}]},"4":{"tz":"价值失守","te":"When Values Erode","mz":"缺了真正滋养人的价值,本事再大也容易走偏。","me":"Without nourishing values, even real talent drifts toward decay.","pol":[{"t":"exalted","p":"Saturn","z":"▲扬升:价值虽浅,仍能靠自律稳住分寸,自私而不越界。","e":"Holds the line through discipline—selfish maybe, but never crossing into harm."},{"t":"detriment","p":"Mars","z":"▼落陷:精力旺盛却没了底线,价值崩塌,防线随之瓦解。","e":"Raw energy with no values to anchor it—defenses break down into corruption."}]},"5":{"tz":"成事勿改","te":"Don't Fix What Works","mz":"靠它走通的路,别轻易推翻;成功了就守住根本。","me":"What carried you to success shouldn't be casually overturned—keep the core intact.","pol":[{"t":"exalted","p":"Saturn","z":"▲扬升:稳健保守,不为变而变,清楚根本原则不可随手丢。","e":"Disciplined and steady, avoiding needless change and guarding core principles."},{"t":"detriment","p":"Mars","z":"▼落陷:一被刺激就想反叛,连让自己成功的方法都要砸掉。","e":"When provoked, rebels against the very method that brought success."}]},"6":{"tz":"服众之人","te":"The One Others Follow","mz":"身居高位时,既能坚守价值,又能让周围的人服气、和睦。","me":"In a place of power, you uphold your values while keeping relationships in harmony.","pol":[{"t":"exalted","p":"Venus","z":"▲扬升:就算严厉,也能维系和谐,有力又有温度地守住价值。","e":"Keeps harmony even when firm, holding values with both strength and warmth."},{"t":"detriment","p":"Moon","z":"▼落陷:情绪起伏,在高位时易得罪人、伤了和气,拖累全局。","e":"Moody at the top, sometimes alienating others and undercutting the whole."}]}},"51":{"1":{"tz":"前车之鉴","te":"Drawing on Experience","mz":"经历过冲击的人,把旧伤化成预案,临事比谁都稳。","me":"Someone who turns past shocks into readiness, staying steady when crisis hits.","pol":[{"t":"exalted","p":"Pluto","z":"▲扬升:翻看旧经历当功课,把每次惊吓都变成下次的底气。","e":"Re-examining the past as homework, turning each scare into next time's footing."},{"t":"detriment","p":"Venus","z":"▼落陷:受惊后只想缩回情绪壳里,关键时刻软了下来。","e":"Pulling back into an emotional shell after a jolt, going soft just when it counts."}]},"2":{"tz":"知退的人","te":"Knowing When to Step Back","mz":"看清冲击来势,该撤就撤,本能地为自己留出安全距离。","me":"Someone who reads the shock clearly and pulls back when retreat is the only smart move.","pol":[{"t":"exalted","p":"Mars","z":"▲扬升:摸透冲击的脾性,该退就果断退,不跟硬碰。","e":"Grasping how shock works, retreating decisively rather than clashing head-on."},{"t":"detriment","p":"Mercury","z":"▼落陷:自以为聪明,偏要硬扛自然之力,结果聪明反被聪明误。","e":"Too clever by half, refusing to retreat in the vain hope of outsmarting nature."}]},"3":{"tz":"随机应变","te":"Thinking on Your Feet","mz":"意外打乱日常时,临场反应快,在乱局里反而找出新机会。","me":"Someone quick on their feet who finds openings in the very chaos that disrupts them.","pol":[{"t":"exalted","p":"Sun","z":"▲扬升:乱中清醒,边走边想,把意外当成机会的入口。","e":"Staying clear-headed in chaos, improvising openings from the unexpected."},{"t":"detriment","p":"Jupiter","z":"▼落陷:日常被猛然搅乱时阵脚大乱,只想缩回,不肯调整。","e":"Thrown off balance when routine is upended, retreating instead of adapting."}]},"4":{"tz":"绝处生机","te":"Finding the Opening","mz":"在最毁灭性的冲击里,也能脑洞大开,硬是抠出一线生路。","me":"Someone who, even amid devastating shock, invents a way through with sheer ingenuity.","pol":[{"t":"exalted","p":"Uranus","z":"▲扬升:再大的冲击也能灵光一闪,创出别人想不到的活路。","e":"Even in the worst shock, a flash of genius finds an opening no one else saw."},{"t":"detriment","p":"Mercury","z":"▼落陷:只会讲道理凑合应付,真遇大冲击就底气不足、撑不住。","e":"A reasoned make-do mentality that runs out of depth when the shock is severe."}]},"5":{"tz":"顺势化险","te":"Riding the Shock","mz":"看懂冲击的规律,顺着它的节奏调整,化险为夷而不被掀翻。","me":"Someone who grasps a shock's pattern and adapts in rhythm with it, avoiding its damage.","pol":[{"t":"exalted","p":"Sun","z":"▲扬升:看透冲击本质,顺其节奏巧调整,乘浪而行不被吞没。","e":"Seeing into the shock's nature, adapting in symmetry to ride it rather than be swept under."},{"t":"detriment","p":"Mars","z":"▼落陷:刚摆平一波就得意松懈,转头又被下一波冲击拍倒。","e":"Harmonizing with one shock, then basking in victory until the next one overwhelms."}]},"6":{"tz":"独自挺住","te":"Standing Alone","mz":"众人慌乱失序时,不被恐慌带走,凭意志和生命力独自撑过去。","me":"Someone who, amid collective panic, has the will and vitality to survive the crisis alone.","pol":[{"t":"exalted","p":"Sun","z":"▲扬升:周遭一片慌乱,我不随之崩,凭着求生的意志独自闯过。","e":"When all around panic, holding the will and vitality to survive it alone."},{"t":"detriment","p":"Pluto","z":"▼落陷:同样独行,态度却招人反感,反而给对手添了底气、难以脱身。","e":"The same lone strength, but an attitude that invites disapproval and empowers challengers."}]}},"52":{"1":{"tz":"想清再说","te":"Pause Before Words","mz":"话到嘴边先停一停,把冲动沉下来,沉默里反而生出力量的人。","me":"One who quiets the impulse to speak first, finding power in the pause.","pol":[{"t":"exalted","p":"Earth","z":"▲那份停顿深到化为静默,能量被妥帖安放,内里稳如大地。","e":"A pause deep enough to settle into silence, energy at rest."},{"t":"detriment","p":"Mars","z":"▼脱口而出后再收拾烂摊子,能量像脱缰,停不下来。","e":"Blurting first, cleaning up after; restless energy that won't still."}]},"2":{"tz":"为人而停","te":"Pausing for Others","mz":"懂得为了别人按下暂停键,克制自己的冲动,把他人的安危放在前面。","me":"One who restrains their own drive to protect and serve others.","pol":[{"t":"exalted","p":"Venus","z":"▲为了成全别人而主动停下,这份克制里有温柔的体贴。","e":"A pause chosen for others' good, restraint born of care."},{"t":"detriment","p":"Mars","z":"▼只顾自己猛踩刹车,不管旁人死活,任性又突兀。","e":"A selfish, abrupt halt that needlessly endangers those nearby."}]},"3":{"tz":"被迫止步","te":"Held Back","mz":"外在的限制逼你停下来——能否在不情愿里学会接纳,是这条爻的功课。","me":"One forced to stop by outer limits, learning whether to resist or accept.","pol":[{"t":"exalted","p":"Saturn","z":"▲天生懂得接受约束,把这段被迫的停顿用来重新调整方向。","e":"Naturally grasps restraint, using the halt to rethink strategy."},{"t":"detriment","p":"Venus","z":"▼对管束满心不爽,搅了内心的安宁,赌气退缩、视野也跟着乱。","e":"Resentment of controls shatters calm, breeds withdrawal and clouds vision."}]},"4":{"tz":"守得住静","te":"Self-Mastery","mz":"靠内在纪律稳住自己,面对诱惑不慌不乱,在静止里专注用力的人。","me":"One who holds steady through inner discipline, focused amid temptation.","pol":[{"t":"exalted","p":"Saturn","z":"▲自律已成本能,轻松化解一时冲动,在静定中看清重点。","e":"Discipline so honed it disarms impulse, finding focus in stillness."},{"t":"detriment","p":"Jupiter","z":"▼天性想往外扩,停得太久反而坐不住,生出怀疑、丢了细节。","e":"An expansive nature chafes at restraint, breeding doubt and lost focus."}]},"5":{"tz":"说清立场","te":"Stating the Case","mz":"停下来的时候,能把自己的位置三言两语说明白,是这条爻的关键本事。","me":"One who, amid stillness, can clearly explain where they stand.","pol":[{"t":"exalted","p":"Earth","z":"▲话不多却字字精准,在静定专注里把细节抠得清清楚楚。","e":"Terse yet exact; stillness and focus sharpen every detail."},{"t":"detriment","p":"Pluto","z":"▼说得绕、让人摸不着头脑,停得太久反而失了焦、抓不住要点。","e":"Convoluted and baffling; over-stillness blurs the focus and the detail."}]},"6":{"tz":"心安自在","te":"Inner Peace","mz":"无论身处什么处境都能内心安稳,不被外界推着走,活成一份从容的榜样。","me":"One at ease in any circumstance, modeling unshakable calm.","pol":[{"t":"exalted","p":"Venus","z":"▲与万物和谐共处,无论顺逆都泰然自若,静里没有半点压力。","e":"A harmonious ease at peace in any situation, free of pressure."},{"t":"detriment","p":"Neptune","z":"▼用幻想冒充真正的宁静,自我感觉良好,却分不清虚实。","e":"Delusion masquerading as genuine calm, as convincing as the real thing."}]}},"53":{"1":{"tz":"旧根新苗","te":"Building on Roots","mz":"想开始新事,却舍不得丢掉旧的好东西,在原有根基上慢慢起步。","me":"Starting fresh by keeping the best of the old as your foundation.","pol":[{"t":"exalted","p":"Neptune","z":"▲会让旧形式自然消融,但留住真正有价值的部分加以转化。","e":"Lets old forms dissolve while keeping and transforming what's worth saving."},{"t":"detriment","p":"Venus","z":"▼被批评打击后只想退缩,迟迟不敢重新开始。","e":"Stung by criticism, withdraws instead of beginning again."}]},"2":{"tz":"顺势而上","te":"Riding the Win","mz":"早期的小成功被好好呵护,一步步滚成更大的成就。","me":"Early success protected and nurtured grows into bigger wins.","pol":[{"t":"exalted","p":"Moon","z":"▲守护初期的成果,让它稳稳长成下一段成功。","e":"Guards early success so it nurtures the next achievement."},{"t":"detriment","p":"Mars","z":"▼尝到甜头就急躁冒进,因急于求成而失了分寸。","e":"First taste of success breeds haste and reckless moves."}]},"3":{"tz":"避开内耗","te":"Steering Clear of Friction","mz":"懂得绕开冲突、不把精力耗在争斗上,让事情安稳往前走。","me":"Avoiding needless conflict so development can keep moving.","pol":[{"t":"exalted","p":"Moon","z":"▲专注于化解冲突,为成长守住一片安稳空间。","e":"Focuses on defusing conflict to protect steady growth."},{"t":"detriment","p":"Mars","z":"▼不自觉地挑起争端,把刚起步的局面拖入险境。","e":"Unwittingly provokes conflict that threatens what's just begun."}]},"4":{"tz":"乱中守己","te":"Holding Your Ground","mz":"在混乱尴尬的开局里,依然稳得住自己,不被环境带偏。","me":"Keeping your own footing through messy, awkward beginnings.","pol":[{"t":"exalted","p":"Moon","z":"▲在复杂尴尬的处境里仍守住自我,让成长持续。","e":"Holds onto individuality amid complex, awkward situations."},{"t":"detriment","p":"Venus","z":"▼一遇尴尬场面情绪就乱,反应过度反而坏了事。","e":"Awkward moments trigger reactions that backfire."}]},"5":{"tz":"孤行不悔","te":"Conviction Alone","mz":"哪怕孤立无援,也坚信方向的价值,稳稳推动开始。","me":"Trusting the worth of your path even when standing alone.","pol":[{"t":"exalted","p":"Neptune","z":"▲凭内在笃定坚守方向,连反对者也被这份力量感召。","e":"Inner certainty holds the course and even wins over opponents."},{"t":"detriment","p":"Earth","z":"▼用力过猛地强硬,反而激起更大的反对与孤立。","e":"Over-pushing only strengthens the very forces against you."}]},"6":{"tz":"成果引路","te":"Leading by Example","mz":"用一段已完成的成功做榜样,吸引支持走向下一程。","me":"Using a finished success as proof to draw support onward.","pol":[{"t":"exalted","p":"Moon","z":"▲把已完成的成果亮出来当范例,为下一程引来助力。","e":"Shows off a completed stage as an example to draw support."},{"t":"detriment","p":"Pluto","z":"▼怕成功招来麻烦或散了人心,反而把成果藏起来。","e":"Hides success, fearing it will scare off supporters."}]}},"54":{"1":{"tz":"暗处使力","te":"Quiet Leverage","mz":"凭私下的连接默默积蓄影响力,不靠头衔也能推动事情。","me":"Builds real influence through private, behind-the-scenes ties rather than public titles.","pol":[{"t":"exalted","p":"Pluto","z":"▲在低调的关系里悄悄蓄能,不张扬却真正左右局面。","e":"Gains genuine sway through discreet bonds, never needing the spotlight."},{"t":"detriment","p":"Venus","z":"▼非要别人公开承认这段关系,反而削弱了自己的分量。","e":"Demanding formal recognition for the bond actually shrinks its power."}]},"2":{"tz":"守得住的智慧","te":"Knowing When to Hold Back","mz":"得到正式位置后,懂得不去占旧关系的便宜,克制即是力量。","me":"Once formally recognized, has the wisdom to restrain old advantages instead of exploiting them.","pol":[{"t":"exalted","p":"Saturn","z":"▲上位后管住自己,不拿过去的旧情做筹码,克制反而托起野心。","e":"Restraint after rising keeps you from cashing in old ties, and fuels real ambition."},{"t":"detriment","p":"Mars","z":"▼把名分当成可以任意利用旧交情的许可,失了忠诚。","e":"Treats new status as license to exploit past intimacy, betraying loyalty."}]},"3":{"tz":"绕路而行","te":"The Side Door","mz":"正路走不通时,懂得用非正式的暗道达成目标,但仅作最后手段。","me":"When the front door is blocked, finds quiet informal routes, but only as a last resort.","pol":[{"t":"exalted","p":"Pluto","z":"▲正式渠道堵死时,才动用私下门路,把僵局推开。","e":"Turns to hidden channels only when formal paths truly close off."},{"t":"detriment","p":"Venus","z":"▼明知正路受阻,仍硬信靠魅力就能强行打通,白费力气。","e":"Insists charm alone can force open a jammed formal path, wasting effort."}]},"4":{"tz":"向上的门","te":"The Threshold","mz":"最神秘的位置:向光或向暗其实是同一道门,全看你如何穿过。","me":"The mystical turning point where rising into light and slipping into dark are one and the same door.","pol":[]},"5":{"tz":"心宽待人","te":"Generous from the Top","mz":"身居高位时,仍能真心善待处境不如自己的人,关系真实可贵。","me":"In a position of power, still forms genuine, fruitful bonds with those less fortunate.","pol":[{"t":"exalted","p":"Sun","z":"▲手握权力却不端架子,与弱者结成真实、有回报的关系。","e":"Holds power yet builds real, rewarding ties with the less advantaged."}]},"6":{"tz":"懂得取舍","te":"Choosing Your People","mz":"出于守护自我与安全感,自然只留下双向滋养的关系,放下其余。","me":"Naturally keeps only mutually nourishing bonds, letting the rest go to protect identity and security.","pol":[{"t":"exalted","p":"Saturn","z":"▲为守住自我和安稳,本能地剪掉拖累自己的关系。","e":"Instinctively prunes draining ties to guard identity and stability."},{"t":"detriment","p":"Jupiter","z":"▼总以为能补上对方欠缺的部分,硬撑无益的关系,徒耗心力。","e":"Assumes it can supply what partners lack, draining itself on hopeless bonds."}]}},"55":{"1":{"tz":"携手共振","te":"Cooperation","mz":"与强大力量合拍，丰盛由协作而生，但灵性需自己点亮。","me":"Abundance grows by aligning with powerful forces, yet spirit must be your own.","pol":[{"t":"exalted","p":"Jupiter","z":"守原则地携手强者，既稳住支持，也借合作触到内在灵性。","e":"Joining strong allies on principle secures support and awakens the spirit within."},{"t":"detriment","p":"Venus","z":"只为关系和谐而靠拢权势，保住了延续却滋养不了灵性。","e":"Harmonizing with power keeps the peace but feeds no inner spirit."}]},"2":{"tz":"信任之争","te":"Distrust","mz":"情绪稳定系于被信任，流言难辩，唯持续行动可证清白。","me":"Stability rests on being trusted; only steady example silences rumor.","pol":[{"t":"exalted","p":"Venus","z":"以真诚直抵人心，用关系的天赋让信任自然被看见。","e":"Genuine warmth reaches the core and lets others truly see your honesty."},{"t":"detriment","p":"Earth","z":"硬碰流言反招'此地无银'，越急于自证越难赢得接纳。","e":"Loudly fighting slander backfires; insisting on trust rarely wins it."}]},"3":{"tz":"无咎之心","te":"Innocence","mz":"尽力而循规，纵然失败也非己过，灵性不必因此动摇。","me":"When you act rightly within bounds, failure is no personal fault.","pol":[{"t":"exalted","p":"Saturn","z":"形式得当、行动守矩，即便不成也坦然，灵性安稳无伤。","e":"Doing things correctly within limits keeps the spirit calm even in failure."},{"t":"detriment","p":"Mars","z":"躲在借口后逃责，为护己灵而牺牲他人，反致他人崩塌。","e":"Hiding behind excuses to protect oneself can quietly ruin others."}]},"4":{"tz":"融会贯通","te":"Assimilation","mz":"原则与能量平衡成型，扩展与丰盛随之水到渠成。","me":"When principle and energy balance, expansion and abundance follow naturally.","pol":[{"t":"exalted","p":"Jupiter","z":"搭起原则与能量并重的框架，繁荣自来，灵性也随之丰盈。","e":"A framework balancing principle and energy brings prosperity and a fuller spirit."},{"t":"detriment","p":"Mars","z":"能量横冲直撞、毫无节制，忽视觉察终将耗损灵性。","e":"Boundless, unchecked energy ignores awareness and puts the spirit at risk."}]},"5":{"tz":"纳谏而长","te":"Growth","mz":"居高位仍能纳言并创新转化，让自己引领而非被牵。","me":"In power, take advice and reshape it innovatively so you lead, not follow.","pol":[{"t":"exalted","p":"Uranus","z":"身居高位却善纳建言，再以创新转化，始终引领灵性强健。","e":"From a high seat you absorb advice and reinvent it, leading with strong spirit."},{"t":"detriment","p":"Sun","z":"一味敞开广纳意见，反被外缘左右，灵性渐被遮蔽。","e":"Open acceptance of all advice lets conditioning eclipse the spirit."}]},"6":{"tz":"独占之心","te":"Selfishness","mz":"丰盛若执于独占便孤立，分享与否决定灵性的明暗。","me":"Hoarded abundance isolates; whether you share decides the spirit's light.","pol":[{"t":"exalted","p":"Saturn","z":"执着积累虽显疏离，财富外溢仍间接惠及他人。","e":"Obsessive acquisition feels cold yet still spills material good to others."},{"t":"detriment","p":"Moon","z":"坐拥丰盛却光不外照，'无月'之吝，灵性悭于分享。","e":"Abundance sits dark like a moonless night, a mean spirit that shares nothing."}]}},"56":{"1":{"tz":"言之有物","te":"Substance over Sparkle","mz":"讲故事也要落地，分享真正有价值的见解，而非空话。","me":"Even brief, lively ideas should carry real value, not just noise.","pol":[{"t":"exalted","p":"Moon","z":"本能地只传递实用、能用得上的想法。","e":"Instinctively shares only practical ideas that genuinely help."},{"t":"detriment","p":"Mars","z":"为博眼球什么都讲，把精力耗在琐碎刺激上。","e":"Burns energy chasing applause with any trivial talking point."}]},"2":{"tz":"需被看见","te":"Genius Needs Witnesses","mz":"独到的表达需要时间成熟，也需要他人认可才能延续。","me":"Original expression matures slowly and lasts only when others recognize it.","pol":[{"t":"exalted","p":"Uranus","z":"孤独的天才，终因被赏识而获得延续与支持。","e":"Isolated brilliance that endures once recognition and backing arrive."},{"t":"detriment","p":"Moon","z":"会说不够深，一被认真审视便露怯转身。","e":"A glib gift that crumbles under scrutiny and moves on."}]},"3":{"tz":"宁孤勿迎","te":"Self-Sufficient Apart","mz":"强大的自我让人远离众人，却也守住了独立与活力。","me":"A fierce self keeps others at bay yet guards its own vitality.","pol":[{"t":"exalted","p":"Sun","z":"强势主导、甘当焦点，孤立换来旺盛生命力。","e":"Bold willfulness owns the spotlight; isolation fuels its vitality."},{"t":"detriment","p":"Venus","z":"审美错位惹人不快，自断后援陷入孤立。","e":"Off-key taste offends, severs support, and breeds lonely isolation."}]},"4":{"tz":"见机应变","te":"Reading the Room","mz":"能为自保戴上得体的面具，但别让角色吞没真实的你。","me":"Wear a fitting mask for safety, but never let the role become you.","pol":[{"t":"exalted","p":"Moon","z":"必要时收起真情，以圆熟角色赢得庇护。","e":"Masks true feeling when needed, charming its way to protection."},{"t":"detriment","p":"Mercury","z":"把角色当真，时刻紧绷怕被识破而焦虑。","e":"Mistakes the act for reality, tense and anxious of exposure."}]},"5":{"tz":"引人注目","te":"Drawing the Eye","mz":"用独特与创新吸引关注，而非靠挑衅扰乱他人。","me":"Win attention through originality and innovation, not provocation.","pol":[{"t":"exalted","p":"Uranus","z":"以新奇创意乃至天才闪光，自然赢得关注与支持。","e":"Novelty and even genius naturally draw notice and support."},{"t":"detriment","p":"Mars","z":"靠刺激挑衅抢风头，反而把人推远败局自招。","e":"Provokes for attention and ends up sabotaging its own draw."}]},"6":{"tz":"言而有信","te":"Honor Your Word","mz":"一旦建立联结便守住承诺、言行如一，扎稳脚跟。","me":"Once connected, keep your commitments and live by your word.","pol":[{"t":"exalted","p":"Sun","z":"兑现承诺、坦诚如一，稳稳扎下根基。","e":"Honors commitments with honesty and secures a steady footing."},{"t":"detriment","p":"Pluto","z":"越渴求接纳，越在无意中招来排斥，漂泊不定。","e":"Craving acceptance, it unconsciously triggers the rejection it dreads."}]}},"57":{"1":{"tz":"穿透迷雾","te":"Through the Fog","mz":"直觉能穿透表象抓住时机，但情绪一旦盖过它便陷入犹疑。","me":"Intuition can cut to the core and act in time, unless feelings drown it.","pol":[{"t":"exalted","p":"Venus","z":"直觉一瞬穿透到事物本意，让你在对的时刻果断行动。","e":"Intuition pierces to the inner meaning and triggers perfectly timed action."},{"t":"detriment","p":"Moon","z":"情绪替代不了清明，被感受牵着走只会迟疑不决。","e":"Feelings stand in for clarity, and the resulting fog breeds indecision."}]},"2":{"tz":"净化定锚","te":"Cleansing","mz":"向内照见才能立稳价值观，并以决心守护它不被稀释。","me":"Inner seeing sets true values; resolve keeps them from eroding.","pol":[{"t":"exalted","p":"Venus","z":"由内在觉照完成的净化，自然立起真实的价值与理想。","e":"Cleansing born of inner realization establishes genuine values and ideals."},{"t":"detriment","p":"Moon","z":"只做表面清扫，把脏污藏进地毯下，直觉的深度被敷衍。","e":"A surface tidy-up hides the dirt away, treating deep intuition shallowly."}]},"3":{"tz":"锐利无疑","te":"Acuteness","mz":"清明削去一切疑虑，让直觉精准落地、自然成形。","me":"Clarity dissolves doubt so intuition lands sharp and manifests.","pol":[{"t":"exalted","p":"Mercury","z":"智识被打磨到极致，清明扫除疑惑，确保所想化为所成。","e":"Honed intelligence clears all doubt and guarantees what is sensed becomes real."}]},"4":{"tz":"驾驭关系","te":"The Director","mz":"凭直觉的敏锐统筹关系，引导而非压制，方得和谐高效。","me":"Intuitive sensitivity steers relationships toward harmony, not control.","pol":[{"t":"exalted","p":"Pluto","z":"清明掌握人际脉络，既最大化产出，又让彼此和谐共处。","e":"Clarity masters the web of relations, maximizing output while keeping harmony."},{"t":"detriment","p":"Mars","z":"本该引导却变成独断，把驾驭关系的天赋扭成发号施令。","e":"Guidance curdles into dictation, turning the gift for relations into commands."}]},"5":{"tz":"评估前行","te":"Progression","mz":"边推进边复盘，用直觉随时校准方向，才不致偏航。","me":"Advance while reassessing; intuition keeps the course from drifting.","pol":[{"t":"exalted","p":"Pluto","z":"在开创新局时仍持续审视数据、重估进程，校准每一步。","e":"While forging new forms, you keep reviewing the data and reassessing the path."},{"t":"detriment","p":"Moon","z":"只顾埋头硬冲，直觉被淹没，像失控的导弹偏离目标。","e":"Pushing on blindly drowns the intuition, like a missile gone off target."}]},"6":{"tz":"因势而用","te":"Making the Best","mz":"清明是双刃剑；无解之境时，靠创意把局面化到最优。","me":"Clarity cuts both ways; where there's no fix, ingenuity makes the best of it.","pol":[{"t":"exalted","p":"Uranus","z":"接受有些困局无法纠正，便用创新巧思，把难处化到最好。","e":"Accepting some binds can't be fixed, you use inventiveness to make the most of them."},{"t":"detriment","p":"Mars","z":"清明照出无力解决的难题，怒火涌起，逼出注定徒劳的行动。","e":"Clarity exposes an unsolvable problem, and anger forces futile, wasted action."}]}},"58":{"1":{"tz":"爱上生命","te":"Love of Life","mz":"万物的刺激点燃内在喜悦，与存在和谐共振。","me":"The world's stimulation awakens a deep joy that resonates in harmony with simply being alive.","pol":[{"t":"exalted","p":"Venus","z":"感知世界之美，独处或共享皆能由衷喜悦，活力源源不绝。","e":"Sensing the beauty of life, alone or shared, becomes a wellspring of pure aliveness."},{"t":"detriment","p":"Moon","z":"情绪如月相起落，喜悦只在某些时段闪现，难以持续。","e":"Like the Moon's phases, joy flickers in and out, never quite steady."}]},"2":{"tz":"扭曲沉溺","te":"Perversion","mz":"把对刺激的渴望推向堕落与放纵，喜悦沦为耽溺。","me":"The hunger for stimulation twists into decadence, reducing joy to mere indulgence.","pol":[{"t":"detriment","p":"Uranus","z":"追求扭曲刺激而伤己伤人，把活力耗在放纵堕落里。","e":"Chasing twisted thrills harms self and others, draining vitality into excess."}]},"3":{"tz":"自燃之力","te":"Electricity","mz":"活力自带电流，无需外力点火便能自我激发。","me":"An electric vitality that sparks itself, never waiting on others to ignite.","pol":[{"t":"exalted","p":"Uranus","z":"自身电能即是燃料，独立生发刺激，不依赖他人。","e":"Self-charged energy generates its own stimulation, free of any outside source."},{"t":"detriment","p":"Mars","z":"如火需薪，活力全凭外界供给，被他人左右好坏。","e":"Like fire needing fuel, this aliveness depends on others to keep it burning."}]},"4":{"tz":"聚焦取舍","te":"Focusing","mz":"面对纷杂刺激，能毫不费力锁定真正有价值的那一个。","me":"Amid a flood of stimulations, effortlessly homing in on the one that truly matters.","pol":[{"t":"exalted","p":"Pluto","z":"天生擅长专注，乱象当前仍能轻松筛出值得回应的影响。","e":"A natural focus that calmly picks out the worthwhile signal from the noise."},{"t":"detriment","p":"Neptune","z":"太易被感染，想兼容所有刺激反而失序、动荡不安。","e":"Too impressionable, trying to absorb everything tips into instability."}]},"5":{"tz":"守护自我","te":"Self-Defense","mz":"无论诱惑多大，都本能地守住自己、不被卷走。","me":"However tempting the pull, an instinct to protect oneself holds firm.","pol":[{"t":"exalted","p":"Moon","z":"天生实际的护身本能，再大诱惑也守得住底线。","e":"A practical, instinctive self-protection that no temptation can breach."},{"t":"detriment","p":"Sun","z":"自恃强大以攻代守，靠近可疑刺激却高估了不陷落的把握。","e":"Trusting strength of character to flirt with risky thrills, defenses are dropped."}]},"6":{"tz":"适可而止","te":"Carried Away","mz":"尽情享受刺激，却懂得在自我受威胁时及时抽身。","me":"Savoring stimulation fully, yet knowing when to pull back before the self is lost.","pol":[{"t":"exalted","p":"Moon","z":"务实地享受外界刺激，一旦独立性受威胁便本能退守。","e":"Enjoying the world's stimulation, then instinctively retreating when integrity is at stake."},{"t":"detriment","p":"Mercury","z":"心智一被点燃便过度认同刺激，迷失了自己的身份。","e":"Once the mind is sparked, over-identifying with the thrill dissolves one's own identity."}]}},"59":{"1":{"tz":"先发制人","te":"The preemptive strike","mz":"看清方向后，趁壁垒未筑成便主动拆除阻隔。","me":"Sensing the goal, you clear obstacles before they harden.","pol":[{"t":"exalted","p":"Sun","z":"明白意图，果断在隔阂坚固前破除，活力充沛。","e":"Knowing your aim, you dissolve barriers early with vital force."},{"t":"detriment","p":"Mercury","z":"看得清却拿不定主意，何时出手始终犹豫。","e":"You see clearly but stall, unsure of how and when to act."}]},"2":{"tz":"羞怯设界","te":"Shyness","mz":"亲密带来动荡，于是自筑屏障守住独处。","me":"Wary of union's turbulence, you fence off your own space.","pol":[{"t":"exalted","p":"Uranus","z":"天然偏爱独立，以距离避开结合带来的不稳。","e":"You prize natural separateness, holding off union's instability."},{"t":"detriment","p":"Pluto","z":"深层心结筑起算计的羞怯，再热情也封闭。","e":"Calculated shyness from deep wounds locks even the bold away."}]},"3":{"tz":"开放越界","te":"Openness","mz":"敞开本是好事，过了头却滑向放纵生乱。","me":"Openness is a gift, but unchecked it slides into excess.","pol":[{"t":"detriment","p":"Mars","z":"渴望借结合壮大自己，却把开放变成滥情。","e":"Craving power through union, openness turns into promiscuity."}]},"4":{"tz":"四海之亲","te":"Brotherhood and sisterhood","mz":"放下身体的界限，建立超越性的普世亲密。","me":"Lowering barriers, you forge intimacy that unites everyone.","pol":[{"t":"exalted","p":"Venus","z":"卸下隔阂走向共融，从非性的亲密中得力。","e":"Dropping defenses, you draw strength from non-sexual closeness."},{"t":"detriment","p":"Mercury","z":"道理都懂却少行动，念头管不住欲望。","e":"You grasp the ideal yet rarely act; thought can't curb desire."}]},"5":{"tz":"魅惑众生","te":"The femme fatale or Casanova","mz":"以爱为光，能融化任何人心头的壁垒。","me":"Love becomes a light that melts any barrier between people.","pol":[{"t":"exalted","p":"Sun","z":"自带轻盈光芒，用爱吸引他人、化解所有阻隔。","e":"A light, easy charm uses love to draw others and break walls."},{"t":"detriment","p":"Uranus","z":"魅力沦为手段，化身情场猎手玩弄吸引力。","e":"Charm turns into a weapon; the seducer plays power games."}]},"6":{"tz":"露水之缘","te":"The one night stand","mz":"只接受短暂结合，长久于此或难以为继。","me":"You take only fleeting unions, where lasting ties feel impossible.","pol":[{"t":"exalted","p":"Venus","z":"无论一瞬或永恒，都能成就当下圆满的亲密。","e":"Whether a moment or forever, you perfect the intimacy at hand."},{"t":"detriment","p":"Mercury","z":"天性想流动，主动求新鲜，把无常当常态。","e":"An innate drive to move on chases novelty as the default."}]}},"60":{"1":{"tz":"安然受限","te":"Inner Calm Under Limits","mz":"外界设下边界时,仍守住内心的和谐与节奏。","me":"Staying inwardly harmonious even when outer limits press in.","pol":[{"t":"exalted","p":"Venus","z":"受限亦不乱,以柔和之力与边界共处。","e":"A graceful energy that meets restriction without losing its peace."},{"t":"detriment","p":"Mercury","z":"渴望多样却被困住,焦躁不安难定。","e":"A hunger for variety that turns jittery the moment it's hemmed in."}]},"2":{"tz":"懂得取舍","te":"Knowing When to Yield","mz":"看清限制的本质,该忍则忍,待机而动。","me":"Reading the nature of a limit, bending when needed, seizing the opening.","pol":[{"t":"exalted","p":"Saturn","z":"看透限制本质,愿俯身适应再蓄势待机。","e":"Grasps a constraint's nature, adapts willingly, then waits to pounce."},{"t":"detriment","p":"Earth","z":"适应久了成惯性,限制已逝仍困其中。","e":"Adaptation hardens into habit, clinging to a limit long gone."}]},"3":{"tz":"守成保身","te":"Guarding What You Have","mz":"在限制中守住身份与安全,清醒地照顾自己。","me":"Holding identity and safety steady within the limits that bind you.","pol":[{"t":"exalted","p":"Saturn","z":"清醒自利,从容应对约束,稳住身份安全。","e":"Enlightened self-interest that handles limits and keeps you secure."},{"t":"detriment","p":"Mars","z":"只图自我满足,无视边界,代价必至。","e":"Self-indulgence that ignores the limits and predictably pays for it."}]},"4":{"tz":"因限制宜","te":"Making the Most of Limits","mz":"在受限处发挥潜能到极致,而非沉溺其意义。","me":"Squeezing the fullest potential out of whatever the limit allows.","pol":[{"t":"exalted","p":"Mercury","z":"用理智在边界内把潜能榨取到最大。","e":"Intelligently maxing out potential inside the bounds at hand."},{"t":"detriment","p":"Venus","z":"只想参透限制的意义,退缩而陷入消沉。","e":"Chasing a limit's hidden meaning until it pulls you into withdrawal."}]},"5":{"tz":"领航之力","te":"Leading Through Change","mz":"看清破除旧限只会生出新限,以行动示范引领。","me":"Seeing that breaking old limits only breeds new ones, and leading anyway.","pol":[{"t":"exalted","p":"Neptune","z":"明白限制无穷无尽,以行动带出领航之力。","e":"Knows limits are endless, and turns that wisdom into leadership."},{"t":"detriment","p":"Jupiter","z":"该收敛时仍想扩张,从顶端制造混乱。","e":"Pushing to expand when restraint is vital, sowing chaos from the top."}]},"6":{"tz":"刚而有度","te":"Firm With Finesse","mz":"知道何时必须绝对坚守,却以巧思柔化其severe。","me":"Knowing when rigidity is non-negotiable, yet softening it with ingenuity.","pol":[{"t":"exalted","p":"Uranus","z":"直觉看准须绝对坚守时,以创新缓其severe。","e":"Senses when firmness is essential, then innovates to ease its edge."},{"t":"detriment","p":"Mercury","z":"教条死守原则,冷硬到令人窒息生郁。","e":"Dogmatic rigidity so cold and absolute it suffocates into depression."}]}},"61":{"1":{"tz":"通灵之知","te":"Knowing the Unseen","mz":"被压迫去探究奥秘，天赋的直觉感知欲触及万物本源。","me":"An inborn psychic pull drives you to grasp the mystery behind all things.","pol":[{"t":"exalted","p":"Neptune","z":"天然的灵性直觉，把个人洞见升华为普世原理。","e":"A natural inner sight that lifts private insight into universal truth."},{"t":"detriment","p":"Venus","z":"沉溺密传知识而避世，终至晦涩，无力应对现实。","e":"Lost in secret lore, you withdraw until you can no longer face the real world."}]},"2":{"tz":"天赋光华","te":"Natural Radiance","mz":"无心机的灵感天赋，自然散发吸引并滋养他人。","me":"An unforced gift for inspiration that draws and nourishes others.","pol":[{"t":"exalted","p":"Moon","z":"纯净无伪的感召力，温润深远，自然吸引众人。","e":"A pure, far-reaching charm that attracts without manipulation."},{"t":"detriment","p":"Mars","z":"早早迷恋自身魅力，妄信每点灵感都该被看见。","e":"Too soon enamored of your own shine, you crave applause for every flash."}]},"3":{"tz":"相互依存","te":"Truth Needs Allies","mz":"真理难独立，借关系的护持与滋养才能稳固生长。","me":"Truth rarely stands alone; it grows through nurturing bonds.","pol":[{"t":"exalted","p":"Moon","z":"善结同盟，以呵护营造让真理稳定生长的环境。","e":"Skilled at alliances that shelter a truth until it can stand."},{"t":"detriment","p":"Mars","z":"精力过盛而独断，抛下他人或被其阻力压垮。","e":"Brimming with drive, you outrun others or break against their resistance."}]},"4":{"tz":"深掘探究","te":"Deep Research","mz":"以专注潜入内在真理，将洞见落实为根本原理。","me":"Focused concentration dives into truth and turns it into bedrock principle.","pol":[{"t":"exalted","p":"Saturn","z":"凝神专注，深探内在真理直抵根本法则。","e":"Steady focus that bores down to the deepest founding laws."},{"t":"detriment","p":"Uranus","z":"急于拉人入局，扩散出一堆混乱矛盾的版本。","e":"Pulling others in too soon scatters the work into muddled forks."}]},"5":{"tz":"影响之力","te":"Power to Shape","mz":"被认可的智慧与笃定主张，足以塑造一代人。","me":"Recognized wisdom and firm conviction can mold an entire generation.","pol":[{"t":"exalted","p":"Saturn","z":"如开明的长者，以公认智慧引领并塑造一代。","e":"An enlightened elder whose proven wisdom shapes those who follow."},{"t":"detriment","p":"Mars","z":"恋权而强求顺从，厌恶质疑，逼人接受己见。","e":"Clinging to power, you demand obedience and resent every challenge."}]},"6":{"tz":"感召大众","te":"Public Appeal","mz":"对集体的深刻共振，能把众人引向一个真理。","me":"A deep attunement to the crowd can draw the public toward a truth.","pol":[{"t":"exalted","p":"Pluto","z":"深契群体脉搏，以灵感为集体带来清明。","e":"Tuned to the collective pulse, you bring it clarity through inspiration."},{"t":"detriment","p":"Mars","z":"靠陈词滥调充数，纵有新劲也落于聋耳。","e":"Leaning on tired slogans that, however loud, fall on deaf ears."}]}},"62":{"1":{"tz":"日常之法","te":"Taming Routine","mz":"重复琐事最磨人，唯有内在的想象力能为它注入光彩。","me":"Routine deadens unless an inner imagination lifts it.","pol":[{"t":"exalted","p":"Neptune","z":"▲ 以丰富想象越过乏味，让繁琐细节也变得生动有趣。","e":"Daring imagination transcends tedium and gives detail life."},{"t":"detriment","p":"Mars","z":"▼ 抗拒重复而盲目发泄，耗尽精力却忽略了该做的细节。","e":"Restless rebellion burns energy while the details get ignored."}]},"2":{"tz":"自我克制","te":"Disciplined Restraint","mz":"细致活计需要约束自己的耐心，急躁只会前功尽弃。","me":"Detail work asks for the patience to hold yourself in check.","pol":[{"t":"exalted","p":"Saturn","z":"▲ 天生自律守得住分寸，沉得下心把细节一一做好。","e":"Innate discipline holds steady and sees the fine work through."},{"t":"detriment","p":"Mercury","z":"▼ 头脑被约束困住，焦躁不安，难以静心处理琐碎。","e":"A mind boxed in grows anxious and can't settle into detail."}]},"3":{"tz":"发现之眼","te":"Gift of Discovery","mz":"在枯燥细节里挖出珍宝，把不起眼的发现变成新意。","me":"Buried in dull detail lies a treasure worth uncovering.","pol":[{"t":"exalted","p":"Uranus","z":"▲ 独到天赋擅找非凡之处，从细节中翻出有价值的创见。","e":"A rare eye unearths valuable detail and turns it into insight."},{"t":"detriment","p":"Mercury","z":"▼ 厌倦单调而草草略过，可能漏掉真正关键的那一点。","e":"Boredom skims past detail and misses what truly mattered."}]},"4":{"tz":"独处沉淀","te":"Ascetic Withdrawal","mz":"唯有抽身静处、向内沉淀，细节的深意才会浮现。","me":"Only in quiet withdrawal does the meaning in detail surface.","pol":[{"t":"exalted","p":"Venus","z":"▲ 主动退守清净，于和谐独处中体味细节的内在意义。","e":"Chosen solitude finds harmony and the inner meaning of detail."},{"t":"detriment","p":"Pluto","z":"▼ 想反抗旧规却受阻，只能退缩蛰伏，干等时机到来。","e":"Thwarted from acting, one retreats and merely waits for a chance."}]},"5":{"tz":"蜕变出击","te":"Time to Act","mz":"细节备齐、火候已到，便是迈出一步、与人分享的时刻。","me":"When the details are complete, it's time to step out and share.","pol":[{"t":"exalted","p":"Moon","z":"▲ 如月渐盈终放光，待细节圆满再主动伸手与人分享。","e":"Like the waxing moon, share fully once the details are whole."},{"t":"detriment","p":"Neptune","z":"▼ 蜕变中渴求掌声，急于表演博取关注，盖过了实质。","e":"Craving applause, one performs for attention over substance."}]},"6":{"tz":"自律致成","te":"Self-Discipline","mz":"成败不在才华，而在能否守住做细节的那份纪律。","me":"Success rides not on talent but on the discipline for detail.","pol":[{"t":"exalted","p":"Saturn","z":"▲ 积少成多懂经营，明白扎实做细节才是通往成功之路。","e":"Penny by penny, solid detail work paves the road to success."},{"t":"detriment","p":"Mercury","z":"▼ 才能不缺，却缺自律，不肯下功夫做必要的琐碎工作。","e":"Plenty of skill but no discipline to do the needed grind."}]}},"63":{"1":{"tz":"笃定从容","te":"Settled Composure","mz":"成果落地后从容前行，让发展顺其自然展开。","me":"Receiving success with calm, letting growth unfold at its own pace.","pol":[{"t":"exalted","p":"Sun","z":"坦然接纳已有成就，安然静待下一步自然生长。","e":"Owning the win with equanimity, trusting the next phase to arrive in time."},{"t":"detriment","p":"Mars","z":"急于追逐新目标，反而动摇了刚刚稳住的根基。","e":"Chasing fresh goals too soon, shaking loose what was just secured."}]},"2":{"tz":"搭建框架","te":"Building Structure","mz":"建立宏大体系扩展成果，回馈他人却仍掌舵方向。","me":"Framing a structure to expand and share gains while keeping the helm.","pol":[{"t":"exalted","p":"Jupiter","z":"搭出大格局共享成果，公平回报又稳握方向。","e":"Building a wide framework that rewards others yet holds the course."},{"t":"detriment","p":"Uranus","z":"登上高位便傲慢，把人挡在权力核心之外。","e":"Power breeding arrogance, walling others away from the center."}]},"3":{"tz":"守住原则","te":"Holding Course","mz":"投入新局，与未达者周旋仍坚守自己的准则。","me":"Committing to the new start, keeping principles among those who haven't.","pol":[{"t":"exalted","p":"Jupiter","z":"全心投入新起点，混杂人群中也不弃原则。","e":"Devoted to the fresh beginning, holding standards amid those who lack them."},{"t":"detriment","p":"Saturn","z":"为成功不惜代价，急着不计后果地消除疑虑。","e":"Success at any cost, killing the doubt by whatever means."}]},"4":{"tz":"细录留痕","te":"Keeping Record","mz":"细记成就全过程，让信息沉淀为未来的新秩序。","me":"Logging the whole process so it can seed a new order ahead.","pol":[{"t":"exalted","p":"Mercury","z":"把每个细节记清，让积累成为未来成形的根基。","e":"Recording every detail, building a base for what will take shape."},{"t":"detriment","p":"Mars","z":"胜利冲昏头便遗忘细节，日后或要付出代价。","e":"Forgetting details in the glow of triumph, paying for it later."}]},"5":{"tz":"如一笃信","te":"True Affirmation","mz":"以真诚权威坚守初心之值，懂得疑虑本有意义。","me":"Sincere authority upholding the values that won, valuing doubt itself.","pol":[{"t":"exalted","p":"Sun","z":"新局中仍守旧日真值，明白怀疑本身就是养分。","e":"Keeping the founding values in the new start, seeing doubt as nourishment."},{"t":"detriment","p":"Mars","z":"口头敷衍价值，让信念沦为空洞的仪式。","e":"Paying lip service to values, hollowing belief into empty ritual."}]},"6":{"tz":"放下旧执","te":"Letting Go","mz":"明智地不让旧日挣扎成执念，懂得把疑虑留在身后。","me":"Wisely refusing to dwell on past struggle, leaving old doubts behind.","pol":[{"t":"exalted","p":"Jupiter","z":"不把过往斗争熬成执念，理智地翻篇向前。","e":"Not turning old battles into obsession, sensibly moving on."},{"t":"detriment","p":"Pluto","z":"沉溺旧日怀疑，被往昔的猜忌反复缠住。","e":"Lost in revolutionary nostalgia, gripped by old suspicion and doubt."}]}},"64":{"1":{"tz":"穿越混沌","te":"Conditions for Crossing","mz":"在纷乱中找到核心定位，是熬过失序、迎来转变的前提。","me":"Surviving disorder depends on finding the one point that holds amid the noise.","pol":[{"t":"exalted","p":"Venus","z":"▲洞穿表象直抵核心，以从容定力安度混乱","e":"Pierces to the center, steadying chaos with calm clarity."},{"t":"detriment","p":"Mars","z":"▼自以为想通便急于行动，被冲动带偏","e":"Mistakes a hunch for an answer and rushes to act too soon."}]},"2":{"tz":"必备底气","te":"Qualification","mz":"先认清转变真正需要的素质，备齐了再动，否则注定落空。","me":"Know which inner qualities transcendence demands before you move, or it will fail.","pol":[{"t":"exalted","p":"Venus","z":"▲向内修炼，看清何为关键，混乱自然消散","e":"Inner cultivation reveals what truly matters, and confusion dissolves."},{"t":"detriment","p":"Moon","z":"▼忙个不停，把日后要用的力气先耗光","e":"Forever busy, it squanders the very reserves it will later need."}]},"3":{"tz":"量力而行","te":"Overextension","mz":"承认自己实力不足以完成转变，及时求助，才有转机。","me":"Owning that you lack the means to finish opens the door to timely help.","pol":[{"t":"exalted","p":"Saturn","z":"▲懂得混乱只是过渡，借时间或他人之力化解","e":"Knows confusion is temporary, to be resolved by time or by others."},{"t":"detriment","p":"Moon","z":"▼表面自信，崩盘时却孤立无援","e":"All surface confidence, left with no one when it collapses."}]},"4":{"tz":"笃定信念","te":"Conviction","mz":"如月有盈亏，混乱本是过程，走完它必见分晓。","me":"Like the moon's phases, confusion is a process that ends in realization.","pol":[{"t":"exalted","p":"Moon","z":"▲信任过程，深知转变终将抵达成果","e":"Trusts the process, certain that transition arrives at fruition."},{"t":"detriment","p":"Mars","z":"▼蛮力越使越大，疑虑反而越压越重","e":"The more force it pours in, the heavier its doubt grows."}]},"5":{"tz":"价值兑现","te":"Promise","mz":"新秩序的价值，靠与人和谐互动来证明，而非只批判旧的。","me":"New values prove themselves through harmony with others, not by trashing the old.","pol":[{"t":"exalted","p":"Venus","z":"▲在真诚互动中展现新价值，让奋斗更有理由","e":"Lives out new values in real connection, justifying the struggle."},{"t":"detriment","p":"Jupiter","z":"▼只盯着旧秩序的失败，证不出新的好","e":"Fixates on the old order's failure, proving nothing about the new."}]},"6":{"tz":"水到渠成","te":"Victory","mz":"心中早知胜利必至，故能享受成果而不失态、不放纵。","me":"Knowing victory was always coming, it savors the win without excess.","pol":[{"t":"exalted","p":"Mercury","z":"▲心知必胜，从容享受纷繁信息的乐趣","e":"Sure of the outcome, it delights in the rich tangle of data."},{"t":"detriment","p":"Venus","z":"▼如特洛伊木马，得意忘形而丢了警觉与全局","e":"Like the Trojan Horse, celebration costs it vigilance and perspective."}]}}};
